#[derive(Deserialize, Debug)]
struct RefObject {
    #[serde(rename = "$ref")]
    reference: String,
}

#[derive(Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

impl ARaw {
    fn resolve(self, base_file: &Path) -> Result<A, Box<dyn Error>> {
        let path_list = match self.path_list {
            PathListField::Direct(v) => v,
            PathListField::Ref(r) => resolve_ref_to_paths(&r.reference, base_file)?,
        };

        Ok(A { path_list })
    }
}

fn resolve_ref_to_paths(reference: &str, base_file: &Path) -> Result<Vec<PathBuf>, Box<dyn Error>> {
    let (file_part, fragment_part) = match reference.split_once('#') {
        Some((f, frag)) => (f, frag),
        None => (reference, ""),
    };

    let target_file = if file_part.is_empty() {
        base_file.to_path_buf()
    } else {
        let base_dir = base_file
            .parent()
            .map(Path::to_path_buf)
            .unwrap_or_else(|| PathBuf::from("."));
        base_dir.join(file_part)
    };

    let json_text = fs::read_to_string(&target_file)?;
    let doc: Value = serde_json::from_str(&json_text)?;

    let target_value = if fragment_part.is_empty() {
        &doc
    } else {
        // JSON Pointer must start with '/'.
        let pointer = if fragment_part.starts_with('/') {
            fragment_part
        } else {
            return Err(format!("invalid $ref fragment (expected JSON pointer): #{fragment_part}").into());
        };

        doc.pointer(pointer)
            .ok_or_else(|| format!("JSON pointer not found: {pointer}"))?
    };

    let paths: Vec<PathBuf> = serde_json::from_value(target_value.clone())?;
    Ok(paths)
}

fn create_demo_files_if_missing() -> Result<(), Box<dyn Error>> {
    if !Path::new("a.json").exists() {
        fs::write(
            "a.json",
            r#"{
    "p_list": [
        "./a/b/c/def",
        "./g/h/i/jkl"
    ]
}
"#,
        )?;
    }

    if !Path::new("b.json").exists() {
        fs::write(
            "b.json",
            r#"{
    "path_list": {
        "$ref": "./a.json#/p_list"
    }
}
"#,
        )?;
    }

    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    create_demo_files_if_missing()?;

    let b_file = Path::new("b.json");
    let json_data = fs::read_to_string(b_file)?;

    let raw: ARaw = serde_json::from_str(&json_data)?;
    let a_obj = raw.resolve(b_file)?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}
"
}

