",
  "main.rs": "use std::io::{self, Read};

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum State {
    Unquoted,
    SingleQuoted,
    DoubleQuoted,
    EscapeUnquoted,
    EscapeDouble,
}

/// Split a command line into shell-like tokens.
///
/// Supported features:
/// - Whitespace splitting when unquoted
/// - Single quotes: '...'
/// - Double quotes: "..."
/// - Backslash escaping outside quotes and (partially) inside double quotes
/// - Concatenation of adjacent quoted/unquoted segments into one token
///
/// Returns an error for unterminated quotes or trailing backslash.
fn tokenize(input: &str) -> Result<Vec<String>, String> {
    let mut out = Vec::new();
    let mut cur = String::new();
    let mut state = State::Unquoted;
    let mut token_started = false;

    for ch in input.chars() {
        match state {
            State::Unquoted => match ch {
                c if c.is_whitespace() => {
                    if token_started {
                        out.push(std::mem::take(&mut cur));
                        token_started = false;
                    }
                }
                '\'' => {
                    state = State::SingleQuoted;
                    token_started = true;
                }
                '"' => {
                    state = State::DoubleQuoted;
                    token_started = true;
                }
                '\\' => {
                    state = State::EscapeUnquoted;
                    token_started = true;
                }
                _ => {
                    cur.push(ch);
                    token_started = true;
                }
            },

            State::SingleQuoted => {
                if ch == '\'' {
                    state = State::Unquoted;
                } else {
                    cur.push(ch);
                }
            }

            State::DoubleQuoted => match ch {
                '"' => state = State::Unquoted,
                '\\' => state = State::EscapeDouble,
                _ => cur.push(ch),
            },

            State::EscapeUnquoted => {
                cur.push(ch);
                state = State::Unquoted;
            }

            State::EscapeDouble => {
                // Bash-like subset: in double quotes, backslash only escapes
                // \\, ", $, and ` (plus newline, omitted here).
                match ch {
                    '\\' | '"' | '$' | '`' => cur.push(ch),
                    _ => {
                        cur.push('\\');
                        cur.push(ch);
                    }
                }
                state = State::DoubleQuoted;
            }
        }
    }

    match state {
        State::Unquoted => {
            if token_started {
                out.push(cur);
            }
            Ok(out)
        }
        State::SingleQuoted => Err("unterminated single quote".to_string()),
        State::DoubleQuoted => Err("unterminated double quote".to_string()),
        State::EscapeUnquoted | State::EscapeDouble => Err("trailing backslash".to_string()),
    }
}

fn main() {
    // Read whole stdin. If empty, use your sample.
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();

    if input.is_empty() {
        input = " one  ' two  'three    four".to_string();
    } else {
        // Drop one trailing line ending from interactive input.
        if input.ends_with("\r\n") {
            input.truncate(input.len() - 2);
        } else if input.ends_with('\n') {
            input.pop();
        }
    }

    match tokenize(&input) {
        Ok(tokens) => {
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("error: {}", e);
            std::process::exit(1);
        }
    }
}

