        let got = tokenize(s).unwrap();
        let want = vec!["one", " two  three", "four"];
        assert_eq!(got, want);
    }

    #[test]
    fn empty_quoted_arg() {
        let got = tokenize("a '' b").unwrap();
        assert_eq!(got, vec!["a", "", "b"]);
    }

    #[test]
    fn unterminated_quote_is_error() {
        assert!(tokenize("abc 'def").is_err());
    }
}
