    fn fetch_add_via_critical_section(&self) -> usize {
        with(|_| {
            let old = self.channel_index.load(Ordering::Relaxed);
            // fetch_add wraps on overflow, so use wrapping_add to match behavior.
            self.channel_index
                .store(old.wrapping_add(1), Ordering::Relaxed);
            old
