  "main.rs": "use rayon::prelude::*;

#[derive(Debug, Default, Clone)]
struct B {
    r: Vec<f64>,
    v: Vec<f64>,
    f: Vec<f64>,
    nb: Vec<usize>,
}

impl B {
    pub fn criterion(&self, other: &B) -> f64 {
        let dx = self.r[0] - other.r[0];
        let dy = self.r[1] - other.r[1];
        let dz = self.r[2] - other.r[2];
        dx * dx + dy * dy + dz * dz
    }
}

#[derive(Debug, Default, Clone)]
struct A {
    elems: Vec<B>,
    cutoff: f64,
}

impl A {
    pub fn get_nelems(&self) -> usize {
        self.elems.len()
    }

    /// Safe, single-threaded, no copies of `elems`.
    /// Updates both i and j neighbor lists when criterion is met.
    pub fn build_lists_sequential(&mut self) {
        for e in &mut self.elems {
            e.nb.clear();
        }

        let n = self.get_nelems();
        let cutoff = self.cutoff;

        for i in 0..n {
            // Split so `elem_i` and any `elem_j` (j > i) are disjoint mutable borrows.
            let (left, right) = self.elems.split_at_mut(i + 1);
            let elem_i = &mut left[i];

            for (offset, elem_j) in right.iter_mut().enumerate() {
                let j = i + 1 + offset;
                if elem_i.criterion(elem_j) < cutoff {
                    elem_i.nb.push(j);
                    elem_j.nb.push(i);
                }
            }
        }

        for e in &mut self.elems {
            e.nb.sort_unstable();
        }
    }

    /// Safe parallel version:
    /// 1) Read-only parallel pass computes matching pairs (i, j), i < j.
    /// 2) Single-threaded pass writes neighbors to both ends.
    pub fn build_lists_parallel(&mut self) {
        let n = self.get_nelems();
        let cutoff = self.cutoff;
        let elems = &self.elems; // immutable borrow only for parallel computation

        let pairs: Vec<(usize, usize)> = (0..n)
            .into_par_iter()
            .map(|i| {
                let mut local = Vec::new();
                for j in (i + 1)..n {
                    if elems[i].criterion(&elems[j]) < cutoff {
                        local.push((i, j));
                    }
                }
                local
            })
            .reduce(Vec::new, |mut a, mut b| {
                a.append(&mut b);
                a
            });

        for e in &mut self.elems {
            e.nb.clear();
        }

        for (i, j) in pairs {
            self.elems[i].nb.push(j);
            self.elems[j].nb.push(i);
        }

        for e in &mut self.elems {
            e.nb.sort_unstable();
        }
    }
}

fn make_demo_system(n: usize, cutoff: f64) -> A {
    let mut elems = Vec::with_capacity(n);

    for i in 0..n {
        // Deterministic pseudo-random-ish coordinates.
        let x = ((i * 37) % 97) as f64 * 0.2;
        let y = ((i * 53 + 11) % 89) as f64 * 0.2;
        let z = ((i * 29 + 7) % 83) as f64 * 0.2;

        elems.push(B {
            r: vec![x, y, z],
            v: vec![0.0, 0.0, 0.0],
            f: vec![0.0, 0.0, 0.0],
            nb: Vec::new(),
        });
    }

    A { elems, cutoff }
}

fn main() {
    let a = make_demo_system(80, 10.0);

    let mut seq = a.clone();
    seq.build_lists_sequential();

    let mut par = a.clone();
    par.build_lists_parallel();

    let same = seq
        .elems
        .iter()
        .zip(&par.elems)
        .all(|(b1, b2)| b1.nb == b2.nb);

    println!("Sequential and parallel neighbor lists identical: {same}");

    for i in 0..5 {
        println!("elem {i:2} -> neighbors: {:?}", seq.elems[i].nb);
    }
}
