// -------------------- Custom Deserialize for B --------------------

struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("a map like {\"num\": 1} or {\"text\": \"hello\"}")
    }

    fn visit_map<M>(self, mut map: M) -> Result<B, M::Error>
    where
        M: MapAccess<'de>,
    {
        let key: Option<String> = map.next_key()?;
        let key = key.ok_or_else(|| de::Error::custom("empty map for B"))?;

        let value = match key.as_str() {
            "num" => B::Num(map.next_value()?),
            "text" => B::Text(map.next_value()?),
            _ => return Err(de::Error::unknown_field(&key, &["num", "text"])),
