        if map.next_key::<de::IgnoredAny>()?.is_some() {
            return Err(de::Error::custom(
                "B must contain exactly one key: either 'num' or 'text'",
            ));
        }

        Ok(value)
    }
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
