    X,
    B,
}

struct AFieldVisitor;

impl<'de> Visitor<'de> for AFieldVisitor {
    type Value = AField;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("`x` or `b`")
    }

    fn visit_str<E>(self, v: &str) -> Result<AField, E>
    where
        E: de::Error,
    {
        match v {
            "x" => Ok(AField::X),
            "b" => Ok(AField::B),
            _ => Err(de::Error::unknown_field(v, &["x", "b"])),
        }
    }
}

impl<'de> Deserialize<'de> for AField {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
