type EvalFn = Arc<dyn Fn(&[f64]) -> f64 + Send + Sync>;

#[derive(Clone)]
struct Op {
    name: String,
    arity: usize,
    eval: EvalFn,
}

impl Op {
    fn new<F>(name: impl Into<String>, arity: usize, f: F) -> Self
    where
        F: Fn(&[f64]) -> f64 + Send + Sync + 'static,
    {
        Self {
            name: name.into(),
            arity,
            eval: Arc::new(f),
        }
    }

    fn add() -> Self {
        Self::new("+", 2, |a| a[0] + a[1])
    }

    fn sub() -> Self {
        Self::new("-", 2, |a| a[0] - a[1])
    }

    fn mul() -> Self {
        Self::new("*", 2, |a| a[0] * a[1])
    }

    fn pow() -> Self {
        Self::new("pow", 2, |a| a[0].powf(a[1]))
    }

    fn var(index: usize) -> Self {
        Self::new(format!("x{index}"), 0, move |_| {
            // Variable value is read in Node::eval (leaf special-case),
            // this closure is just a placeholder.
            index as f64
        })
    }

    // This is the custom operator you wanted: sqrt(x) + 1
    fn sqrtplusone() -> Self {
        Self::new("sqrtplusone", 1, |a| a[0].sqrt() + 1.0)
    }
}

#[derive(Clone)]
struct Node {
    op: Op,
    children: Vec<Node>,
}

impl Node {
    fn leaf(op: Op) -> Self {
        assert_eq!(op.arity, 0, "leaf op arity must be 0");
        Self {
            op,
            children: vec![],
        }
    }

    fn vertex(op: Op, children: Vec<Node>) -> Self {
        assert_eq!(
            op.arity,
            children.len(),
            "vertex arity mismatch for {}",
            op.name
        );
        Self { op, children }
    }

    fn eval(&self, vars: &[f64]) -> f64 {
        if self.op.arity == 0 {
            // variable leaf: name is xN
            if let Some(idx_str) = self.op.name.strip_prefix('x') {
                let idx: usize = idx_str.parse().expect("invalid variable index");
                return vars[idx];
            }
            return (self.op.eval)(&[]);
        }

        let args: Vec<f64> = self.children.iter().map(|c| c.eval(vars)).collect();
        (self.op.eval)(&args)
    }

    fn pretty(&self) -> String {
        match self.op.arity {
            0 => self.op.name.clone(),
            1 => format!("{}({})", self.op.name, self.children[0].pretty()),
            2 if self.op.name == "+" || self.op.name == "-" || self.op.name == "*" => {
                format!(
                    "({} {} {})",
                    self.children[0].pretty(),
                    self.op.name,
                    self.children[1].pretty()
                )
            }
            _ => {
                let args = self
                    .children
                    .iter()
                    .map(|c| c.pretty())
                    .collect::<Vec<_>>()
                    .join(", ");
                format!("{}({})", self.op.name, args)
            }
        }
    }
}

fn main() {
    // Same shape as your store idea:
