    println!("available leaf ops:   {}", store[1].1.len());

    // Build expression:
    // sqrtplusone(x0) + pow(x0, 2)
    let tree = Node::vertex(
        Op::add(),
        vec![
            Node::vertex(Op::sqrtplusone(), vec![Node::leaf(Op::var(0))]),
            Node::vertex(
                Op::pow(),
                vec![Node::leaf(Op::var(0)), Node::leaf(Op::new("2", 0, |_| 2.0))],
            ),
        ],
    );

    let x = 9.0;
    let y = tree.eval(&[x]);

    println!("expr: {}", tree.pretty());
    println!("x = {x}");
    println!("result = {y}");
}
"
}

