// SplitMix64: small, fast, deterministic PRNG suitable for generating
// fixed tables (like Zobrist keys). Implemented as const so it runs at compile time.
const fn splitmix64_next(state: u64) -> (u64, u64) {
    let next_state = state.wrapping_add(0x9E3779B97F4A7C15);

    let mut z = next_state;
    z ^= z >> 30;
    z = z.wrapping_mul(0xBF58476D1CE4E5B9);
    z ^= z >> 27;
    z = z.wrapping_mul(0x94D049BB133111EB);
    z ^= z >> 31;

    (next_state, z)
}

