    let mut out = [0u64; ZOBRIST_COUNT];
    let mut state = seed;
    let mut i = 0;

    while i < ZOBRIST_COUNT {
        let (next_state, value) = splitmix64_next(state);
        state = next_state;
        out[i] = value;
        i += 1;
    }

    out
}

