            qp.append_pair("restype", "container");
            qp.append_pair("comp", "list");
            qp.append_pair("maxresults", "5000");
            if !prefix.is_empty() {
                qp.append_pair("prefix", prefix);
            }
            if !marker.is_empty() {
                qp.append_pair("marker", &marker);
            }
        }

        let xml = client
            .get(url)
            .bearer_auth(token)
            .header("x-ms-version", "2023-11-03")
            .send()
            .await
