  "main.rs": "use rxrust::prelude::*;
use std::cell::Cell;
use std::convert::Infallible;
use std::rc::Rc;

type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

fn flipflop(s: Type, r: Type) -> (Type, Type) {
    // Choose one stable initial state for (S=1, R=1): Q=1, !Q=0
    let mut q_subject = Local::behavior_subject::<bool, Infallible>(true);
    let mut qb_subject = Local::behavior_subject::<bool, Infallible>(false);

    let state = Rc::new(Cell::new((true, false)));

    let state_c = state.clone();
    let mut q_out = q_subject.clone();
    let mut qb_out = qb_subject.clone();

    // Important: avoid direct recursive feedback through subjects.
    // Instead, compute next latch state from (S,R,current_state) in one place.
    let sub = s
        .combine_latest(r, |s, r| (s, r))
        .distinct()
        .tap(|(s, r)| println!("input  S={s}, R={r}"))
        .subscribe(move |(s, r)| {
            let (mut q, mut qb) = state_c.get();

            // NAND RS latch (active-low inputs)
            match (s, r) {
                (false, true) => {
                    // Set
                    q = true;
                    qb = false;
                }
                (true, false) => {
                    // Reset
                    q = false;
                    qb = true;
                }
                (true, true) => {
                    // Hold previous state
                }
                (false, false) => {
                    // Invalid/forced state for NAND latch
                    q = true;
                    qb = true;
                }
            }

            if state_c.get() != (q, qb) {
                state_c.set((q, qb));
                q_out.next(q);
                qb_out.next(qb);
            }
        });

    // Keep internal subscription alive for program lifetime.
    std::mem::forget(sub);

    (q_subject.clone().box_it_clone(), qb_subject.clone().box_it_clone())
}

fn main() {
    let mut s = Local::behavior_subject::<bool, Infallible>(true);
    let mut r = Local::behavior_subject::<bool, Infallible>(true);

    let (q, qb) = flipflop(s.clone().box_it_clone(), r.clone().box_it_clone());

    let sub_out = q
        .combine_latest(qb, |q, qb| (q, qb))
        .subscribe(|(q, qb)| println!("Q={q}, !Q={qb}"));

    // Keep output subscription alive.
    std::mem::forget(sub_out);

    // Test sequence
    s.next(false); // set
    s.next(true);  // hold

    r.next(false); // reset
    r.next(true);  // hold
}
