use std::ffi::CString;
use std::io::{self, Write};
use std::ptr;
use std::slice;
use std::thread;
use std::time::{Duration, Instant, SystemTime, UNIX_EPOCH};
use termion::{terminal_size, terminal_size_pixels};

struct ShmBuffer {
    name: String,
    fd: i32,
    ptr: *mut u8,
    len: usize,
}

impl ShmBuffer {
    fn new(len: usize) -> io::Result<Self> {
        let pid = std::process::id();
        let nonce = SystemTime::now()
            .duration_since(UNIX_EPOCH)
            .unwrap_or_default()
            .as_nanos();
        let name = format!("/kitty-rs-{}-{}", pid, nonce);
        let c_name = CString::new(name.clone()).expect("valid shm name");

        let fd = unsafe { shm_open(c_name.as_ptr(), O_CREAT | O_EXCL | O_RDWR, 0o600) };
        if fd < 0 {
            return Err(io::Error::last_os_error());
        }

        if unsafe { ftruncate(fd, len as i64) } != 0 {
            let e = io::Error::last_os_error();
            unsafe {
                close(fd);
                shm_unlink(c_name.as_ptr());
            }
            return Err(e);
        }

        let map_ptr = unsafe {
            mmap(
                ptr::null_mut(),
                len,
                PROT_READ | PROT_WRITE,
                MAP_SHARED,
                fd,
                0,
            )
        };

        if map_ptr == MAP_FAILED {
            let e = io::Error::last_os_error();
            unsafe {
                close(fd);
                shm_unlink(c_name.as_ptr());
            }
            return Err(e);
        }

        Ok(Self {
            name,
            fd,
            ptr: map_ptr as *mut u8,
            len,
        })
    }

    fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { slice::from_raw_parts_mut(self.ptr, self.len) }
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        unsafe {
            let _ = munmap(self.ptr as *mut c_void, self.len);
            let _ = close(self.fd);
            if let Ok(c_name) = CString::new(self.name.clone()) {
                let _ = shm_unlink(c_name.as_ptr());
            }
        }
    }
}

