    let width = pix_w as usize;
    let height = pix_h as usize;
    let bytes_per_pixel = 3usize; // RGB
    let frame_len = width * height * bytes_per_pixel;

    let mut shm = ShmBuffer::new(frame_len)?;
    let shm_name_b64 = STANDARD.encode(shm.name.as_bytes());

