                let b = ((((fx + fy) * std::f32::consts::PI) + t * 0.7).sin() * 0.5 + 0.5) * 255.0;

                buf[idx] = r as u8;
                buf[idx + 1] = g as u8;
                buf[idx + 2] = b as u8;
            }
        }

