            width, height, frame_len, image_id, cols, rows, shm_name_b64
        )?;
        out.flush()?;

        t += 0.08;

        let elapsed = frame_start.elapsed();
        if elapsed < target_frame {
            thread::sleep(target_frame - elapsed);
