fn parse_cons<'i, 'e>(input: &mut SStream<'i, 'e>) -> Result<Cons<'e>, String> {
    let s = input.input.trim();
    if !(s.starts_with('(') && s.ends_with(')')) {
        return Err(format!("expected '(a . b)', got {s:?}"));
    }

    let inner = &s[1..s.len() - 1];
    let parts: Vec<_> = inner.split('.').map(str::trim).collect();
    if parts.len() != 2 {
        return Err(format!("expected exactly one dot, got {inner:?}"));
    }

    let car = parts[0]
        .parse::<u32>()
        .map_err(|e| format!("invalid car: {e}"))?;
    let cdr = parts[1]
        .parse::<u32>()
        .map_err(|e| format!("invalid cdr: {e}"))?;

    Ok(Cons {
        car,
        cdr,
        filename: input.state.filename,
        _sym: input.state.symbol_interner,
    })
}

// Adapter type so we can pass a parser value into the helper
#[derive(Debug, Default, Clone, Copy)]
struct ParseCons;

impl<'i> ParserFamily<'i> for ParseCons {
    type Output<'e> = Cons<'e>;

    fn parse<'e>(&mut self, input: &mut SStream<'i, 'e>) -> Result<Self::Output<'e>, String> {
        parse_cons(input)
    }
}

// --- Generic test helper ---

fn test_input_output<'i, ExOut, P>(input: &'i str, expected_output: &ExOut, mut parser: P)
where
    P: ParserFamily<'i>,
    ExOut: Debug,
    for<'e> P::Output<'e>: PartialEq<ExOut> + Debug,
{
    // Local state whose lifetime is used as `'e`
    let symbol_interner = SymbolInterner::new();

    let filename_interner = FilenameInterner::new();
    let filename = filename_interner.intern("<test>");

    let mut stateful = SStream {
        input,
        state: State {
            filename,
            symbol_interner: &symbol_interner,
        },
    };

    let parsed = parser.parse(&mut stateful).unwrap_or_else(|e| {
        panic!(
            "Failed on:\n\tinput: {input:?}\n\texpected output: {expected_output:?}\n\n{e}"
        )
    });

    println!(
        "Testing:\n\tinput: {input:?}\n\texpected output: {expected_output:?}"
    );
    assert_eq!(&parsed, expected_output);
}

fn main() {
    let expected_output = ExpectedCons {
        car: 1,
        cdr: 2,
        filename: "<test>".to_string(),
    };

    test_input_output("(1 . 2)", &expected_output, ParseCons);
    println!("All checks passed.");
}
"
}

