/// Parse LanceDB-style ISO datetime strings into UTC DateTime.
/// Handles:
/// - "YYYY-MM-DDTHH:MM:SS"
/// - "YYYY-MM-DDTHH:MM:SS.sss..."
/// - RFC3339 forms with timezone (e.g. trailing Z or +00:00)
fn parse_lancedb_datetime(input: &str) -> Result<DateTime<Utc>, String> {
    // If input came from debug-printing, it may include surrounding quotes.
    let s = input.trim().trim_matches('"');

    // 1) Try fully-qualified RFC3339 first (has timezone/offset)
    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // 2) Try naive timestamp with optional fractional seconds
    //    Example: 2025-08-02T17:35:41.409
    if let Ok(ndt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S%.f") {
        return Ok(DateTime::<Utc>::from_naive_utc_and_offset(ndt, Utc));
    }

    // 3) Try naive timestamp without fractional seconds
    //    Example: 1970-01-01T00:00:00
    if let Ok(ndt) = NaiveDateTime::parse_from_str(s, "%Y-%m-%dT%H:%M:%S") {
        return Ok(DateTime::<Utc>::from_naive_utc_and_offset(ndt, Utc));
    }

    Err(format!("Could not parse datetime: {s}"))
}

fn date_string_to_unix_millis(input: &str) -> Result<i64, String> {
    let dt = parse_lancedb_datetime(input)?;
