  "main.rs": "use std::{
    future::Future,
    pin::Pin,
    sync::Arc,
    task::{Context, Poll, Wake, Waker},
    time::Duration,
};

#[derive(Debug)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// A no-op waker used for a single opportunistic poll.
// If the future is Pending, we immediately hand it to Tokio (spawn),
// where it will be polled again with a proper runtime waker.
struct NoopWaker;
impl Wake for NoopWaker {
    fn wake(self: Arc<Self>) {}
    fn wake_by_ref(self: &Arc<Self>) {}
}

fn noop_waker() -> Waker {
    Waker::from(Arc::new(NoopWaker))
}

fn try_poll<X>(future: Pin<&mut impl Future<Output = X>>) -> TryPollResult<X> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match future.poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

// Non-async function, but intended to be called inside a Tokio runtime.
fn use_now_or_spawn<F, T>(name: &'static str, fut: F)
where
    F: Future<Output = T> + Send + 'static,
    T: std::fmt::Debug + Send + 'static,
{
    let mut fut = Box::pin(fut);

    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("{name}: ready immediately -> {value:?}");
        }
        TryPollResult::Pending => {
            println!("{name}: pending; spawning task to await it...");
