use futures::future::BoxFuture;
use std::collections::HashMap;
use std::future::{ready, IntoFuture, Ready};
use std::sync::Arc;

// ===== Minimal request/response types =====
#[derive(Debug)]
struct Request {
    path: String,
}

#[derive(Debug)]
struct Response(&'static str);

// Let sync handlers (that return Response directly) participate in async flow.
impl IntoFuture for Response {
    type Output = Response;
    type IntoFuture = Ready<Response>;

    fn into_future(self) -> Self::IntoFuture {
        ready(self)
    }
}

// Unified stored handler type: (&Request) -> BoxFuture<Response>
type HandlerFn =
    dyn for<'a> Fn(&'a Request) -> BoxFuture<'a, Response> + Send + Sync + 'static;

#[derive(Clone)]
struct Handler(Arc<HandlerFn>);

impl Handler {
    fn call<'a>(&'a self, req: &'a Request) -> BoxFuture<'a, Response> {
        (self.0)(req)
    }
}

trait IntoHandler {
    fn into_handler(self) -> Handler;
}

// Helper alias: output type of calling F with &Request for a specific lifetime 'a
type FnOutput<'a, F> = <F as FnOnce<(&'a Request,)>>::Output;

// One blanket impl that accepts BOTH:
// - sync fns:  fn(&Request) -> Response
// - async fns: fn(&Request) -> impl Future<Output = Response>
impl<F> IntoHandler for F
where
    F: Send + Sync + 'static + for<'a> Fn(&'a Request),
    for<'a> FnOutput<'a, F>: IntoFuture<Output = Response> + 'a,
    for<'a> <FnOutput<'a, F> as IntoFuture>::IntoFuture: Send + 'a,
{
    fn into_handler(self) -> Handler {
        Handler(Arc::new(move |req| Box::pin(self(req).into_future())))
    }
}

