    routes: HashMap<String, Handler>,
}

impl Server {
    fn new() -> Self {
        Self {
            routes: HashMap::new(),
        }
    }

    fn add_route<H>(&mut self, path: &str, handler: H)
    where
        H: IntoHandler,
    {
        self.routes.insert(path.to_string(), handler.into_handler());
    }

    fn handle(&self, path: &str) -> Option<Response> {
        let req = Request {
