fn nix_to_io(err: nix::errno::Errno) -> io::Error {
    io::Error::from_raw_os_error(err as i32)
}

fn set_nonblocking<T: AsRawFd>(io_obj: &T) -> io::Result<()> {
    let fd = io_obj.as_raw_fd();
    let flags = fcntl(fd, FcntlArg::F_GETFL).map_err(nix_to_io)?;
    let flags = OFlag::from_bits_truncate(flags);
    let _ = fcntl(fd, FcntlArg::F_SETFL(flags | OFlag::O_NONBLOCK)).map_err(nix_to_io)?;
    Ok(())
}

/// Spawns a PTY child and returns:
/// - tx_in: send raw bytes/strings into PTY
/// - rx_out: receive PTY output chunks
fn spawn_agent_worker(cmd: &str) -> io::Result<(Sender<String>, Receiver<String>)> {
    let (tx_in, rx_in) = unbounded::<String>();
    let (tx_out, rx_out) = unbounded::<String>();

    let cmd = cmd.to_string();
    thread::spawn(move || {
        let mut session = match spawn(&cmd) {
            Ok(s) => s,
            Err(e) => {
                let _ = tx_out.send(format!("[spawn error] {e}\n"));
                return;
            }
        };

        if let Err(e) = set_nonblocking(&session) {
            let _ = tx_out.send(format!("[warn] failed to set nonblocking PTY: {e}\n"));
            // Continue anyway; behavior may block depending on platform.
        }

        let mut buf = [0u8; 4096];

        loop {
            // 1) Drain pending input (non-blocking)
            while let Ok(msg) = rx_in.try_recv() {
                if msg == "__EXIT__" {
                    let _ = tx_out.send("\n[worker shutdown]\n".to_string());
                    return;
                }

                if let Err(e) = session.send(&msg) {
                    let _ = tx_out.send(format!("\n[send error] {e}\n"));
                    return;
                }
            }

            // 2) Pull PTY output (non-blocking)
            match session.read(&mut buf) {
                Ok(0) => {
                    let _ = tx_out.send("\n[process terminated]\n".to_string());
                    return;
                }
                Ok(n) => {
                    let out = String::from_utf8_lossy(&buf[..n]).to_string();
                    let _ = tx_out.send(out);
                }
                Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
                    // Nothing to read right now.
                }
                Err(e) => {
                    let _ = tx_out.send(format!("\n[read error] {e}\n"));
                    return;
                }
            }

            // Prevent busy spin.
            thread::sleep(Duration::from_millis(10));
        }
    });

    Ok((tx_in, rx_out))
}

fn main() -> io::Result<()> {
    // Use a shell for easy testing; override with first arg if desired.
    let cmd = std::env::args().nth(1).unwrap_or_else(|| "sh".to_string());

