  "main.rs": "use axum::{
    extract::{ws::Message, Path, Request, State, WebSocketUpgrade},
    http::{header, HeaderValue, Method, StatusCode},
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use tower_http::cors::CorsLayer;

#[derive(Clone)]
struct AppState {
    allowed_ws_origin: String,
}

#[tokio::main]
async fn main() {
    let state = AppState {
        allowed_ws_origin: "https://www.example.com".to_string(),
    };

    // Your normal HTTP CORS policy (doesn't protect WS upgrades by itself).
    let cors = CorsLayer::new()
        .allow_origin(
            "https://www.example.com"
                .parse::<HeaderValue>()
                .expect("valid origin"),
        )
        .allow_methods([Method::GET, Method::POST])
        .allow_headers([header::CONTENT_TYPE]);

    // Put websocket routes in a sub-router and protect them with a middleware.
    let ws_routes = Router::new()
        .route("/client/{session_id}", get(client_handler))
        .route_layer(middleware::from_fn_with_state(
            state.clone(),
            websocket_origin_guard,
        ));

    let app = Router::new()
        .route("/", get(|| async { "OK" }))
        .merge(ws_routes)
        .layer(cors)
        .with_state(state);

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000")
        .await
        .expect("bind listener");

    println!("listening on http://127.0.0.1:3000");
    axum::serve(listener, app).await.expect("server error");
}

async fn websocket_origin_guard(
    State(state): State<AppState>,
    req: Request,
    next: Next,
) -> Result<Response, StatusCode> {
    let is_websocket_upgrade = req
        .headers()
        .get(header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false)
        || req.headers().contains_key("sec-websocket-key");

    if !is_websocket_upgrade {
        return Ok(next.run(req).await);
    }

    let origin = req
        .headers()
        .get(header::ORIGIN)
        .and_then(|v| v.to_str().ok())
        .ok_or(StatusCode::FORBIDDEN)?;

    if origin != state.allowed_ws_origin {
        return Err(StatusCode::FORBIDDEN);
    }

    Ok(next.run(req).await)
}

async fn client_handler(ws: WebSocketUpgrade, Path(session_id): Path<String>) -> impl IntoResponse {
    ws.on_upgrade(move |mut socket| async move {
        let _ = socket
            .send(Message::Text(format!("connected to session: {session_id}").into()))
            .await;

        while let Some(msg_result) = socket.recv().await {
            match msg_result {
                Ok(Message::Text(text)) => {
                    let _ = socket.send(Message::Text(format!("echo: {text}").into())).await;
                }
                Ok(Message::Binary(bin)) => {
                    let _ = socket.send(Message::Binary(bin)).await;
                }
                Ok(Message::Close(_)) => break,
                Ok(_) => {}
                Err(_) => break,
            }
        }
    })
}
"
