// `#[async_trait]` rewrites async methods into boxed futures,
// making this trait object-safe (`dyn RemoteActions`).
#[async_trait]
pub trait RemoteActions: Send {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()>;
    async fn remove_repo(&mut self, path: &Path) -> Result<()>;
    async fn add_repo(&mut self, path: &Path) -> Result<()>;

