#[derive(Default)]
struct RealRemote {
    repos: Vec<PathBuf>,
}

#[async_trait]
impl RemoteActions for RealRemote {
    async fn change_path(&mut self, from: &Path, to: &Path) -> Result<()> {
        println!("[real] moving repo: {} -> {}", from.display(), to.display());
        sleep(Duration::from_millis(80)).await;

        if let Some(pos) = self.repos.iter().position(|p| p == from) {
            self.repos[pos] = to.to_path_buf();
            Ok(())
        } else {
            Err(anyhow!("repo not found: {}", from.display()))
        }
    }

    async fn remove_repo(&mut self, path: &Path) -> Result<()> {
        println!("[real] removing repo: {}", path.display());
        sleep(Duration::from_millis(50)).await;

        if let Some(pos) = self.repos.iter().position(|p| p == path) {
            self.repos.remove(pos);
            Ok(())
        } else {
            Err(anyhow!("repo not found: {}", path.display()))
        }
    }

    async fn add_repo(&mut self, path: &Path) -> Result<()> {
