  "main.rs": "use async_trait::async_trait;
use std::sync::Arc;
use std::time::Duration;
use tokio::time::sleep;
use tracing::Instrument;
use tracing_subscriber::fmt::format::FmtSpan;
use tracing_subscriber::prelude::*;

#[derive(Clone)]
struct RequestContext {
    // Store the request/root span in shared context.
    request_span: tracing::Span,
}

#[async_trait]
trait Stages: Send + Sync {
    async fn stage_1(&self, ctx: Arc<RequestContext>);
    async fn stage_2(&self, ctx: Arc<RequestContext>);
    async fn stage_3(&self, ctx: Arc<RequestContext>);
}

struct Proxy;

#[async_trait]
impl Stages for Proxy {
    async fn stage_1(&self, ctx: Arc<RequestContext>) {
        // Rehydrate request span as current for this callback execution.
        async move {
            tracing::info!("stage_1 callback received");

            async move {
                tracing::info!("stage_1 begin");
                sleep(Duration::from_millis(120)).await;
                tracing::info!("stage_1 end");
            }
            .instrument(tracing::info_span!("stage_1"))
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }

    async fn stage_2(&self, ctx: Arc<RequestContext>) {
        // Rehydrate request span as current for this callback execution.
        async move {
            tracing::info!("stage_2 callback received");

            async move {
                tracing::info!("stage_2 begin");
                sleep(Duration::from_millis(60)).await;

                async move {
                    tracing::info!("upstream begin");
                    sleep(Duration::from_millis(90)).await;
                    tracing::info!("upstream end");
                }
                .instrument(tracing::info_span!("upstream"))
                .await;

                tracing::info!("stage_2 end");
            }
            .instrument(tracing::info_span!("stage_2"))
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }

    async fn stage_3(&self, ctx: Arc<RequestContext>) {
        // Rehydrate request span as current for this callback execution.
        async move {
            tracing::info!("stage_3 callback received");

            async move {
                tracing::info!("stage_3 begin");
                sleep(Duration::from_millis(40)).await;
                tracing::info!("stage_3 end");
            }
            .instrument(tracing::info_span!("stage_3"))
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }
}

async fn run_request(proxy: Arc<dyn Stages>, request_id: u64) {
    let request_span = tracing::info_span!("request", request_id);
    let ctx = Arc::new(RequestContext {
        request_span: request_span.clone(),
    });

    // Simulate Pingora/Tokio invoking callbacks at arbitrary times/threads.
    let t1 = tokio::spawn({
        let proxy = proxy.clone();
        let ctx = ctx.clone();
        async move {
            sleep(Duration::from_millis(10)).await;
            proxy.stage_1(ctx).await;
        }
    });

    let t2 = tokio::spawn({
        let proxy = proxy.clone();
        let ctx = ctx.clone();
        async move {
            sleep(Duration::from_millis(30)).await;
            proxy.stage_2(ctx).await;
        }
    });

    let t3 = tokio::spawn({
        let proxy = proxy.clone();
        let ctx = ctx.clone();
        async move {
            sleep(Duration::from_millis(20)).await;
            proxy.stage_3(ctx).await;
        }
    });

    let _ = tokio::join!(t1, t2, t3);

    // Emit a final event under the request span.
    async move {
        tracing::info!("request lifecycle finished");
    }
    .instrument(request_span)
