  "main.rs": "use syn::{parse_quote, punctuated::Punctuated, Item, ItemUse, UseGroup, UseName, UseTree};

#[derive(Copy, Clone, Debug, Eq, PartialEq)]
enum PrefixState {
    /// We have not yet seen the first path segment in this subtree.
    Root,
    /// This subtree starts with `vexide`.
    SeenVexide,
    /// This subtree starts with something else.
    Other,
}

impl PrefixState {
    fn descend(self, ident: &syn::Ident) -> Self {
        match self {
            PrefixState::Root => {
                if ident == "vexide" {
                    PrefixState::SeenVexide
                } else {
                    PrefixState::Other
                }
            }
            PrefixState::SeenVexide => PrefixState::SeenVexide,
            PrefixState::Other => PrefixState::Other,
        }
    }
}

fn rewrite_use_item(item_use: &mut ItemUse) {
    rewrite_use_tree(&mut item_use.tree, PrefixState::Root);
    simplify_use_tree(&mut item_use.tree);
}

/// Rewrites `vexide::devices::...` to `vexide::...` recursively.
fn rewrite_use_tree(tree: &mut UseTree, state: PrefixState) {
    // If we're currently under `vexide` and this node is `devices::...`, drop `devices`.
    loop {
        let replacement = match tree {
            UseTree::Path(p) if state == PrefixState::SeenVexide && p.ident == "devices" => {
                Some((*p.tree).clone())
            }
            _ => None,
        };

        if let Some(new_tree) = replacement {
            *tree = new_tree;
            continue;
        }
        break;
    }

    match tree {
        UseTree::Path(p) => {
            let next = state.descend(&p.ident);
            rewrite_use_tree(&mut p.tree, next);
        }
        UseTree::Group(g) => {
            for child in g.items.iter_mut() {
                rewrite_use_tree(child, state);
            }
            flatten_group(g);
        }
        UseTree::Name(n) => {
            // `use vexide::devices;` inside a `vexide::...` subtree -> `use vexide::self;`
            // (later simplified to `use vexide;` when possible)
            if state == PrefixState::SeenVexide && n.ident == "devices" {
                *tree = parse_quote!(self);
            }
        }
        UseTree::Rename(r) => {
            // `use vexide::devices as dev;` -> `use vexide::self as dev;`
            if state == PrefixState::SeenVexide && r.ident == "devices" {
                let rename = r.rename.clone();
                *tree = parse_quote!(self as #rename);
            }
        }
        UseTree::Glob(_) => {}
    }
}

/// Flattens nested groups like `{ {a, b}, c }` -> `{a, b, c}`.
fn flatten_group(group: &mut UseGroup) {
    let old_items = std::mem::take(&mut group.items);
    let mut new_items: Punctuated<UseTree, syn::Token![,]> = Punctuated::new();

    for item in old_items {
        match item {
            UseTree::Group(mut inner) => {
                flatten_group(&mut inner);
                for child in inner.items {
                    new_items.push(child);
                }
            }
            other => new_items.push(other),
        }
    }

    group.items = new_items;
}

/// Small cleanup pass:
/// - collapse `vexide::self` into just `vexide`.
fn simplify_use_tree(tree: &mut UseTree) {
    match tree {
        UseTree::Path(p) => {
            simplify_use_tree(&mut p.tree);

            let collapse = matches!(&*p.tree, UseTree::Name(n) if n.ident == "self");
            if collapse {
                let ident = p.ident.clone();
                *tree = UseTree::Name(UseName { ident });
            }
        }
        UseTree::Group(g) => {
            for child in g.items.iter_mut() {
                simplify_use_tree(child);
            }
            flatten_group(g);
        }
        UseTree::Name(_) | UseTree::Rename(_) | UseTree::Glob(_) => {}
    }
}

fn main() {
    let src = r#"
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};
use foo::vexide::devices::should_not_change;
use vexide::devices as dev;
"#;

    let mut file = syn::parse_file(src).expect("valid Rust source");

    for item in file.items.iter_mut() {
        if let Item::Use(item_use) = item {
            rewrite_use_item(item_use);
        }
    }

    println!("=== Original ===\n{src}");
    println!("=== Rewritten ===\n{}", prettyplease::unparse(&file));
}
"
}

