        while bg_running.load(Ordering::Relaxed) {
            {
                let _guard = bg_lock.lock().unwrap();
                println!("[child async] background event #{n}");
                let _ = io::stdout().flush();
            }
            n += 1;
            thread::sleep(Duration::from_millis(1500));
