fn run() -> Result<bool, String> {
    let (python_cmd, mut python_prefix_args) = find_python()
        .ok_or_else(|| "Could not find a Python interpreter (tried: python3, python, py -3).".to_string())?;

    let script_path = write_temp_script(PY_SCRIPT).map_err(|e| format!("Failed to write temp script: {e}"))?;

