    python_prefix_args.push(script_path.to_string_lossy().to_string());
    python_prefix_args.push("hello-from-rust".to_string());

    let status = Command::new(&python_cmd)
        .args(&python_prefix_args)
        .stdin(Stdio::inherit())
        .stdout(Stdio::inherit())
        .stderr(Stdio::inherit())
        .status()
        .map_err(|e| format!("Failed to run Python interpreter '{python_cmd}': {e}"))?;

    // Best-effort cleanup of temporary script.
    let _ = fs::remove_file(&script_path);

    Ok(status.success())
}

fn find_python() -> Option<(String, Vec<String>)> {
    // Optional override: PYTHON_BIN can be set to a full command path/name.
    if let Ok(custom) = env::var("PYTHON_BIN") {
        if command_works(&custom, &["--version"]) {
            return Some((custom, vec![]));
        }
    }

    // Try common commands in order.
    let candidates: Vec<(&str, Vec<&str>)> = vec![
        ("python3", vec![]),
        ("python", vec![]),
        // Windows launcher
        ("py", vec!["-3"]),
    ];

    for (cmd, prefix) in candidates {
        let mut args = prefix.clone();
        args.push("--version");
        if command_works(cmd, &args) {
            return Some((
                cmd.to_string(),
                prefix.into_iter().map(|s| s.to_string()).collect(),
            ));
        }
    }

    None
}

fn command_works(cmd: &str, args: &[&str]) -> bool {
    Command::new(cmd)
        .args(args)
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false)
