  "main.rs": "use core::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::thread;

/// Replacement for `fetch_add(1, Ordering::Relaxed)` using `critical_section`.
///
/// Why `Relaxed` here?
/// - Your original op was `fetch_add(..., Relaxed)`.
/// - You only need atomicity of the counter increment itself (unique index values),
///   not extra cross-thread memory ordering.
/// - The critical section provides mutual exclusion for the read-modify-write sequence,
///   so `load/store(Relaxed)` is enough for that same intent.
fn fetch_add_relaxed_with_cs(counter: &AtomicUsize) -> usize {
    critical_section::with(|_| {
        let old = counter.load(Ordering::Relaxed);
        counter.store(old.wrapping_add(1), Ordering::Relaxed);
        old
    })
}

fn main() {
    let counter = Arc::new(AtomicUsize::new(0));

    const THREADS: usize = 4;
    const ITERS_PER_THREAD: usize = 25_000;

    let mut handles = Vec::new();

    for _ in 0..THREADS {
        let c = Arc::clone(&counter);
        handles.push(thread::spawn(move || {
            for _ in 0..ITERS_PER_THREAD {
                let _idx = fetch_add_relaxed_with_cs(&c);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let final_value = counter.load(Ordering::Relaxed);
    let expected = THREADS * ITERS_PER_THREAD;

    println!("final counter = {final_value}, expected = {expected}");
    println!(
        "For replacing fetch_add(Relaxed): use Relaxed load/store inside critical_section."
    );
}
"
}

