/// Builds a rotation where local +Z points along `world_normal`,
/// and local +X/+Y remain aligned to the cube's face axes.
///
/// This is what you want for a face gizmo: flush + properly "twisted" with the block.
fn face_aligned_rotation_from_world_normal(block_rotation: Quat, world_normal: Vec3) -> Quat {
    // Convert hit normal to block local-space so we can snap to the nearest cube axis.
    let local_n = (block_rotation.inverse() * world_normal).normalize();
    let local_n_snapped = snap_to_axis(local_n);

    // Pick a stable in-face local axis (u) for each major face direction.
    // This makes the gizmo orientation deterministic and aligned with cube edges.
    let local_u = if local_n_snapped.x.abs() > 0.5 {
        Vec3::Y
    } else if local_n_snapped.y.abs() > 0.5 {
        Vec3::Z
    } else {
        Vec3::X
    };

    let n = (block_rotation * local_n_snapped).normalize();
    let mut u = (block_rotation * local_u).normalize();

    // Orthonormalize in case of numeric drift.
    let v = n.cross(u).normalize();
    u = v.cross(n).normalize();

    // Local gizmo basis: X=u, Y=v, Z=n
    let basis = Mat3::from_cols(u, v, n);
    Quat::from_mat3(&basis)
}

fn snap_to_axis(v: Vec3) -> Vec3 {
    let a = v.abs();
    if a.x >= a.y && a.x >= a.z {
        Vec3::new(v.x.signum(), 0.0, 0.0)
    } else if a.y >= a.x && a.y >= a.z {
        Vec3::new(0.0, v.y.signum(), 0.0)
    } else {
        Vec3::new(0.0, 0.0, v.z.signum())
    }
}
