#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum State {
    Unquoted,
    SingleQuoted,
}

fn tokenize_shell(input: &str) -> Result<Vec<String>, String> {
    let mut state = State::Unquoted;
    let mut tokens = Vec::new();
    let mut current = String::new();

    // `token_started` is needed so cases like '' become an empty token.
    let mut token_started = false;

    for (idx, ch) in input.char_indices() {
        match state {
            State::Unquoted => {
                if ch.is_whitespace() {
                    if token_started {
                        tokens.push(std::mem::take(&mut current));
                        token_started = false;
                    }
                } else if ch == '\'' {
                    state = State::SingleQuoted;
                    token_started = true;
                } else {
                    current.push(ch);
                    token_started = true;
                }
            }
            State::SingleQuoted => {
                if ch == '\'' {
                    state = State::Unquoted;
                } else {
                    current.push(ch);
                }
            }
        }

        // Keep `idx` used for better error messages if needed in future.
        let _ = idx;
    }

    if state == State::SingleQuoted {
        return Err("unmatched single quote".to_string());
    }

    if token_started {
        tokens.push(current);
    }

    Ok(tokens)
}

fn main() {
    let input = env::args()
        .nth(1)
        .unwrap_or_else(|| " one  ' two  'three    four".to_string());

    match tokenize_shell(&input) {
        Ok(tokens) => {
            println!("input: {:?}", input);
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("Error: {}", e);
            std::process::exit(1);
        }
    }
}
