  "main.rs": "use flatbuffers::FlatBufferBuilder;
use rayon::prelude::*;

#[derive(Debug, Clone)]
struct FrontMatter {
    ignored_parsers: Vec<String>,
}

#[derive(Debug, Clone)]
struct MdxParsingResult {
    front_matter: Option<FrontMatter>,
    content: String,
}

impl MdxParsingResult {
    /// Important pattern:
    /// 1) Do CPU-heavy prep in parallel (owned Rust values)
    /// 2) Do FlatBufferBuilder writes on one thread, sequentially
    ///
    /// FlatBufferBuilder is mutable state and not designed for concurrent writes.
    fn serialize_to_flatbuffer(&self) -> Vec<u8> {
        // Parallel step (safe): transform data before touching FlatBufferBuilder
        let normalized_ignored_parsers: Vec<String> = self
            .front_matter
            .as_ref()
            .map(|fm| {
                fm.ignored_parsers
                    .par_iter()
                    .map(|s| s.trim().to_ascii_lowercase())
                    .collect()
            })
            .unwrap_or_default();

        // Single-threaded builder step
        let mut builder = FlatBufferBuilder::new();

        // Create content string
        let content_offset = builder.create_string(&self.content);

        // Create ignored parser strings
        let parser_offsets: Vec<_> = normalized_ignored_parsers
            .iter()
            .map(|s| builder.create_string(s))
            .collect();

        // For this self-contained demo (no generated schema),
        // we store everything as a root vector of strings:
        // [content, ignored_parser_1, ignored_parser_2, ...]
        let mut all_offsets = Vec::with_capacity(1 + parser_offsets.len());
        all_offsets.push(content_offset);
        all_offsets.extend(parser_offsets);

        let root_vec = builder.create_vector(&all_offsets);
        builder.finish_minimal(root_vec);

        builder.finished_data().to_vec()
    }
}

fn main() {
    let result = MdxParsingResult {
        front_matter: Some(FrontMatter {
            ignored_parsers: vec![
                "  YAML  ".to_string(),
                " TOML".to_string(),
                "Json ".to_string(),
            ],
        }),
        content: "# Hello from FlatBuffers".to_string(),
    };

    let bytes = result.serialize_to_flatbuffer();

    println!("Serialized {} bytes", bytes.len());
    println!(
        "First 24 bytes: {:02X?}",
        &bytes[..bytes.len().min(24)]
    );

    println!("Done. This demonstrates the borrow-safe pattern.");
}
