    let (file_part, fragment) = reference
        .split_once('#')
        .map_or((reference, ""), |(f, frag)| (f, frag));

    if file_part.is_empty() {
        bail!("$ref is missing a file path: {reference}");
    }

    let target_file = base_dir.join(file_part);
    let text = fs::read_to_string(&target_file)
        .with_context(|| format!("failed to read referenced file: {}", target_file.display()))?;
    let root: Value = serde_json::from_str(&text)
        .with_context(|| format!("failed to parse referenced JSON: {}", target_file.display()))?;

    let selected = if fragment.is_empty() {
        &root
    } else {
        if !fragment.starts_with('/') {
            bail!(
                "JSON Pointer fragment must start with '/': got #{fragment} in $ref {reference}"
            );
        }

        root.pointer(fragment).with_context(|| {
            format!(
                "pointer '#{}' not found in file {}",
                fragment,
                target_file.display()
            )
        })?
    };

    let paths: Vec<PathBuf> = serde_json::from_value(selected.clone())
        .context("referenced value is not a list of path strings")?;

