  "main.rs": "use serde::{Deserialize, Serialize};
use serde_json::Value;
use std::collections::HashMap;

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
enum RichTextType {
    Text,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct TextObject {
    content: String,
    link: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct RichTextObject {
    annotations: Option<Value>,
    data_type: Option<RichTextType>,
    equation: Option<Value>,
    mention: Option<Value>,
    plain_text: Option<String>,
    href: Option<String>,
    text: TextObject,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct SelectObject {
    id: Option<String>,
    color: Option<String>,
    name: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "snake_case")]
enum PropertyValue {
    Title(Vec<RichTextObject>),
    Url(String),
    MultiSelect(Vec<SelectObject>),
}

trait ToNotionProperties {
    fn to_notion_properties(&self) -> HashMap<String, PropertyValue>;
}

// Marker types for property kind dispatch.
struct TitleKind;
struct UrlKind;
struct MultiSelectKind;

trait NotionConvert<K> {
    fn to_property(&self) -> Option<PropertyValue>;
}

impl NotionConvert<TitleKind> for String {
    fn to_property(&self) -> Option<PropertyValue> {
        Some(PropertyValue::Title(vec![RichTextObject {
            annotations: None,
            data_type: Some(RichTextType::Text),
            equation: None,
            mention: None,
            plain_text: None,
            href: None,
            text: TextObject {
                content: self.clone(),
                link: None,
            },
        }]))
    }
}

impl NotionConvert<UrlKind> for String {
    fn to_property(&self) -> Option<PropertyValue> {
        Some(PropertyValue::Url(self.clone()))
    }
}

impl NotionConvert<MultiSelectKind> for Vec<Value> {
    fn to_property(&self) -> Option<PropertyValue> {
        let items = self
            .iter()
            .map(|v| SelectObject {
                id: None,
                color: None,
                name: match v {
                    Value::String(s) => s.clone(),
                    _ => v.to_string(),
                },
            })
            .collect();

        Some(PropertyValue::MultiSelect(items))
    }
}

impl<K, T> NotionConvert<K> for Option<T>
where
    T: NotionConvert<K>,
{
    fn to_property(&self) -> Option<PropertyValue> {
        self.as_ref().and_then(|v| v.to_property())
    }
}

fn insert_notion_property<K, V>(map: &mut HashMap<String, PropertyValue>, name: &str, value: &V)
where
    V: NotionConvert<K>,
{
    if let Some(prop) = value.to_property() {
        map.insert(name.to_string(), prop);
    }
}

macro_rules! notion_kind_marker {
    ("title") => {
        TitleKind
    };
    (title) => {
        TitleKind
    };
    ("url") => {
        UrlKind
    };
    (url) => {
        UrlKind
    };
    ("MultiSelect") => {
        MultiSelectKind
    };
    ("multi_select") => {
        MultiSelectKind
    };
    (MultiSelect) => {
        MultiSelectKind
    };
    (multi_select) => {
        MultiSelectKind
    };
}

macro_rules! notion_struct {
    (
        $(#[$smeta:meta])*
        $vis:vis struct $name:ident {
            $(
                #[notion_property(type = $ptype:tt, name = $pname:literal)]
                $fvis:vis $fname:ident : $fty:ty
            ),* $(,)?
        }
    ) => {
        $(#[$smeta])*
        $vis struct $name {
            $( $fvis $fname : $fty ),*
        }

        impl ToNotionProperties for $name {
            fn to_notion_properties(&self) -> HashMap<String, PropertyValue> {
                let mut tmp = HashMap::new();
                $(
                    insert_notion_property::<notion_kind_marker!($ptype), _>(
                        &mut tmp,
                        $pname,
                        &self.$fname,
                    );
                )*
                tmp
            }
        }
    };
}

