#[derive(Debug, Clone, Copy)]
struct Entry {
    offset: u64,
    len: u64,
}

/// Custom asset source reader: serves files from one archive file lazily.
/// Only the requested entry bytes are read.
struct PackReader {
    archive_path: PathBuf,
    index: OnceLock<HashMap<String, Entry>>,
}

impl PackReader {
    fn new(archive_path: PathBuf) -> Self {
        Self {
            archive_path,
            index: OnceLock::new(),
        }
    }

    fn index(&self) -> Result<&HashMap<String, Entry>, AssetReaderError> {
        self.index
            .get_or_try_init(|| load_pack_index(&self.archive_path).map_err(AssetReaderError::from))
    }
}

impl AssetReader for PackReader {
    fn read<'a>(&'a self, path: &'a Path) -> BoxedFuture<'a, Result<Box<Reader<'a>>, AssetReaderError>> {
        Box::pin(async move {
            let key = normalize(path);
            let index = self.index()?;
            let entry = index
                .get(&key)
                .ok_or_else(|| AssetReaderError::NotFound(path.to_path_buf()))?;

            let mut file = File::open(&self.archive_path)?;
            file.seek(SeekFrom::Start(entry.offset))?;
            let mut bytes = vec![0u8; entry.len as usize];
            file.read_exact(&mut bytes)?;

            println!("[PackReader] lazy read: {key} ({} bytes)", entry.len);
            Ok(Box::new(VecReader::new(bytes)))
        })
    }

    fn read_meta<'a>(
        &'a self,
        path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<Reader<'a>>, AssetReaderError>> {
        Box::pin(async move { Err(AssetReaderError::NotFound(path.to_path_buf())) })
    }

    fn read_directory<'a>(
        &'a self,
        _path: &'a Path,
    ) -> BoxedFuture<'a, Result<Box<PathStream>, AssetReaderError>> {
        Box::pin(async move {
            let stream = futures_lite::stream::empty::<PathBuf>();
            Ok(Box::new(stream))
        })
    }

    fn is_directory<'a>(&'a self, _path: &'a Path) -> BoxedFuture<'a, Result<bool, AssetReaderError>> {
        Box::pin(async move { Ok(false) })
    }
}

#[derive(Asset, TypePath, Debug)]
struct BinAsset(Vec<u8>);

#[derive(Default)]
struct BinAssetLoader;

impl AssetLoader for BinAssetLoader {
    type Asset = BinAsset;
    type Settings = ();
    type Error = std::io::Error;

    async fn load(
        &self,
        reader: &mut Reader<'_>,
        _settings: &Self::Settings,
        _load_context: &mut LoadContext<'_>,
    ) -> Result<Self::Asset, Self::Error> {
        let mut bytes = Vec::new();
        reader.read_to_end(&mut bytes).await?;
        Ok(BinAsset(bytes))
    }

    fn extensions(&self) -> &[&str] {
        &["bin"]
    }
}

#[derive(Resource)]
struct DemoHandles(Vec<Handle<BinAsset>>);

fn main() {
    let archive_path = PathBuf::from("assets/demo.pack");
    create_demo_pack_if_missing(&archive_path, 3_200).expect("failed to create demo archive");

    App::new()
        .add_plugins((MinimalPlugins, AssetPlugin::default()))
        .init_asset::<BinAsset>()
        .init_asset_loader::<BinAssetLoader>()
        .register_asset_source(
