        asset_server.load("pack://tex_3199.bin"),
    ];

    println!("Requested 3 assets from a 3200-entry archive.");
    commands.insert_resource(DemoHandles(handles));
}

fn print_when_loaded(
    mut exit: EventWriter<AppExit>,
    handles: Res<DemoHandles>,
    assets: Res<Assets<BinAsset>>,
    mut done: Local<bool>,
) {
    if *done {
        return;
    }

    let mut all_loaded = true;
    for (i, h) in handles.0.iter().enumerate() {
        if let Some(asset) = assets.get(h) {
            println!("Loaded handle #{i}: {} bytes", asset.0.len());
        } else {
            all_loaded = false;
        }
    }

    if all_loaded {
        *done = true;
        println!("Done. Notice only 3 lazy reads were logged.");
        exit.send(AppExit::Success);
    }
}

fn create_demo_pack_if_missing(path: &Path, count: usize) -> std::io::Result<()> {
    if path.exists() {
        return Ok(());
    }
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }

    let mut names_and_data = Vec::with_capacity(count);
    for i in 0..count {
        let name = format!("tex_{i:04}.bin");
        let data = format!("this is payload for {name}").into_bytes();
        names_and_data.push((name, data));
    }

    let header_len = 8u64; // magic(4) + count(u32)
    let index_len: u64 = names_and_data
        .iter()
        .map(|(name, _)| 2u64 + name.len() as u64 + 8 + 8)
        .sum();
    let mut next_offset = header_len + index_len;

    let mut file = File::create(path)?;
    file.write_all(b"LPK1")?;
    write_u32(&mut file, names_and_data.len() as u32)?;

    let mut entries = Vec::with_capacity(names_and_data.len());
    for (name, data) in &names_and_data {
        entries.push((name.clone(), Entry { offset: next_offset, len: data.len() as u64 }));
        next_offset += data.len() as u64;
    }

    for (name, entry) in &entries {
        write_u16(&mut file, name.len() as u16)?;
        file.write_all(name.as_bytes())?;
        write_u64(&mut file, entry.offset)?;
        write_u64(&mut file, entry.len)?;
    }

    for (_, data) in &names_and_data {
        file.write_all(data)?;
    }

    println!("Created demo archive at {} with {} entries", path.display(), count);
    Ok(())
}

fn load_pack_index(path: &Path) -> std::io::Result<HashMap<String, Entry>> {
    let mut file = File::open(path)?;
    let mut magic = [0u8; 4];
    file.read_exact(&mut magic)?;
    if &magic != b"LPK1" {
        return Err(std::io::Error::new(
            std::io::ErrorKind::InvalidData,
            "invalid pack magic",
        ));
    }

    let count = read_u32(&mut file)? as usize;
    let mut map = HashMap::with_capacity(count);

    for _ in 0..count {
        let name_len = read_u16(&mut file)? as usize;
        let mut name_buf = vec![0u8; name_len];
        file.read_exact(&mut name_buf)?;
        let name = String::from_utf8(name_buf)
            .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e))?;
        let offset = read_u64(&mut file)?;
        let len = read_u64(&mut file)?;
        map.insert(name, Entry { offset, len });
    }

    println!("[PackReader] index loaded once ({} entries)", map.len());
    Ok(map)
}

fn normalize(path: &Path) -> String {
    path.to_string_lossy().replace('\\', "/")
}

fn write_u16(w: &mut File, v: u16) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}

fn write_u32(w: &mut File, v: u32) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}

fn write_u64(w: &mut File, v: u64) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}

fn read_u16(r: &mut File) -> std::io::Result<u16> {
    let mut b = [0u8; 2];
    r.read_exact(&mut b)?;
    Ok(u16::from_le_bytes(b))
