use std::time::Duration;

use tokio::sync::broadcast::{self, Sender};
use tokio_stream::{wrappers::BroadcastStream, Stream, StreamExt};

type Event = String;

#[derive(Debug)]
pub enum RecvError {
    Lagged(u64),
}

struct Inner {
    // Single owned Sender. Cloned EventSender handles do NOT clone this Sender.
    // That lets us drop it globally in one place.
    tx: Mutex<Option<Sender<Event>>>,
}

pub fn events_channel() -> (EventSender, EventStreamFactory, EventShutdown) {
    let (tx, _) = broadcast::channel(20);
    let inner = Arc::new(Inner {
        tx: Mutex::new(Some(tx)),
    });

    (
        EventSender {
            inner: inner.clone(),
        },
        EventStreamFactory {
            inner: inner.clone(),
        },
        EventShutdown { inner },
    )
}

#[derive(Clone)]
pub struct EventSender {
    inner: Arc<Inner>,
}

impl EventSender {
    pub fn send(&self, event: Event) {
        if let Some(tx) = self.inner.tx.lock().unwrap().as_ref() {
            let _ = tx.send(event);
        }
    }
}

#[derive(Clone)]
pub struct EventStreamFactory {
    inner: Arc<Inner>,
}

impl EventStreamFactory {
    pub fn all_events(&self) -> Option<impl Stream<Item = Result<Event, RecvError>> + Send> {
        let rx = self.inner.tx.lock().unwrap().as_ref()?.subscribe();

        Some(BroadcastStream::new(rx).filter_map(|event| match event {
            Ok(event) => Some(Ok(event)),
            Err(tokio_stream::wrappers::errors::BroadcastStreamRecvError::Lagged(n)) => {
                Some(Err(RecvError::Lagged(n)))
            }
        }))
    }
}

#[derive(Clone)]
pub struct EventShutdown {
    inner: Arc<Inner>,
}

impl EventShutdown {
    pub fn shutdown(&self) {
        // Dropping the only Sender closes the broadcast channel.
        let _ = self.inner.tx.lock().unwrap().take();
    }
}

#[tokio::main]
async fn main() {
    let (event_sender, stream_factory, shutdown) = events_channel();

    let producer = {
        let sender = event_sender.clone();
        tokio::spawn(async move {
            let mut n = 0u64;
            loop {
                n += 1;
                sender.send(format!("event-{n}"));
                tokio::time::sleep(Duration::from_millis(300)).await;
            }
        })
    };

    let mut stream = stream_factory
        .all_events()
        .expect("stream should exist before shutdown");

    let consumer = tokio::spawn(async move {
        while let Some(item) = stream.next().await {
            match item {
                Ok(event) => println!("[consumer] {event}"),
                Err(err) => println!("[consumer] recv error: {err:?}"),
            }
        }
        println!("[consumer] stream ended (channel closed)");
    });

    println!("Running. Press Ctrl+C to shutdown, or wait 5 seconds...");
    tokio::select! {
        _ = tokio::signal::ctrl_c() => {
            println!("Ctrl+C received");
        }
        _ = tokio::time::sleep(Duration::from_secs(5)) => {
            println!("Timer elapsed");
        }
    }

    shutdown.shutdown();
    println!("Global shutdown: sender dropped.");

    let _ = consumer.await;
    producer.abort();

    match stream_factory.all_events() {
        None => println!("New subscribers cannot be created after shutdown."),
        Some(_) => println!("Unexpected: channel still open."),
    }
}
"
}

