  "main.rs": "use serde::de::{self, Deserialize, Deserializer, MapAccess, Visitor};
use std::fmt;

#[derive(Debug, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug)]
enum B {
    Num(i64),
    Pair { name: String, value: i32 },
}

impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("an integer, or an object like {\"name\": ..., \"value\": ...}")
            }

            fn visit_i64<E>(self, v: i64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                Ok(B::Num(v))
            }

            fn visit_u64<E>(self, v: u64) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                let v = i64::try_from(v).map_err(|_| E::custom("u64 is too large for i64"))?;
                Ok(B::Num(v))
            }

            fn visit_map<M>(self, mut map: M) -> Result<Self::Value, M::Error>
            where
                M: MapAccess<'de>,
            {
                let mut name: Option<String> = None;
                let mut value: Option<i32> = None;

                while let Some(key) = map.next_key::<&str>()? {
                    match key {
                        "name" => {
                            if name.is_some() {
                                return Err(de::Error::duplicate_field("name"));
                            }
                            name = Some(map.next_value()?);
                        }
                        "value" => {
                            if value.is_some() {
                                return Err(de::Error::duplicate_field("value"));
                            }
                            value = Some(map.next_value()?);
                        }
                        _ => {
                            return Err(de::Error::unknown_field(key, &["name", "value"]));
                        }
                    }
                }

                let name = name.ok_or_else(|| de::Error::missing_field("name"))?;
                let value = value.ok_or_else(|| de::Error::missing_field("value"))?;
                Ok(B::Pair { name, value })
            }
        }

        // For JSON, deserialize_any lets B be either number or map.
        deserializer.deserialize_any(BVisitor)
    }
}

enum Field {
    X,
    B,
}

impl<'de> Deserialize<'de> for Field {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct FieldVisitor;

        impl<'de> Visitor<'de> for FieldVisitor {
            type Value = Field;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("`x` or `b`")
            }

            fn visit_str<E>(self, v: &str) -> Result<Self::Value, E>
            where
                E: de::Error,
            {
                match v {
                    "x" => Ok(Field::X),
                    "b" => Ok(Field::B),
                    _ => Err(de::Error::unknown_field(v, &["x", "b"])),
                }
            }
        }

        deserializer.deserialize_identifier(FieldVisitor)
    }
}

impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("struct A")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x: Option<usize> = None;
                let mut b: Option<Vec<B>> = None;

                while let Some(key) = map.next_key::<Field>()? {
                    match key {
                        Field::X => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        Field::B => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // This is the nested step: serde now deserializes Vec<B>,
                            // and each element uses B's custom Deserialize impl.
                            b = Some(map.next_value()?);
                        }
                    }
                }

                let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b.ok_or_else(|| de::Error::missing_field("b"))?;

                Ok(A { x, b })
            }
        }

        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    let input = r#"
