        .map(|item| match item {
            B::Num(n) => *n,
            B::Pair { name, value } => {
                let _ = name.len();
                i64::from(*value)
            }
        })
        .sum();
    println!("x = {}, derived sum from b = {}", parsed.x, sum_nums);
}
