        assert!(
            expected_len == store.len(),
            "store length ({}) must equal product of dims ({})",
            store.len(),
            expected_len
        );
        Self { store, dims }
    }

    fn linear_index(&self, idx: &[usize]) -> usize {
        assert_eq!(idx.len(), self.dims.len(), "index rank mismatch");
        let mut lin = 0usize;
        let mut stride = 1usize;
        for i in (0..self.dims.len()).rev() {
            assert!(idx[i] < self.dims[i], "index out of bounds at axis {}", i);
            lin += idx[i] * stride;
            stride *= self.dims[i];
        }
        lin
    }

    pub fn get(&self, idx: &[usize]) -> &T {
        let lin = self.linear_index(idx);
        &self.store[lin]
    }

    pub fn iter(&self) -> ArrayIter<'_, T> {
        let cart_indices = all_cartesian_indices(&self.dims);
        ArrayIter {
            array: self,
            cart_indices,
            pos: 0,
        }
    }

    pub fn iter_mut(&mut self) -> ArrayIterMut<'_, T> {
        // Full traversal => unique indices by construction.
        let cart_indices = all_cartesian_indices(&self.dims);
        let linear_indices: Vec<usize> = cart_indices
            .iter()
            .map(|c| {
                let mut lin = 0usize;
                let mut stride = 1usize;
                for i in (0..self.dims.len()).rev() {
                    lin += c[i] * stride;
                    stride *= self.dims[i];
                }
                lin
            })
            .collect();

        // Extra safety check (debug-time) that indices are unique.
        let mut seen = HashSet::new();
        debug_assert!(linear_indices.iter().all(|i| seen.insert(*i)));

        ArrayIterMut {
            ptr: self.store.as_mut_ptr(),
            cart_indices,
            linear_indices,
            pos: 0,
            _marker: PhantomData,
        }
    }
}

pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    cart_indices: Vec<Vec<usize>>,
    pos: usize,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = self.cart_indices.get(self.pos)?.clone();
        self.pos += 1;
        let value = self.array.get(&idx);
        Some((idx, value))
    }
}

pub struct ArrayIterMut<'a, T> {
    ptr: *mut T,
    cart_indices: Vec<Vec<usize>>,
    linear_indices: Vec<usize>,
    pos: usize,
    // Ties yielded &mut T to original borrow lifetime.
    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> Iterator for ArrayIterMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        let idx = self.cart_indices.get(self.pos)?.clone();
        let lin = self.linear_indices[self.pos];
        self.pos += 1;

        // SAFETY:
        // - `ptr` comes from a unique `&'a mut Vec<T>` borrow.
        // - `lin` is in-bounds.
        // - each `lin` is yielded at most once (unique indices), so no aliasing `&mut T`.
        let value = unsafe { &mut *self.ptr.add(lin) };
        Some((idx, value))
    }
}

fn all_cartesian_indices(dims: &[usize]) -> Vec<Vec<usize>> {
    if dims.is_empty() {
        return vec![vec![]];
    }
    if dims.iter().any(|&d| d == 0) {
        return vec![];
    }

    let n = dims.len();
    let mut idx = vec![0usize; n];
    let mut out = Vec::new();

    loop {
        out.push(idx.clone());

        // Odometer increment, last axis changes fastest.
        let mut carry = true;
        for axis in (0..n).rev() {
            if !carry {
                break;
            }
            idx[axis] += 1;
            if idx[axis] == dims[axis] {
                idx[axis] = 0;
                carry = true;
            } else {
                carry = false;
            }
        }

        if carry {
            break;
        }
    }

    out
}

fn main() {
    let mut a = Array::new(vec![2, 3], vec![1, 2, 3, 4, 5, 6]);

    println!("Immutable iteration:");
    for (idx, v) in a.iter() {
        println!("  {:?} -> {}", idx, v);
    }

    for (_idx, v) in a.iter_mut() {
        *v *= 10;
    }

    println!("\nAfter mutable iteration:");
    for (idx, v) in a.iter() {
        println!("  {:?} -> {}", idx, v);
    }
}
"
}

