    fn drop(&mut self) {
        unsafe {
            libc::munmap(self.ptr as *mut libc::c_void, self.len);
            libc::close(self.fd);
            if let Ok(cname) = CString::new(self.name.clone()) {
                libc::shm_unlink(cname.as_ptr());
            }
        }
    }
}

fn render_gradient_rgb24(buf: &mut [u8], width: usize, height: usize, t: f32) {
    let pi = std::f32::consts::PI;
    for y in 0..height {
        let fy = y as f32 / height as f32;
        for x in 0..width {
            let fx = x as f32 / width as f32;

            let r = ((fx * pi + t).sin() * 0.5 + 0.5) * 255.0;
            let g = ((fy * pi + t * 1.3).sin() * 0.5 + 0.5) * 255.0;
            let b = (((fx + fy) * pi + t * 0.7).sin() * 0.5 + 0.5) * 255.0;

            let i = (y * width + x) * 3;
            buf[i] = r as u8;
            buf[i + 1] = g as u8;
            buf[i + 2] = b as u8;
        }
    }
}

fn main() -> io::Result<()> {
    let (cols, rows) = termion::terminal_size().unwrap_or((80, 24));
    let (px_w, px_h) = termion::terminal_size_pixels().unwrap_or((cols * 8, rows * 16));

    let width = px_w as usize;
    let height = px_h as usize;
    let byte_len = width * height * 3;

    let unique = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_nanos();
    let shm_name = format!("/kitty-rs-shm-{}-{}", std::process::id(), unique);

    let mut shm = SharedMemory::create(shm_name.clone(), byte_len)?;
    let shm_name_b64 = STANDARD.encode(shm_name.as_bytes());

    let stdout = io::stdout();
    let mut out = stdout.lock();

    // Clear screen + home + hide cursor.
    write!(out, "\x1b[2J\x1b[H\x1b[?25l")?;
    out.flush()?;

    let mut t = 0.0f32;
    let frame_time = Duration::from_micros(16_666); // ~60 FPS

    // Press Ctrl+C to stop.
    loop {
        let frame_start = Instant::now();

        {
            let buf = shm.as_mut_slice();
            render_gradient_rgb24(buf, width, height, t);
        }

        // Kitty graphics via POSIX shared memory (t=s).
        // i=1 keeps reusing same image id.
        write!(
            out,
            "\x1b_Ga=T,t=s,i=1,f=24,s={},v={},S={},c={},r={},X=0,Y=0;{}\x1b\\",
            width, height, byte_len, cols, rows, shm_name_b64
        )?;
        out.flush()?;

        t += 0.05;

        let elapsed = frame_start.elapsed();
        if elapsed < frame_time {
            thread::sleep(frame_time - elapsed);
        }
    }
}
"
}

