  "main.rs": "use rustyline::error::ReadlineError;
use rustyline::{
    Cmd, ConditionalEventHandler, DefaultEditor, Event, EventContext, EventHandler, KeyCode,
    KeyEvent, Modifiers, RepeatCount,
};

/// When '.' or ',' is typed, remove whitespace immediately before cursor,
/// then insert the typed punctuation, with cursor ending up *after* punctuation.
///
/// This uses `Cmd::Macro(...)` to simulate multiple actions in one key binding:
/// repeated backspace(s) + typed punctuation.
struct TrimWsThenInsertPunct {
    punct: char,
}

impl TrimWsThenInsertPunct {
    fn new(punct: char) -> Self {
        Self { punct }
    }
}

impl ConditionalEventHandler for TrimWsThenInsertPunct {
    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        ctx: &EventContext,
    ) -> Option<Cmd> {
        let pos = ctx.pos();
        let line = ctx.line();
        let before = &line[..pos];

        let ws_count = before
            .chars()
            .rev()
            .take_while(|c| c.is_whitespace())
            .count();

        if ws_count == 0 {
            // No whitespace before cursor => use default behavior for '.' / ','
            return None;
        }

        // Ctrl-H (\x08) is backspace in readline macros.
        let mut macro_keys = String::new();
        macro_keys.push_str(&"\x08".repeat(ws_count));
        macro_keys.push(self.punct);

        Some(Cmd::Macro(macro_keys))
