  "main.rs": "use chrono::{DateTime, NaiveDateTime, Utc};

fn parse_lancedb_datetime(input: &str) -> Result<DateTime<Utc>, String> {
    // Some DB layers return values with surrounding quotes; remove them.
    let s = input.trim().trim_matches('"');

    // 1) If a timezone is present (e.g. "Z" or "+00:00"), parse as RFC3339.
    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // 2) LanceDB-like naive timestamps (no timezone), with optional fractional seconds.
    //    Example: "2025-08-02T17:35:41.409" or "1970-01-01T00:00:00"
    let naive_formats = [
        "%Y-%m-%dT%H:%M:%S%.f", // optional fraction if present (e.g. .409)
        "%Y-%m-%dT%H:%M:%S",    // no fraction
    ];

    for fmt in naive_formats {
        if let Ok(naive) = NaiveDateTime::parse_from_str(s, fmt) {
            // Interpret naive datetime as UTC
            return Ok(DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc));
        }
    }

    Err(format!("Could not parse date: {s}"))
}

fn date_string_to_unix_seconds(d: &str) -> Result<i64, String> {
    parse_lancedb_datetime(d).map(|dt| dt.timestamp())
}

fn date_string_to_unix_millis(d: &str) -> Result<i64, String> {
    parse_lancedb_datetime(d).map(|dt| dt.timestamp_millis())
}

fn main() {
    let samples = [
        "\"1970-01-01T00:00:00\"",
        "\"2025-08-02T17:35:41.409\"",
        "\"2025-08-04T01:48:44.017\"",
        "\"2025-08-04T23:02:20.584\"",
        "\"2025-08-05T00:08:57.350\"",
        "\"2025-08-10T18:31:26.628\"",
        // Also works if timezone appears:
        "2025-08-10T18:31:26.628Z",
    ];

    for s in samples {
        println!("Input: {s}");
        match parse_lancedb_datetime(s) {
            Ok(dt) => {
                println!("  chrono::DateTime<Utc>: {dt}");
                println!("  unix seconds: {}", date_string_to_unix_seconds(s).unwrap());
                println!("  unix millis:  {}", date_string_to_unix_millis(s).unwrap());
            }
            Err(e) => {
                println!("  parse error: {e}");
            }
