        while let Some(task) = { tasks.borrow_mut().pop_front() } {
            match task {
                FeedbackTask::ToS(v) => s2.next(v),
                FeedbackTask::ToR(v) => r2.next(v),
            }
        }
    });

    (q1, q2, pump)
