    loop {
        let url = build_list_url(cfg, &prefix, marker.as_deref())?;
        let resp = client
            .get(url)
            .send()
            .await
            .with_context(|| format!("list request failed for prefix '{prefix}'"))?;

        let status = resp.status();
        let body = resp
            .text()
            .await
            .with_context(|| format!("failed reading list response body for prefix '{prefix}'"))?;

        if !status.is_success() {
            return Err(anyhow!(
                "list blobs failed for prefix '{}' with {}: {}",
                prefix,
                status,
                body
            ));
        }

        let parsed: EnumerationResults = from_str(&body)
            .with_context(|| format!("failed parsing list XML for prefix '{prefix}'"))?;

        if let Some(blobs) = parsed.blobs {
            out.extend(
                blobs
                    .blob
                    .into_iter()
                    .map(|b| b.name)
                    .filter(|name| name.ends_with(".json")),
