}

#[derive(Subcommand, Debug)]
enum NodeAction {
    /// Create a node
    Create {
        /// Node name
        name: String,
    },
    /// Get a node
    Get {
        /// Node name
        name: String,
    },
    /// Treat unknown first token as a node name, then parse node-specific actions
    #[command(external_subcommand)]
    NamedNode(Vec<String>),
}

#[derive(Parser, Debug)]
#[command(
    name = "<NAME>",
    no_binary_name = true,
    about = "Actions on a specific node"
)]
struct NodeEntityCommand {
    #[command(subcommand)]
    action: NodeEntityAction,
}

#[derive(Subcommand, Debug)]
