            }
            NodeAction::Get { name } => {
                println!("get node: {name}");
            }
            NodeAction::NamedNode(tokens) => {
                handle_named_node(tokens);
            }
        },
    }
}

fn handle_named_node(tokens: Vec<String>) {
    if tokens.is_empty() {
        eprintln!("error: missing node name");
        std::process::exit(2);
    }

    let node_name = &tokens[0];
    let rest = &tokens[1..];

    if rest.is_empty() {
        eprintln!("error: missing action for node '{node_name}'\n");
        print_node_entity_help(node_name);
        std::process::exit(2);
