quote = "1"
prettyplease = "0.2"
",
  "main.rs": "use std::{env, fs};

use quote::ToTokens;
use syn::{
    parse_file, parse_str, File, Item, ItemUse, UseGroup, UsePath, UseRename, UseTree,
};

#[derive(Debug, Clone)]
enum ImportKind {
    Name,
    Glob,
    Rename(String), // alias
}

#[derive(Debug, Clone)]
struct FlatImport {
    segments: Vec<String>,
    kind: ImportKind,
}

fn main() {
    // If a file path is provided, rewrite that file's contents and print to stdout.
    // Otherwise, run on an embedded demo snippet.
    let input = if let Some(path) = env::args().nth(1) {
        fs::read_to_string(path).expect("failed to read input file")
    } else {
        r#"
use vexide::{devices::smart::*, prelude::*};
use vexide::devices::*;
use vexide::devices::smart::Motor;
use vexide::{devices, fs};
use vexide::devices;
use vexide::devices::{smart, adi};
use {vexide::{devices, fs}, core::borrow};

fn main() {}
"#
        .to_string()
    };

    let file = parse_file(&input).expect("failed to parse Rust source");
    let rewritten = rewrite_file(file);
    let out = prettyplease::unparse(&rewritten);
    println!("{}", out);
}

fn rewrite_file(file: File) -> File {
    let mut new_items = Vec::new();

    for item in file.items {
        match item {
            Item::Use(orig_use) => {
                let flat = flatten_use_tree(&orig_use.tree);
                let rewritten: Vec<FlatImport> = flat.into_iter().map(rewrite_import).collect();

                for (idx, imp) in rewritten.into_iter().enumerate() {
                    let mut new_use = clone_use_shell(&orig_use);
                    if idx > 0 {
                        // Avoid duplicating attributes/comments if one use expands to many uses.
                        new_use.attrs.clear();
                    }
                    let tree_src = imp.to_use_tree_src();
                    new_use.tree = parse_str::<UseTree>(&tree_src)
                        .unwrap_or_else(|_| panic!("failed to parse generated tree: {tree_src}"));
                    new_items.push(Item::Use(new_use));
                }
            }
            other => new_items.push(other),
        }
    }

    File { items: new_items, ..file }
}

fn clone_use_shell(orig: &ItemUse) -> ItemUse {
    ItemUse {
        attrs: orig.attrs.clone(),
        vis: orig.vis.clone(),
        use_token: orig.use_token,
        leading_colon: orig.leading_colon,
        tree: orig.tree.clone(),
        semi_token: orig.semi_token,
    }
}

fn flatten_use_tree(tree: &UseTree) -> Vec<FlatImport> {
    let mut out = Vec::new();
    flatten_rec(tree, &mut Vec::new(), &mut out);
    out
}

fn flatten_rec(tree: &UseTree, prefix: &mut Vec<String>, out: &mut Vec<FlatImport>) {
    match tree {
        UseTree::Path(UsePath { ident, tree, .. }) => {
            prefix.push(ident.to_string());
            flatten_rec(tree, prefix, out);
            prefix.pop();
        }
        UseTree::Name(name) => {
            let mut segs = prefix.clone();
            segs.push(name.ident.to_string());
            out.push(FlatImport {
                segments: segs,
                kind: ImportKind::Name,
            });
        }
        UseTree::Rename(UseRename { ident, rename, .. }) => {
            let mut segs = prefix.clone();
            segs.push(ident.to_string());
            out.push(FlatImport {
                segments: segs,
                kind: ImportKind::Rename(rename.to_string()),
            });
        }
        UseTree::Glob(_) => {
            out.push(FlatImport {
                segments: prefix.clone(),
                kind: ImportKind::Glob,
            });
        }
        UseTree::Group(UseGroup { items, .. }) => {
            for item in items {
                flatten_rec(item, prefix, out);
            }
        }
    }
}

fn rewrite_import(mut imp: FlatImport) -> FlatImport {
    // Flatten vexide::devices::X -> vexide::X
    if imp.segments.len() >= 2 && imp.segments[0] == "vexide" && imp.segments[1] == "devices" {
        imp.segments.remove(1);
    }
    imp
}

impl FlatImport {
    fn to_use_tree_src(&self) -> String {
        let path = self.segments.join("::");
        match &self.kind {
            ImportKind::Name => path,
            ImportKind::Glob => {
                if path.is_empty() {
                    "*".to_string()
                } else {
                    format!("{path}::*")
                }
            }
            ImportKind::Rename(alias) => format!("{path} as {alias}"),
        }
    }
}
"
}

