  "Cargo.toml": "[package]
name = "tokio-manual-poll-once"
version = "0.1.0"
edition = "2021"

[dependencies]
tokio = { version = "1", features = ["macros", "rt-multi-thread", "time"] }
",
  "main.rs": "use std::future::{poll_fn, Future};
use std::pin::Pin;
use std::task::{Context, Poll};
use tokio::time::{sleep, Duration};

#[derive(Debug)]
enum TryPollResult<T> {
    Ready(T),
    Pending,
}

// Non-async function that polls exactly once.
fn try_poll<F>(future: Pin<&mut F>, cx: &mut Context<'_>) -> TryPollResult<F::Output>
where
    F: Future,
{
    match future.poll(cx) {
        Poll::Ready(v) => TryPollResult::Ready(v),
        Poll::Pending => TryPollResult::Pending,
    }
}

async fn use_or_spawn<F, T>(future: F, label: &'static str)
where
    F: Future<Output = T> + Send + 'static,
    T: std::fmt::Debug + Send + 'static,
{
    let mut future = Box::pin(future);

    // Build a proper Context/Waker from the current async task, then poll once.
    let first_poll = poll_fn(|cx| Poll::Ready(try_poll(future.as_mut(), cx))).await;

    match first_poll {
        TryPollResult::Ready(value) => {
            println!("[{label}] ready immediately: {value:?}");
            // Do synchronous handling here.
        }
        TryPollResult::Pending => {
            println!("[{label}] pending; spawning a task to await it...");
            tokio::spawn(async move {
                let value = future.await;
                println!("[{label}] completed in spawned task: {value:?}");
            });
        }
    }
}

async fn immediate_future() -> i32 {
    7
}

async fn delayed_future() -> i32 {
    sleep(Duration::from_millis(300)).await;
    42
}

#[tokio::main]
async fn main() {
    use_or_spawn(immediate_future(), "immediate").await;
    use_or_spawn(delayed_future(), "delayed").await;

    // Give spawned task time to finish before process exits.
    sleep(Duration::from_millis(500)).await;
}
"
}

