  "main.rs": "use syslog::{Facility, Formatter3164};

#[derive(Clone, Copy, Debug)]
enum LogLevel {
    Info,
    Warning,
    Error,
}

fn log_message(
    logger: &mut syslog::Logger<syslog::LoggerBackend, Formatter3164>,
    level: LogLevel,
    msg: impl AsRef<str>,
) {
    let msg = msg.as_ref();

    let result = match level {
        LogLevel::Info => logger.info(msg),
        LogLevel::Warning => logger.warning(msg),
        LogLevel::Error => logger.err(msg),
    };

    if let Err(e) = result {
        eprintln!("Failed to log: {e}");
    }
}

macro_rules! logf {
    ($logger:expr, $level:expr, $($arg:tt)*) => {{
        log_message(
            $logger,
            $level,
            format!("[{}:{}] {}", file!(), line!(), format!($($arg)*)),
        )
    }};
}

fn main() {
    let formatter = Formatter3164 {
        facility: Facility::LOG_USER,
        hostname: None,
        process: "syslog_test".into(),
        pid: 0,
    };

    let mut logger = syslog::unix(formatter).expect("Could not connect to syslog");

    let sum1 = 2 + 3;
    logf!(&mut logger, LogLevel::Info, "Sum 1: 2 + 3 = {}", sum1);

    let sum2 = 10 - 4;
    logf!(&mut logger, LogLevel::Warning, "Sum 2: 10 - 4 = {}", sum2);

    let sum3 = 6 * 7;
    logf!(&mut logger, LogLevel::Error, "Sum 3: 6 * 7 = {}", sum3);
}
"
