        .expect("failed to listen for Ctrl+C");

    println!("Ctrl+C received: starting graceful shutdown");

    // 1) Stop queue worker.
    shutdown_token.cancel();

    // 2) Stop HTTP server gracefully (wait=true).
    server_handle.stop(true).await;

    // 3) Await both tasks so no background tasks remain.
    if let Err(join_err) = queue_task.await {
        eprintln!("Queue task join error: {join_err}");
    }

    match server_task.await {
        Ok(inner) => inner?,
        Err(join_err) => {
            return Err(io::Error::new(
                io::ErrorKind::Other,
