{
  "Cargo.toml": "[package]
name = "axum-ws-origin-check"
version = "0.1.0"
edition = "2021"

[dependencies]
axum = { version = "0.7", features = ["ws"] }
tokio = { version = "1", features = ["full"] }
tower-http = { version = "0.5", features = ["cors"] }
futures-util = "0.3"
",
  "main.rs": "use axum::{
    extract::{
        ws::{Message, WebSocket},
        Path, WebSocketUpgrade,
    },
    http::{header, Method, Request, StatusCode},
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use futures_util::{sink::SinkExt, stream::StreamExt};
use tower_http::cors::CorsLayer;

const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    let app = Router::new()
        .route("/", get(|| async { "OK" }))
        .route("/client/:session_id", get(client_handler))
        // Apply websocket origin filtering at the router level for this route.
        .route_layer(middleware::from_fn(check_ws_origin))
        // Regular HTTP CORS config (doesn't protect websocket upgrades by itself).
        .layer(
            CorsLayer::new()
                .allow_origin(ALLOWED_ORIGIN.parse().unwrap())
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([header::CONTENT_TYPE]),
        );

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .expect("bind failed");

    println!("listening on http://127.0.0.1:3000");
    axum::serve(listener, app).await.expect("server error");
}

async fn check_ws_origin(req: Request<axum::body::Body>, next: Next) -> Response {
    let is_websocket_upgrade = req
        .headers()
        .get(header::UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);

    if is_websocket_upgrade {
        let allowed = req
            .headers()
            .get(header::ORIGIN)
            .and_then(|v| v.to_str().ok())
            .map(|origin| origin == ALLOWED_ORIGIN)
            .unwrap_or(false);

        if !allowed {
            return (
                StatusCode::FORBIDDEN,
                format!("websocket origin denied; only {ALLOWED_ORIGIN} is allowed"),
            )
                .into_response();
        }
    }

    next.run(req).await
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    let _ = socket
        .send(Message::Text(
            format!("connected to session {session_id}").into(),
        ))
        .await;

    while let Some(Ok(msg)) = socket.next().await {
        match msg {
            Message::Text(text) => {
                let _ = socket
                    .send(Message::Text(format!("echo: {text}").into()))
                    .await;
            }
            Message::Binary(bin) => {
                let _ = socket.send(Message::Binary(bin)).await;
            }
            Message::Ping(v) => {
                let _ = socket.send(Message::Pong(v)).await;
            }
            Message::Close(_) => break,
            Message::Pong(_) => {}
        }
    }
}
"
}

