  "main.rs": "use std::{sync::Arc, time::Duration};

use async_trait::async_trait;
use opentelemetry::trace::TracerProvider as _;
use opentelemetry_sdk::trace::SdkTracerProvider;
use tokio::time::sleep;
use tracing::{info, info_span, Instrument, Span};
use tracing_subscriber::{fmt::format::FmtSpan, layer::SubscriberExt, util::SubscriberInitExt, EnvFilter};

#[derive(Clone)]
struct RequestCtx {
    request_id: u64,
    // Store the parent span in request context.
    request_span: Span,
}

#[async_trait]
trait Lifecycle: Send + Sync {
    async fn stage_1(&self, ctx: Arc<RequestCtx>);
    async fn stage_2(&self, ctx: Arc<RequestCtx>);
    async fn upstream(&self, ctx: Arc<RequestCtx>);
}

struct DemoProxy;

#[async_trait]
impl Lifecycle for DemoProxy {
    async fn stage_1(&self, ctx: Arc<RequestCtx>) {
        // Rehydrate parent span for this callback/future.
        async move {
            let stage_span = info_span!("stage_1", request_id = ctx.request_id);
            async move {
                info!("processing stage 1");
                sleep(Duration::from_millis(120)).await;
            }
            .instrument(stage_span)
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }

    async fn stage_2(&self, ctx: Arc<RequestCtx>) {
        async move {
            let stage_span = info_span!("stage_2", request_id = ctx.request_id);
            async move {
                info!("processing stage 2");
                sleep(Duration::from_millis(80)).await;
            }
            .instrument(stage_span)
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }

    async fn upstream(&self, ctx: Arc<RequestCtx>) {
        async move {
            let stage_span = info_span!("upstream", request_id = ctx.request_id);
            async move {
                info!("calling upstream");
                sleep(Duration::from_millis(150)).await;
                info!("upstream complete");
            }
            .instrument(stage_span)
            .await;
        }
        .instrument(ctx.request_span.clone())
        .await;
    }
}

async fn fake_pingora_scheduler(proxy: Arc<dyn Lifecycle>, ctx: Arc<RequestCtx>) {
    // Simulate framework invoking callbacks on arbitrary tasks/timing.
    let p1 = {
        let proxy = Arc::clone(&proxy);
        let ctx = Arc::clone(&ctx);
        tokio::spawn(async move {
            sleep(Duration::from_millis(10)).await;
            proxy.stage_1(ctx).await;
        })
    };

    let p2 = {
        let proxy = Arc::clone(&proxy);
        let ctx = Arc::clone(&ctx);
        tokio::spawn(async move {
            sleep(Duration::from_millis(30)).await;
            proxy.stage_2(ctx).await;
        })
    };

    let p3 = {
        let proxy = Arc::clone(&proxy);
        let ctx = Arc::clone(&ctx);
        tokio::spawn(async move {
            sleep(Duration::from_millis(60)).await;
            proxy.upstream(ctx).await;
        })
    };

    let _ = tokio::join!(p1, p2, p3);
}

fn init_tracing() -> SdkTracerProvider {
    let provider = SdkTracerProvider::builder().build();
    let tracer = provider.tracer("pingora-demo");

    let otel_layer = tracing_opentelemetry::layer().with_tracer(tracer);

    tracing_subscriber::registry()
        .with(EnvFilter::new("info"))
        .with(
            tracing_subscriber::fmt::layer()
                .with_target(false)
                .with_thread_ids(true)
                .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE),
        )
        .with(otel_layer)
        .init();

    provider
}

#[tokio::main(flavor = "multi_thread", worker_threads = 4)]
async fn main() {
    let provider = init_tracing();

    let proxy: Arc<dyn Lifecycle> = Arc::new(DemoProxy);

    // Simulate two concurrent requests.
    let mut joins = Vec::new();
    for request_id in 1..=2 {
        let proxy = Arc::clone(&proxy);
        let request_span = info_span!("request", request_id);

        let ctx = Arc::new(RequestCtx {
            request_id,
            request_span: request_span.clone(),
        });

        joins.push(tokio::spawn(
            async move {
                info!("request accepted");
                fake_pingora_scheduler(proxy, ctx).await;
                info!("request finished");
            }
            .instrument(request_span),
        ));
    }

    for j in joins {
        let _ = j.await;
    }

    // Flush OTEL provider.
    let _ = provider.shutdown();
}
"
}

