#[derive(Debug, Sequence)]
struct SignedDataLoose<'a> {
    version: u8,
    // Keep these as raw ASN.1 so we don't fail on strict cert/profile checks.
    digest_algorithms: AnyRef<'a>,
    encap_content_info: EncapContentInfo<'a>,
    #[asn1(context_specific = "0", tag_mode = "IMPLICIT", optional = "true")]
    certificates: Option<AnyRef<'a>>,
    #[asn1(context_specific = "1", tag_mode = "IMPLICIT", optional = "true")]
    crls: Option<AnyRef<'a>>,
    signer_infos: AnyRef<'a>,
}

fn main() -> Result<()> {
    let path = env::args().nth(1).unwrap_or_else(|| "ci.der".to_string());
