    if ci.content_type != ID_SIGNED_DATA {
        println!("warning: outer contentType is not signedData");
    }

    // This is what often fails on SCEP payloads with strict RFC validation.
    match SignedData::from_der(ci.content.value()) {
        Ok(_) => println!("strict cms::SignedData decode: OK"),
        Err(e) => println!("strict cms::SignedData decode failed: {e}"),
    }

    // Loose decode: parse SignedData structure but keep problematic fields as raw ASN.1.
    let sd = SignedDataLoose::from_der(ci.content.value())
        .context("failed to decode inner SignedData (loose parser)")?;

    println!("signedData.version: {}", sd.version);
