use std::thread;
use std::time::Duration;

use crossterm::event::{self, Event, KeyCode};
use crossterm::terminal;
use signal_hook::consts::signal::{SIGINT, SIGTERM};
use signal_hook::iterator::Signals;

#[derive(Debug)]
enum Message {
    Key(char),
    Signal(i32),
    Tick,
    QuitRequested(&'static str),
}

fn spawn_key_thread(
    tx: mpsc::Sender<Message>,
    shutdown: Arc<AtomicBool>,
) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        if let Err(e) = terminal::enable_raw_mode() {
            eprintln!("failed to enable raw mode: {e}");
            return;
        }

        // Poll with timeout so we can periodically check shutdown flag.
        while !shutdown.load(Ordering::Relaxed) {
            match event::poll(Duration::from_millis(200)) {
                Ok(true) => match event::read() {
                    Ok(Event::Key(k)) => {
                        if let KeyCode::Char(c) = k.code {
                            if tx.send(Message::Key(c)).is_err() {
                                break;
                            }
                            if c == 'q' {
                                let _ = tx.send(Message::QuitRequested("keyboard"));
                            }
                        }
                    }
                    Ok(_) => {}
                    Err(e) => {
                        eprintln!("keyboard read error: {e}");
                        break;
                    }
                },
                Ok(false) => {}
                Err(e) => {
                    eprintln!("keyboard poll error: {e}");
                    break;
                }
            }
        }

        let _ = terminal::disable_raw_mode();
    })
}

fn spawn_signal_thread(
    tx: mpsc::Sender<Message>,
) -> Result<(thread::JoinHandle<()>, signal_hook::iterator::Handle), Box<dyn std::error::Error>> {
    let mut signals = Signals::new([SIGINT, SIGTERM])?;
    let handle = signals.handle();

    let join = thread::spawn(move || {
        for sig in signals.forever() {
            if tx.send(Message::Signal(sig)).is_err() {
                break;
            }
            let _ = tx.send(Message::QuitRequested("signal"));
        }
    });

    Ok((join, handle))
}

fn spawn_tick_thread(
    tx: mpsc::Sender<Message>,
    shutdown: Arc<AtomicBool>,
) -> thread::JoinHandle<()> {
    thread::spawn(move || {
        while !shutdown.load(Ordering::Relaxed) {
            thread::sleep(Duration::from_secs(1));
            if tx.send(Message::Tick).is_err() {
                break;
            }
        }
    })
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Press keys (q to quit) or send SIGINT/SIGTERM (Ctrl+C).\n");

    let (tx, rx) = mpsc::channel::<Message>();
    let shutdown = Arc::new(AtomicBool::new(false));

    let key_thread = spawn_key_thread(tx.clone(), shutdown.clone());
    let tick_thread = spawn_tick_thread(tx.clone(), shutdown.clone());
    let (signal_thread, signal_handle) = spawn_signal_thread(tx.clone())?;

    // Main event loop
    while let Ok(msg) = rx.recv() {
        match msg {
            Message::Key(c) => println!("key: {c}"),
            Message::Signal(sig) => println!("signal: {sig}"),
            Message::Tick => println!("tick"),
            Message::QuitRequested(from) => {
                println!("quit requested from: {from}");
                break;
            }
        }
    }

    // Graceful shutdown
    shutdown.store(true, Ordering::Relaxed);
    signal_handle.close(); // unblocks `signals.forever()` immediately
    drop(tx); // allow recv/send loops to finish

    let _ = key_thread.join();
    let _ = tick_thread.join();
    let _ = signal_thread.join();

    println!("All threads stopped cleanly.");
    Ok(())
}
"
}

