impl ChannelCounter {
    fn new() -> Self {
        Self {
            channel_index: AtomicUsize::new(0),
        }
    }

    /// Replacement for `fetch_add(1, Ordering::Relaxed)`.
    ///
    /// Why Relaxed here?
    /// - Original operation requested `Relaxed`, i.e. atomic RMW with no extra
    ///   acquire/release synchronization.
