    ///   sequence; keeping `Relaxed` preserves the original memory-order intent.
    ///
    /// Important: use `wrapping_add` to match atomic `fetch_add` overflow behavior.
    fn fetch_add_relaxed_via_cs(&self) -> usize {
        critical_section::with(|_| {
            let old = self.channel_index.load(Ordering::Relaxed);
            self.channel_index
                .store(old.wrapping_add(1), Ordering::Relaxed);
            old
        })
    }

    fn load_relaxed(&self) -> usize {
        self.channel_index.load(Ordering::Relaxed)
    }
}

