use std::time::{SystemTime, UNIX_EPOCH};

// This Python code is packaged directly into the Rust binary.
// That means `cargo install rust-program` installs everything needed on the Rust side.
const EMBEDDED_PYTHON_SCRIPT: &str = r#"import sys

print('Hello from embedded script.py')
print('Python executable:', sys.executable)
print('Received args:', sys.argv[1:])
"#;

#[derive(Debug, Clone)]
struct PythonInterpreter {
    program: String,
    pre_args: Vec<String>,
}

fn main() -> Result<(), Box<dyn Error>> {
    let interpreter = find_python_interpreter().ok_or_else(|| {
        "Could not find a Python interpreter. Tried PYTHON env var, python3, python, and py -3."
    })?;

    let script_path = write_embedded_script_to_temp_file()?;

    // Forward CLI args after the Rust binary name to Python script.
    let forwarded_args: Vec<String> = env::args().skip(1).collect();

    let run_result = run_python_script(&interpreter, &script_path, &forwarded_args);

    // Best-effort cleanup.
    let _ = fs::remove_file(&script_path);

    let status = run_result?;
    if !status.success() {
        return Err(format!("Python exited with non-zero status: {status}").into());
    }

    Ok(())
}

fn write_embedded_script_to_temp_file() -> Result<PathBuf, Box<dyn Error>> {
    let mut path = env::temp_dir();
    let nanos = SystemTime::now().duration_since(UNIX_EPOCH)?.as_nanos();
    path.push(format!(
        "rust_program_embedded_{}_{}.py",
        process::id(),
        nanos
    ));

    fs::write(&path, EMBEDDED_PYTHON_SCRIPT)?;
    Ok(path)
}

fn run_python_script(
    interpreter: &PythonInterpreter,
    script_path: &Path,
    script_args: &[String],
) -> Result<ExitStatus, Box<dyn Error>> {
    let mut cmd = Command::new(&interpreter.program);
    cmd.args(&interpreter.pre_args);
    cmd.arg(script_path);
    cmd.args(script_args);

    // Inherit stdio so user sees script output directly.
    let status = cmd.status()?;
    Ok(status)
}

fn find_python_interpreter() -> Option<PythonInterpreter> {
    if let Ok(py) = env::var("PYTHON") {
        let candidate = PythonInterpreter {
            program: py,
            pre_args: vec![],
        };
        if interpreter_works(&candidate) {
            return Some(candidate);
        }
    }

    let candidates = vec![
        PythonInterpreter {
            program: "python3".to_string(),
            pre_args: vec![],
        },
        PythonInterpreter {
            program: "python".to_string(),
            pre_args: vec![],
        },
        // Windows Python launcher fallback
        PythonInterpreter {
            program: "py".to_string(),
            pre_args: vec!["-3".to_string()],
        },
    ];

    candidates.into_iter().find(|c| interpreter_works(c))
}

fn interpreter_works(candidate: &PythonInterpreter) -> bool {
    let mut cmd = Command::new(&candidate.program);
    cmd.args(&candidate.pre_args)
        .arg("--version")
        .stdout(Stdio::null())
        .stderr(Stdio::null());

    cmd.status().is_ok()
}
"
}

