    cam_q: Query<&Transform, (With<Camera3d>, Without<Block>)>,
) {
    let block_tf = block_q.single();
    let cam_tf = cam_q.single();

    // Simulated "hit normal": pick the cube face most toward the camera.
    let to_cam = (cam_tf.translation - block_tf.translation).normalize();
    let face_normals = [
        block_tf.rotation * Vec3::X,
        block_tf.rotation * -Vec3::X,
        block_tf.rotation * Vec3::Y,
        block_tf.rotation * -Vec3::Y,
        block_tf.rotation * Vec3::Z,
        block_tf.rotation * -Vec3::Z,
