    // Convert hit normal into block local space so we know which cube face was hit.
    let local_normal = (block_rot.inverse() * world_normal).normalize();

    // Local rotation that maps rect's +Z to the face normal.
    let local_face_rot = local_face_rotation_from_normal(local_normal);

    // Compose: world = block * local
    block_rot * local_face_rot
}

fn local_face_rotation_from_normal(local_normal: Vec3) -> Quat {
    let x = local_normal.x.abs();
    let y = local_normal.y.abs();
    let z = local_normal.z.abs();

    if x >= y && x >= z {
        if local_normal.x >= 0.0 {
