        } else {
            Quat::from_rotation_y(FRAC_PI_2) // -X
        }
    } else if y >= x && y >= z {
        if local_normal.y >= 0.0 {
            Quat::from_rotation_x(-FRAC_PI_2) // +Y
        } else {
            Quat::from_rotation_x(FRAC_PI_2) // -Y
        }
    } else if local_normal.z >= 0.0 {
        Quat::IDENTITY // +Z
    } else {
        Quat::from_rotation_y(PI) // -Z
    }
}
