const PIXELS_PER_SIDE: usize = 8;
const PIXELS_PER_LINE: usize = PIXELS_PER_SIDE;
const BYTES_PER_PIXEL: usize = 4;

/// Fast version: swaps 4-byte pixels via unaligned u32 loads/stores.
/// Works on x86_64 and aarch64.
fn flip_line(line_bytes: &mut [u8]) {
    debug_assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0);

    let pixels = line_bytes.len() / BYTES_PER_PIXEL;
    let mut i = 0;

    while i < pixels / 2 {
        let left = i * BYTES_PER_PIXEL;
        let right = (pixels - 1 - i) * BYTES_PER_PIXEL;

        unsafe {
            let lptr = line_bytes.as_mut_ptr().add(left) as *mut u32;
            let rptr = line_bytes.as_mut_ptr().add(right) as *mut u32;

            let l = ptr::read_unaligned(lptr);
            let r = ptr::read_unaligned(rptr);
            ptr::write_unaligned(lptr, r);
            ptr::write_unaligned(rptr, l);
