  "main.rs": "use expectrl::spawn;
use std::io::{self, Read, Write};
use std::os::fd::AsRawFd;
use std::sync::mpsc::{self, TryRecvError};
use std::thread;
use std::time::Duration;

fn set_nonblocking<T: AsRawFd>(io_obj: &T) -> io::Result<()> {
    let fd = io_obj.as_raw_fd();
    unsafe {
        let flags = libc::fcntl(fd, libc::F_GETFL);
        if flags < 0 {
            return Err(io::Error::last_os_error());
        }

        if libc::fcntl(fd, libc::F_SETFL, flags | libc::O_NONBLOCK) < 0 {
            return Err(io::Error::last_os_error());
        }
    }
    Ok(())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    println!("Starting child shell in PTY (expectrl)...");
    println!("Type commands and press Enter. Ctrl+D to quit this demo.\n");

    // You can replace "bash" with your real CLI agent command.
    let mut session = spawn("bash")?;

    // Key part: make PTY non-blocking so one owner thread can interleave
    // reads + writes without blocking forever on read().
    set_nonblocking(&session)?;

    let (to_pty_tx, to_pty_rx) = mpsc::channel::<Vec<u8>>();
    let (from_pty_tx, from_pty_rx) = mpsc::channel::<Vec<u8>>();

    // Single owner thread for Session (no Arc<Mutex<Session>>).
    // This avoids the deadlock/freeze pattern where read holds a mutex.
    let io_thread = thread::spawn(move || {
        let mut buf = [0u8; 4096];

        loop {
            // 1) Drain pending input from UI/channel and write to PTY.
            loop {
                match to_pty_rx.try_recv() {
                    Ok(data) => {
                        if let Err(e) = session.write_all(&data) {
                            let _ = from_pty_tx.send(format!("\r\n[write error: {e}]\r\n").into_bytes());
                            return;
                        }
                        let _ = session.flush();
                    }
                    Err(TryRecvError::Empty) => break,
                    Err(TryRecvError::Disconnected) => return,
                }
            }

            // 2) Non-blocking read from PTY.
            match session.read(&mut buf) {
                Ok(0) => {
                    let _ = from_pty_tx.send(b"\r\n[child exited]\r\n".to_vec());
                    return;
                }
                Ok(n) => {
                    let _ = from_pty_tx.send(buf[..n].to_vec());
                }
                Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
                    // No output right now; continue.
                }
                Err(e) => {
                    let _ = from_pty_tx.send(format!("\r\n[read error: {e}]\r\n").into_bytes());
                    return;
                }
            }

            thread::sleep(Duration::from_millis(10));
        }
    });

    // Printer thread: PTY output -> local stdout
    let printer = thread::spawn(move || {
        let mut stdout = io::stdout();
        while let Ok(chunk) = from_pty_rx.recv() {
            if stdout.write_all(&chunk).is_err() {
                break;
            }
            let _ = stdout.flush();
        }
    });

    // stdin -> PTY input channel
    let stdin = io::stdin();
    let mut input = stdin.lock();
    let mut one = [0u8; 1];

    loop {
        match input.read(&mut one) {
            Ok(0) => break, // EOF (Ctrl+D in terminal)
            Ok(_) => {
                if to_pty_tx.send(vec![one[0]]).is_err() {
                    break;
                }
            }
            Err(e) => {
                eprintln!("stdin read error: {e}");
                break;
            }
        }
    }

    drop(to_pty_tx);
    let _ = io_thread.join();
    let _ = printer.join();

    Ok(())
}
"
