            (0..n).into_par_iter().for_each(|i| {
                for j in (i + 1)..n {
                    if elems[i].criterion(&elems[j]) < cutoff {
                        nbs[i].lock().unwrap().push(j);
                        nbs[j].lock().unwrap().push(i);
                    }
                }
            });

            nbs
        };

        // Write back results.
        for (elem, m) in self.elems.iter_mut().zip(nbs) {
            let mut nb = m.into_inner().unwrap();
            nb.sort_unstable();
            elem.nb = nb;
        }
    }
}

fn main() {
