        [0.0, 0.0, 0.0],
        [0.5, 0.0, 0.0],
        [2.0, 0.0, 0.0],
        [0.0, 0.5, 0.0],
        [0.4, 0.4, 0.0],
    ];

    // criterion is squared distance, so cutoff=1.0 means distance < 1.0
    let mut a_seq = A::new(1.0, positions.clone());
    let mut a_par = A::new(1.0, positions);

    a_seq.build_lists_pairwise_safe();
    a_par.build_lists_pairwise_parallel();

    for e in &mut a_seq.elems {
        e.nb.sort_unstable();
    }

    for i in 0..a_seq.get_nelems() {
        assert_eq!(a_seq.elems[i].nb, a_par.elems[i].nb);
    }

    println!("Sequential neighbor lists:");
    for (i, e) in a_seq.elems.iter().enumerate() {
        println!("  {i}: {:?}", e.nb);
    }

    println!("\nParallel neighbor lists:");
    for (i, e) in a_par.elems.iter().enumerate() {
        println!("  {i}: {:?}", e.nb);
    }

    // Read v and f so they are not considered dead code in this demo.
    let _sum_lengths: usize = a_seq
        .elems
        .iter()
        .map(|e| e.v.len() + e.f.len())
        .sum();
}
