  "main.rs": "use std::io::{self, Read};

fn tokenize_shell_like(input: &str) -> Result<Vec<String>, String> {
    let mut tokens = Vec::new();
    let mut current = String::new();

    let mut in_single = false;
    let mut in_double = false;
    let mut token_started = false;

    let mut chars = input.chars().peekable();

    while let Some(ch) = chars.next() {
        match ch {
            // Whitespace only splits tokens when outside quotes.
            ' ' | '\t' | '\n' if !in_single && !in_double => {
                if token_started {
                    tokens.push(std::mem::take(&mut current));
                    token_started = false;
                }
            }

            // Single quote starts/ends single-quoted mode (unless inside double quotes).
            '\'' if !in_double => {
                in_single = !in_single;
                token_started = true; // important for handling empty quoted strings: ''
            }

            // Double quote starts/ends double-quoted mode (unless inside single quotes).
            '"' if !in_single => {
                in_double = !in_double;
                token_started = true;
            }

            // Backslash escaping (simple, practical version).
            '\\' if !in_single => {
                if let Some(next) = chars.next() {
                    current.push(next);
                    token_started = true;
                } else {
                    return Err("dangling escape at end of input".to_string());
                }
            }

            _ => {
                current.push(ch);
                token_started = true;
            }
        }
    }

    if in_single {
        return Err("unterminated single quote".to_string());
    }
    if in_double {
        return Err("unterminated double quote".to_string());
    }

    if token_started {
        tokens.push(current);
    }

    Ok(tokens)
}

fn main() {
    // Read raw input from stdin so quote characters are preserved.
    let mut input = String::new();
    io::stdin().read_to_string(&mut input).unwrap();

    // Fallback demo input if nothing was provided on stdin.
    if input.trim().is_empty() {
        input = " one  ' two  'three    four\n".to_string();
    }

    let line = input.trim_end_matches(['\n', '\r']);

    match tokenize_shell_like(line) {
        Ok(tokens) => {
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("tokenization error: {e}");
