#[derive(Asset, TypePath, Debug)]
struct WadText {
    text: String,
}

#[derive(Default)]
struct WadTextLoader;

impl AssetLoader for WadTextLoader {
    type Asset = WadText;
    type Settings = ();
    type Error = anyhow::Error;

    fn load<'a>(
        &'a self,
        reader: &'a mut Reader,
        _settings: &'a Self::Settings,
        _load_context: &'a mut LoadContext,
    ) -> BoxedFuture<'a, Result<Self::Asset, Self::Error>> {
        Box::pin(async move {
            // This is tiny and cheap: only a locator file is read by Bevy.
            let mut locator_bytes = Vec::new();
            reader.read_to_end(&mut locator_bytes).await?;
            let locator_text = std::str::from_utf8(&locator_bytes)?;

            let (pack_rel, entry_name) = parse_locator(locator_text)?;

            // With default AssetPlugin settings, assets live at ./assets
            let asset_root = std::env::current_dir()?.join("assets");
            let pack_path = asset_root.join(pack_rel);

            // Lazy read: open one archive file, read index, seek one entry only.
            let text = read_text_entry_from_pack(&pack_path, &entry_name)?;

            Ok(WadText { text })
        })
    }

    fn extensions(&self) -> &[&str] {
        &["wadentry"]
    }
}

#[derive(Resource)]
struct Pending {
    handles: Vec<Handle<WadText>>,
    seen: Vec<bool>,
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>) {
    let h1: Handle<WadText> = asset_server.load("locators/brick.wadentry");
    let h2: Handle<WadText> = asset_server.load("locators/metal.wadentry");

    commands.insert_resource(Pending {
        handles: vec![h1, h2],
        seen: vec![false, false],
    });

    println!("Requested 2 lazy assets from one packed file...");
}

fn poll_loaded_assets(mut pending: ResMut<Pending>, assets: Res<Assets<WadText>>) {
    for (i, handle) in pending.handles.iter().enumerate() {
        if !pending.seen[i] {
            if let Some(asset) = assets.get(handle) {
                pending.seen[i] = true;
                println!("Loaded: {}", asset.text);
            }
        }
    }

    if pending.seen.iter().all(|v| *v) {
        println!("All lazy assets loaded. Exiting.");
        std::process::exit(0);
    }
}

fn parse_locator(s: &str) -> Result<(String, String)> {
    let mut pack: Option<String> = None;
    let mut entry: Option<String> = None;

    for line in s.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') {
            continue;
        }
        if let Some((k, v)) = line.split_once('=') {
            match k.trim() {
                "pack" => pack = Some(v.trim().to_string()),
                "entry" => entry = Some(v.trim().to_string()),
                _ => {}
            }
        }
    }

    let pack = pack.context("locator missing `pack=...`")?;
    let entry = entry.context("locator missing `entry=...`")?;
    Ok((pack, entry))
}

fn create_demo_assets() -> Result<()> {
    let asset_root = std::env::current_dir()?.join("assets");
    let packs_dir = asset_root.join("packs");
    let locators_dir = asset_root.join("locators");

    fs::create_dir_all(&packs_dir)?;
    fs::create_dir_all(&locators_dir)?;

    let pack_path = packs_dir.join("textures.lpk");
    write_pack(
