            ("metal", "METAL texture bytes (pretend binary image data)"),
            ("grass", "GRASS texture bytes (pretend binary image data)"),
        ],
    )?;

    fs::write(
        locators_dir.join("brick.wadentry"),
        "pack=packs/textures.lpk\nentry=brick\n",
    )?;
    fs::write(
        locators_dir.join("metal.wadentry"),
        "pack=packs/textures.lpk\nentry=metal\n",
    )?;

    Ok(())
