/// Very small custom archive format for demo:
/// [magic:4="LPK0"][count:u32]
/// Repeated count times:
///   [name_len:u16][name bytes][offset:u64][size:u64]
/// Then raw entry bytes concatenated.
fn write_pack(path: &Path, entries: &[(&str, &str)]) -> Result<()> {
    let mut file = File::create(path)?;

    let index_size: u64 = entries
        .iter()
        .map(|(name, _)| 2u64 + name.len() as u64 + 8 + 8)
        .sum();

    let mut offset = 4u64 + 4u64 + index_size;

    let mut meta = Vec::with_capacity(entries.len());
    for (name, data) in entries {
        let bytes = data.as_bytes().to_vec();
        let size = bytes.len() as u64;
        meta.push(((*name).to_string(), offset, size, bytes));
        offset += size;
    }

    file.write_all(b"LPK0")?;
    write_u32(&mut file, entries.len() as u32)?;

    for (name, off, size, _) in &meta {
        let name_bytes = name.as_bytes();
        write_u16(&mut file, name_bytes.len() as u16)?;
        file.write_all(name_bytes)?;
        write_u64(&mut file, *off)?;
        write_u64(&mut file, *size)?;
    }

    for (_, _, _, data) in meta {
        file.write_all(&data)?;
    }

    Ok(())
}

fn read_text_entry_from_pack(path: &Path, wanted: &str) -> Result<String> {
    let mut file = File::open(path).with_context(|| format!("open pack {:?}", path))?;

    let mut magic = [0u8; 4];
    file.read_exact(&mut magic)?;
    if &magic != b"LPK0" {
        bail!("invalid pack magic in {:?}", path);
    }

    let count = read_u32(&mut file)?;
    let mut found: Option<(u64, u64)> = None;

    for _ in 0..count {
        let name_len = read_u16(&mut file)? as usize;
        let mut name_bytes = vec![0u8; name_len];
        file.read_exact(&mut name_bytes)?;
        let name = String::from_utf8(name_bytes)?;

        let offset = read_u64(&mut file)?;
        let size = read_u64(&mut file)?;

        if name == wanted {
            found = Some((offset, size));
        }
    }

    let (offset, size) = found.with_context(|| format!("entry '{}' not found", wanted))?;

    file.seek(SeekFrom::Start(offset))?;
    let mut buf = vec![0u8; size as usize];
    file.read_exact(&mut buf)?;

    Ok(String::from_utf8(buf)?)
}

