            let guard = self.inner.tx.lock().expect("mutex poisoned");
            guard.as_ref().map(|tx| tx.subscribe())
        };

        match rx_opt {
            Some(rx) => Box::pin(
                BroadcastStream::new(rx).map(|item| item.map_err(|_| RecvError::Lagged)),
            ),
            None => Box::pin(tokio_stream::empty()),
        }
    }
}

async fn producer(name: &'static str, sender: EventSender) {
    let mut seq = 0u64;
    let mut interval = tokio::time::interval(Duration::from_millis(300));

    loop {
        interval.tick().await;
        seq += 1;

        let event = Event { source: name, seq };
        if sender.send(event).is_err() {
            println!("producer {name}: channel closed, exiting");
            break;
        }
    }
}

async fn consumer(factory: EventStreamFactory) {
    let mut stream = factory.all_events();

    while let Some(item) = stream.next().await {
        match item {
            Ok(event) => println!("consumer got event: {:?}", event),
            Err(RecvError::Lagged) => println!("consumer lagged"),
        }
    }

    println!("consumer: stream ended (all senders dropped)");
}

