fn resolve_ref(reference: &str, base_file: &Path) -> Result<Value, Box<dyn Error>> {
    let (doc_part, fragment_part) = reference.split_once('#').unwrap_or((reference, ""));

    let target_file = if doc_part.is_empty() {
        base_file.to_path_buf()
    } else {
        base_file
            .parent()
            .unwrap_or_else(|| Path::new("."))
            .join(doc_part)
    };

    let doc_text = fs::read_to_string(&target_file)?;
    let doc_json: Value = serde_json::from_str(&doc_text)?;

    if fragment_part.is_empty() {
        return Ok(doc_json);
    }

    let pointer = if fragment_part.starts_with('/') {
        fragment_part
    } else {
        return Err(format!(
            "Unsupported fragment in $ref: #{fragment_part}. Expected JSON pointer like #/p_list"
        )
        .into());
    };

    doc_json
        .pointer(pointer)
        .cloned()
        .ok_or_else(|| format!("JSON pointer not found: {pointer} in {}", target_file.display()).into())
}

fn ensure_demo_files() -> Result<(), Box<dyn Error>> {
    if !Path::new("a.json").exists() {
        fs::write(
            "a.json",
            r#"{
    "p_list": [
        "./a/b/c/def",
        "./g/h/i/jkl"
    ]
}
"#,
        )?;
    }

    if !Path::new("b.json").exists() {
        fs::write(
            "b.json",
            r#"{
    "path_list": {
        "$ref": "./a.json#/p_list"
    }
}
"#,
        )?;
    }

    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
    ensure_demo_files()?;

    let b_path = PathBuf::from("b.json");
    let json_data = fs::read_to_string(&b_path)?;

    let raw: RawA = serde_json::from_str(&json_data)?;
    let a_obj = raw.resolve(&b_path)?;

    for p in &a_obj.path_list {
        println!("{}", p.display());
    }

    Ok(())
}
"
}

