#[derive(Debug, Default)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug)]
enum B {
    Num(i64),
    Text(String),
}

// -------------------------
// Custom Deserialize for A
// -------------------------
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        const FIELDS: &[&str] = &["x", "b"];
        deserializer.deserialize_struct("A", FIELDS, AVisitor)
    }
}

struct AVisitor;

impl<'de> Visitor<'de> for AVisitor {
    type Value = A;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("struct A")
    }

    fn visit_map<M>(self, mut map: M) -> Result<A, M::Error>
    where
        M: MapAccess<'de>,
    {
        let mut x: Option<usize> = None;
        let mut b: Option<Vec<B>> = None;

        while let Some(key) = map.next_key::<AField>()? {
            match key {
                AField::X => {
                    if x.is_some() {
                        return Err(de::Error::duplicate_field("x"));
                    }
                    x = Some(map.next_value()?);
                }
                AField::B => {
                    if b.is_some() {
                        return Err(de::Error::duplicate_field("b"));
                    }
                    // This is the important nested step:
                    // serde will deserialize Vec<B> and call B's custom deserializer for each item.
                    b = Some(map.next_value::<Vec<B>>()?);
                }
            }
        }

        let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
        let b = b.ok_or_else(|| de::Error::missing_field("b"))?;

        Ok(A { x, b })
    }
}

enum AField {
    X,
    B,
}

impl<'de> Deserialize<'de> for AField {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        struct FieldVisitor;

        impl<'de> Visitor<'de> for FieldVisitor {
            type Value = AField;

            fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
                f.write_str("`x` or `b`")
            }

            fn visit_str<E>(self, value: &str) -> Result<AField, E>
            where
                E: de::Error,
            {
                match value {
                    "x" => Ok(AField::X),
                    "b" => Ok(AField::B),
                    _ => Err(de::Error::unknown_field(value, &["x", "b"])),
                }
            }
        }

        deserializer.deserialize_identifier(FieldVisitor)
    }
}

