// Custom Deserialize for B
// JSON representation examples:
// {"type":"num","n":123}
// {"type":"text","s":"hello"}
// -------------------------
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        const FIELDS: &[&str] = &["type", "n", "s"];
        deserializer.deserialize_struct("B", FIELDS, BVisitor)
    }
}

struct BVisitor;

impl<'de> Visitor<'de> for BVisitor {
    type Value = B;

    fn expecting(&self, f: &mut fmt::Formatter) -> fmt::Result {
        f.write_str("enum B as an object")
    }

    fn visit_map<M>(self, mut map: M) -> Result<B, M::Error>
    where
        M: MapAccess<'de>,
    {
        let mut kind: Option<String> = None;
        let mut n: Option<i64> = None;
        let mut s: Option<String> = None;

        while let Some(key) = map.next_key::<BField>()? {
            match key {
                BField::Type => {
                    if kind.is_some() {
                        return Err(de::Error::duplicate_field("type"));
                    }
                    kind = Some(map.next_value()?);
                }
                BField::N => {
                    if n.is_some() {
                        return Err(de::Error::duplicate_field("n"));
                    }
                    n = Some(map.next_value()?);
                }
                BField::S => {
                    if s.is_some() {
                        return Err(de::Error::duplicate_field("s"));
                    }
                    s = Some(map.next_value()?);
                }
            }
        }

        match kind.as_deref() {
            Some("num") => {
                let n = n.ok_or_else(|| de::Error::missing_field("n"))?;
                Ok(B::Num(n))
            }
            Some("text") => {
                let s = s.ok_or_else(|| de::Error::missing_field("s"))?;
                Ok(B::Text(s))
            }
            Some(other) => Err(de::Error::unknown_variant(other, &["num", "text"])),
            None => Err(de::Error::missing_field("type")),
        }
    }
}

enum BField {
    Type,
    N,
    S,
}

impl<'de> Deserialize<'de> for BField {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
