use std::io::{self, Write};
use std::ptr;
use std::slice;
use std::thread;
use std::time::{Duration, Instant};
use termion::terminal_size_pixels;

struct ShmBuffer {
    name: CString,
    fd: i32,
    ptr: *mut u8,
    len: usize,
}

impl ShmBuffer {
    fn new(name: &str, len: usize) -> io::Result<Self> {
        let cname = CString::new(name).map_err(|_| io::Error::new(io::ErrorKind::InvalidInput, "invalid shm name"))?;

        let fd = unsafe { libc::shm_open(cname.as_ptr(), libc::O_CREAT | libc::O_RDWR, 0o600) };
        if fd < 0 {
            return Err(io::Error::last_os_error());
        }

        let tr = unsafe { libc::ftruncate(fd, len as libc::off_t) };
        if tr != 0 {
            unsafe { libc::close(fd) };
            return Err(io::Error::last_os_error());
        }

        let mapped = unsafe {
            libc::mmap(
                ptr::null_mut(),
                len,
                libc::PROT_READ | libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            )
        };

        if mapped == libc::MAP_FAILED {
            unsafe { libc::close(fd) };
            return Err(io::Error::last_os_error());
        }

        Ok(Self {
            name: cname,
            fd,
            ptr: mapped as *mut u8,
            len,
        })
    }

    fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { slice::from_raw_parts_mut(self.ptr, self.len) }
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        unsafe {
            libc::munmap(self.ptr as *mut libc::c_void, self.len);
            libc::close(self.fd);
            libc::shm_unlink(self.name.as_ptr());
        }
    }
}

fn main() -> io::Result<()> {
    let mut out = io::stdout().lock();

    // Get terminal pixel size; fallback if unavailable.
    let (w, h) = terminal_size_pixels().unwrap_or((1280, 720));
    let width = w as usize;
    let height = h as usize;
    let frame_bytes = width * height * 3; // RGB24

    // POSIX shm names must start with '/'
    let shm_name = format!("/kitty_anim_{}", std::process::id());
    let mut shm = ShmBuffer::new(&shm_name, frame_bytes)?;

    // Kitty expects the payload base64-encoded (even for t=s), but it's tiny (just the shm name).
    let shm_name_b64 = STANDARD.encode(shm_name.as_bytes());

    // Cosmetic terminal setup
    write!(out, "\x1b[?25l\x1b[2J\x1b[H")?;
    out.flush()?;

    let target_dt = Duration::from_nanos((1_000_000_000f64 / 60.0) as u64);
    let start = Instant::now();

    loop {
        let frame_start = Instant::now();
        let t = start.elapsed().as_secs_f32();

        // Render directly into shared memory
        let buf = shm.as_mut_slice();
        for y in 0..height {
            let fy = y as f32 / height as f32;
            for x in 0..width {
                let fx = x as f32 / width as f32;
                let idx = (y * width + x) * 3;

                let r = ((fx * std::f32::consts::PI + t).sin() * 0.5 + 0.5) * 255.0;
                let g = ((fy * std::f32::consts::PI + t * 1.3).sin() * 0.5 + 0.5) * 255.0;
                let b = (((fx + fy) * std::f32::consts::PI + t * 0.7).sin() * 0.5 + 0.5) * 255.0;

                buf[idx] = r as u8;
