            "\x1b[H\x1b_Ga=T,i=1,q=2,t=s,f=24,s={},v={},S={};{}\x1b\\",
            width, height, frame_bytes, shm_name_b64
        )?;
        out.flush()?;

        let elapsed = frame_start.elapsed();
        if elapsed < target_dt {
            thread::sleep(target_dt - elapsed);
        }
    }
