    type Input: Copy;
    type Output;

    fn prepare(&amp;mut self, rate: f64);
    fn process(&amp;mut self, input: Self::Input) -&gt; Self::Output;
}


pub trait Sample: Copy + Clone + Add&lt;Self, Output = Self&gt; {
    type Float: Float;

    const CHANNELS: usize;

    fn mono(&amp;self) -&gt; Self::Float;

    fn gain(&amp;self, db: Self::Float) -&gt; Self;
}

#[derive(Copy, Clone)]
pub struct Node&lt;P&gt;(pub P);

impl&lt;In: Copy, Out, P&gt; Processor for Node&lt;P&gt;
where
    P: Processor&lt;Input = In, Output = Out&gt;,
{
    type Input = In;

    type Output = Out;

    fn prepare(&amp;mut self, rate: f64) {
        todo!()
    }

    fn process(&amp;mut self, input: Self::Input) -&gt; Self::Output {
        self.0.process(input)
    }
}

pub struct Gain&lt;S: Sample&gt;(pub S::Float);

impl&lt;S: Sample&gt; Processor for Gain&lt;S&gt; {
    type Input = S::Float;
    type Output = S::Float;

    fn prepare(&amp;mut self, rate: f64) {
        todo!()
    }

    fn process(&amp;mut self, input: Self::Input) -&gt; Self::Output {
        self.0 * input
    }
}

pub fn gain_node&lt;S: Sample&gt;(db: S::Float) -&gt; Node&lt;Gain&lt;S&gt;&gt; {
    Node(Gain(db))
}

impl Sample for f32 {
    type Float = Self;

    const CHANNELS: usize = 1;

    fn mono(&amp;self) -&gt; Self::Float {
        todo!()
    }

    fn gain(&amp;self, db: Self::Float) -&gt; Self {
        todo!()
    }
}

#[cfg(test)]
mod tests {
    #[test]
    fn process_f32_test() {

        let mut node = Node(Gain(32f32)); // ERROR -&gt; cannot infer type of the type parameter `S`
        node.process(32.34);
    }
}

</code></pre>
<p>This code results in the following error in the test module:</p>
<pre><code>error[E0283]: type annotations needed
   --&gt; src/lib.rs:291:29
    |
291 |         let mut node = Node(Gain(32f32));
    |                             ^^^^ cannot infer type of the type parameter `S` declared on the struct `Gain`
    |
    = note: cannot satisfy `_: Sample`
    = help: the trait `Sample` is implemented for `f32`
note: required by a bound in `Gain`
   --&gt; src/lib.rs:230:20
    |
230 | pub struct Gain&lt;S: Sample&gt;(pub S::Float);
    |                    ^^^^^^ required by this bound in `Gain`
help: consider specifying the generic argument
    |
291 |         let mut node = Node(Gain::&lt;S&gt;(32f32));
    |                                 +++++

</code></pre>
<p>How can I modify the trait definitions or implementations so that the compiler will infer this type for me?</p>


