{
  "Cargo.toml": "[package]
name = "custom-gp-operator-demo"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "use std::fmt;
use std::sync::Arc;

#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash)]
enum NodeType {
    Vertex,
    Leaf,
}

type EvalFn = Arc<dyn Fn(&[f64], &[f64]) -> f64 + Send + Sync>;

#[derive(Clone)]
struct Op {
    name: String,
    arity: usize,
    eval: EvalFn,
}

impl fmt::Debug for Op {
    fn fmt(&self, f: &mut fmt::Formatter<'_>) -> fmt::Result {
        f.debug_struct("Op")
            .field("name", &self.name)
            .field("arity", &self.arity)
            .finish()
    }
}

impl Op {
    fn new(name: impl Into<String>, arity: usize, eval: EvalFn) -> Self {
        Self {
            name: name.into(),
            arity,
            eval,
        }
    }

    fn add() -> Self {
        Self::new("add", 2, Arc::new(|_, args| args[0] + args[1]))
    }

    fn sub() -> Self {
        Self::new("sub", 2, Arc::new(|_, args| args[0] - args[1]))
    }

    fn mul() -> Self {
        Self::new("mul", 2, Arc::new(|_, args| args[0] * args[1]))
    }

    fn pow() -> Self {
        Self::new("pow", 2, Arc::new(|_, args| args[0].powf(args[1])))
    }

    fn var(index: usize) -> Self {
        Self::new(
            format!("var({index})"),
            0,
            Arc::new(move |vars, _| vars.get(index).copied().unwrap_or(0.0)),
        )
    }

    /// This is how you define a custom operator:
    /// arity = number of children this node expects.
    fn custom(
        name: impl Into<String>,
        arity: usize,
        f: impl Fn(&[f64]) -> f64 + Send + Sync + 'static,
    ) -> Self {
        Self::new(name, arity, Arc::new(move |_, args| f(args)))
    }
}

#[derive(Debug, Clone)]
struct Node {
    op: Op,
    children: Vec<Node>,
}

impl Node {
    fn leaf(op: Op) -> Self {
        Self {
            op,
            children: vec![],
        }
    }

    fn vertex(op: Op, children: Vec<Node>) -> Self {
        assert_eq!(
            op.arity,
            children.len(),
            "operator '{}' expects {} children, got {}",
            op.name,
            op.arity,
            children.len()
        );
        Self { op, children }
    }

    fn eval(&self, vars: &[f64]) -> f64 {
        let child_vals: Vec<f64> = self.children.iter().map(|c| c.eval(vars)).collect();
        (self.op.eval)(vars, &child_vals)
    }

    fn to_expr(&self) -> String {
        if self.children.is_empty() {
            return self.op.name.clone();
        }
        let args = self
            .children
            .iter()
            .map(|c| c.to_expr())
            .collect::<Vec<_>>()
            .join(", ");
        format!("{}({})", self.op.name, args)
    }
}

fn main() {
    // Custom operator equivalent to: sqrtplusone(x) = sqrt(x) + 1
    let sqrtplusone = Op::custom("sqrtplusone", 1, |args| args[0].sqrt() + 1.0);

    // Same style as your snippet:
    let store = vec![
        (
            NodeType::Vertex,
            vec![Op::add(), Op::sub(), Op::mul(), Op::pow(), sqrtplusone.clone()],
        ),
        (NodeType::Leaf, vec![Op::var(0)]),
    ];

    println!("Operator store:");
    for (kind, ops) in &store {
        println!("  {:?}: {:?}", kind, ops.iter().map(|o| &o.name).collect::<Vec<_>>());
    }

    // Build tree: sqrtplusone(add(var(0), var(0)))
    let x1 = Node::leaf(Op::var(0));
    let x2 = Node::leaf(Op::var(0));
    let add_xx = Node::vertex(Op::add(), vec![x1, x2]);
    let tree = Node::vertex(sqrtplusone, vec![add_xx]);

    let input = [9.0_f64];
    let y = tree.eval(&input);

    println!("\nTree expression: {}", tree.to_expr());
    println!("Input x = {}", input[0]);
    println!("Output = {}", y);
}
"
}

