        for (&c, &d) in cart.iter().rev().zip(self.dims.iter().rev()) {
            assert!(c < d, "index out of bounds: {c} >= {d}");
            idx += c * stride;
            stride *= d;
        }

        idx
    }

    pub fn get(&self, cart: &[usize]) -> &T {
        let i = self.linear_index(cart);
        &self.store[i]
    }

    pub fn get_mut(&mut self, cart: &[usize]) -> &mut T {
        let i = self.linear_index(cart);
        &mut self.store[i]
    }

    pub fn iter_indices<'a>(&'a self, cartesian_indices: Vec<Vec<usize>>) -> ArrayIter<'a, T> {
        ArrayIter {
            array: self,
            cartesian_indices,
            pos: 0,
        }
    }

    pub fn iter_indices_mut<'a>(
        &'a mut self,
        cartesian_indices: Vec<Vec<usize>>,
    ) -> ArrayIterMut<'a, T> {
        ArrayIterMut::new(self, cartesian_indices)
    }
}

pub struct ArrayIter<'a, T> {
    array: &'a Array<T>,
    cartesian_indices: Vec<Vec<usize>>,
    pos: usize,
}

impl<'a, T> Iterator for ArrayIter<'a, T> {
    type Item = (Vec<usize>, &'a T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.pos >= self.cartesian_indices.len() {
            return None;
        }

        let cart = self.cartesian_indices[self.pos].clone();
        self.pos += 1;
        let value = self.array.get(&cart);
        Some((cart, value))
    }
}

pub struct ArrayIterMut<'a, T> {
    ptr: *mut T,
    len: usize,
    cartesian_indices: Vec<Vec<usize>>,
    linear_indices: Vec<usize>,
    pos: usize,
    _marker: PhantomData<&'a mut T>,
}

impl<'a, T> ArrayIterMut<'a, T> {
    fn new(array: &'a mut Array<T>, cartesian_indices: Vec<Vec<usize>>) -> Self {
        let len = array.store.len();

        let mut linear_indices = Vec::with_capacity(cartesian_indices.len());
        let mut seen = HashSet::with_capacity(cartesian_indices.len());

        for cart in &cartesian_indices {
            let lin = array.linear_index(cart);
            assert!(
                seen.insert(lin),
                "duplicate index in mutable iteration: {:?} (linear {})",
                cart,
                lin
            );
            linear_indices.push(lin);
        }

        Self {
            ptr: array.store.as_mut_ptr(),
            len,
            cartesian_indices,
            linear_indices,
            pos: 0,
            _marker: PhantomData,
        }
    }
}

impl<'a, T> Iterator for ArrayIterMut<'a, T> {
    type Item = (Vec<usize>, &'a mut T);

    fn next(&mut self) -> Option<Self::Item> {
        if self.pos >= self.linear_indices.len() {
            return None;
        }

        let lin = self.linear_indices[self.pos];
        let cart = self.cartesian_indices[self.pos].clone();
        self.pos += 1;

        debug_assert!(lin < self.len);

        // SAFETY:
        // - `ptr` comes from a live `&'a mut Array<T>` allocation.
        // - `linear_indices` were bounds-checked in `new`.
        // - duplicates are rejected in `new`, so each yielded `&'a mut T`
        //   points to a distinct element, avoiding aliasing.
        unsafe { Some((cart, &mut *self.ptr.add(lin))) }
    }
}

fn all_indices(dims: &[usize]) -> Vec<Vec<usize>> {
    if dims.is_empty() {
        return vec![vec![]];
    }

    let total = dims.iter().product::<usize>();
    let n = dims.len();

    let mut out = Vec::with_capacity(total);
    let mut cur = vec![0usize; n];

    for _ in 0..total {
        out.push(cur.clone());

        for ax in (0..n).rev() {
            cur[ax] += 1;
            if cur[ax] < dims[ax] {
                break;
            }
            cur[ax] = 0;
        }
    }

    out
}

fn main() {
    let dims = vec![2, 3];
    let data = (0..6).collect::<Vec<i32>>();
    let mut a = Array::from_vec(dims.clone(), data);

    println!("Before:");
    for (idx, v) in a.iter_indices(all_indices(&dims)) {
        println!("{:?} = {}", idx, v);
    }

    let picks = vec![vec![0, 1], vec![1, 2], vec![0, 0]];
    for (_idx, v) in a.iter_indices_mut(picks) {
        *v *= 10;
    }

    println!("\nAfter mutating three positions:");
    for (idx, v) in a.iter_indices(all_indices(&dims)) {
        println!("{:?} = {}", idx, v);
    }
}
"
}

