    fn fmt(&self, f: &mut Formatter<'_>) -> std::fmt::Result {
        write!(f, "{}", self.0)
    }
}

impl std::error::Error for UnavailableDataError {}

#[derive(Clone)]
struct CustomServiceClient {
    url: String,
    client: Client,
}

impl CustomServiceClient {
    fn new(url: String) -> Self {
        Self {
            url,
            client: Client::new(),
        }
    }

    async fn get_additional_data(&self, date_str: String) -> Result<Data, UnavailableDataError> {
        let resp = self
            .client
            .get(&self.url)
            .header("date", date_str)
            .send()
            .await
            .map_err(|e| UnavailableDataError(format!("request failed: {e}")))?;

        if !resp.status().is_success() {
            return Err(UnavailableDataError(format!(
                "upstream returned status {}",
                resp.status()
            )));
        }

        resp.json::<Data>()
            .await
            .map_err(|e| UnavailableDataError(format!("invalid json: {e}")))
    }
}

#[derive(Debug, Serialize)]
struct AuthorizedHttpRequest {
    path: String,
    date_header: String,
    additional: Data,
}

impl FromRequest for AuthorizedHttpRequest {
    type Error = Error;
    type Future = LocalBoxFuture<'static, Result<Self, Self::Error>>;

    fn from_request(req: &HttpRequest, _: &mut Payload) -> Self::Future {
        // IMPORTANT: convert borrowed request data into owned values BEFORE async move.
        let path = req.path().to_owned();
        let date_header = req
            .headers()
            .get(header::DATE)
            .and_then(|h| h.to_str().ok())
            .map(str::to_owned);
        let service_url = req
            .app_data::<web::Data<AppConfig>>()
            .map(|cfg| cfg.additional_url.clone());

        Box::pin(async move {
            let date = date_header.ok_or_else(|| ErrorBadRequest("missing/invalid Date header"))?;
            let url = service_url.ok_or_else(|| ErrorInternalServerError("missing app config"))?;

            let client = CustomServiceClient::new(url);
