  "main.rs": "use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};

use futures::task::noop_waker_ref;
use tokio::task::JoinHandle;
use tokio::time::{sleep, Duration};

enum TryPollResult<T> {
    Ready(T),
    Pending,
}

fn try_poll<F>(future: Pin<&mut F>) -> TryPollResult<F::Output>
where
    F: Future,
{
    // We only do a single optimistic poll here.
    // If it's pending, we will later await/spawn the future, which registers
    // a real runtime waker on a subsequent poll.
    let waker = noop_waker_ref();
    let mut cx = Context::from_waker(waker);

    match future.poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

// Non-async function called from async context.
fn use_now_or_spawn<F>(mut fut: Pin<Box<F>>, label: &'static str) -> Option<JoinHandle<()>>
where
    F: Future<Output = String> + Send + 'static,
{
    match try_poll(fut.as_mut()) {
        TryPollResult::Ready(value) => {
            println!("[{label}] ready immediately: {value}");
            None
        }
        TryPollResult::Pending => {
            println!("[{label}] not ready, spawning task...");
            Some(tokio::spawn(async move {
                let value = fut.await;
                println!("[{label}] completed in spawned task: {value}");
            }))
        }
    }
}

#[tokio::main]
async fn main() {
    // Completes immediately on first poll.
    let immediate = Box::pin(async { "immediate result".to_string() });

    // Yields (sleep) so first poll returns Pending.
    let delayed = Box::pin(async {
        sleep(Duration::from_millis(300)).await;
        "delayed result".to_string()
    });

    let h1 = use_now_or_spawn(immediate, "immediate");
    let h2 = use_now_or_spawn(delayed, "delayed");

    if let Some(handle) = h1 {
        handle.await.unwrap();
    }
    if let Some(handle) = h2 {
        handle.await.unwrap();
    }
}
"
