  "main.rs": "use chrono::{DateTime, NaiveDateTime, Utc};

fn parse_lancedb_datetime(input: &str) -> Result<DateTime<Utc>, String> {
    // Handle accidental surrounding quotes/spaces.
    let s = input.trim().trim_matches('"');

    // If the string already has timezone info (e.g. Z / +00:00), parse as RFC3339.
    if let Ok(dt) = DateTime::parse_from_rfc3339(s) {
        return Ok(dt.with_timezone(&Utc));
    }

    // Lance-like strings without timezone. We treat them as UTC.
    // Supports both:
    //   2025-08-02T17:35:41.409
    //   1970-01-01T00:00:00
    let naive_formats = [
        "%Y-%m-%dT%H:%M:%S%.f", // with optional fractional seconds in many cases
        "%Y-%m-%dT%H:%M:%S",    // no fractional seconds
    ];

    for fmt in naive_formats {
        if let Ok(naive) = NaiveDateTime::parse_from_str(s, fmt) {
            return Ok(DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc));
        }
    }

    Err(format!("Could not parse datetime: {s}"))
}

fn date_string_to_unix_millis(input: &str) -> Result<i64, String> {
    Ok(parse_lancedb_datetime(input)?.timestamp_millis())
}

