            Ok(dt) => {
                let millis = dt.timestamp_millis();
                let seconds = dt.timestamp();
                println!("Input: {s}");
                println!("  chrono::DateTime<Utc>: {dt}");
                println!("  unix seconds: {seconds}");
                println!("  unix millis : {millis}");
