async fn get_oauth_token(client: &Client, cfg: &Config) -> Result<String> {
    let url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        cfg.tenant_id
    );

    let params = [
        ("grant_type", "client_credentials"),
        ("client_id", cfg.client_id.as_str()),
        ("client_secret", cfg.client_secret.as_str()),
        ("scope", "https://storage.azure.com/.default"),
    ];

    let resp = client
        .post(url)
        .form(&params)
        .send()
        .await
        .context("token request failed")?;

    let status = resp.status();
    let body = resp.text().await.unwrap_or_default();

    if !status.is_success() {
        return Err(anyhow!("token endpoint status={} body={}", status, body));
    }

    let parsed: TokenResponse = serde_json::from_str(&body)
        .with_context(|| format!("failed to parse token response: {}", body))?;

    Ok(parsed.access_token)
}

async fn list_blobs_for_prefix(
    client: &Client,
    cfg: &Config,
    token: &str,
    prefix: &str,
) -> Result<Vec<String>> {
    let mut out = Vec::new();
    let mut marker: Option<String> = None;
    let url = format!("{}/{}", cfg.service_base_url(), cfg.container_name);

    loop {
        let mut req = client
            .get(&url)
            .bearer_auth(token)
            .header("x-ms-version", "2023-11-03")
            .header("x-ms-date", httpdate::fmt_http_date(SystemTime::now()))
            .query(&[("restype", "container"), ("comp", "list"), ("maxresults", "5000")]);

        if !prefix.is_empty() {
            req = req.query(&[("prefix", prefix)]);
        }

        if let Some(m) = marker.as_deref() {
            if !m.is_empty() {
                req = req.query(&[("marker", m)]);
            }
        }

        let resp = req.send().await.context("list blobs request failed")?;
        let status = resp.status();
        let xml = resp.text().await.unwrap_or_default();

        if !status.is_success() {
            return Err(anyhow!("list blobs failed: status={} body={}", status, xml));
        }

        let parsed: EnumerationResults = from_str(&xml)
            .with_context(|| format!("failed to parse list XML (prefix='{}')", prefix))?;

        if let Some(blobs) = parsed.blobs {
            out.extend(blobs.blob.into_iter().map(|b| b.name));
        }

        marker = parsed
            .next_marker
            .and_then(|m| if m.trim().is_empty() { None } else { Some(m) });

        if marker.is_none() {
            break;
        }
    }

    Ok(out)
}

