    client: &Client,
    cfg: &Config,
    token: &str,
    blob_name: &str,
) -> Result<Option<Value>> {
    let encoded = encode_blob_name(blob_name);
    let url = format!("{}/{}/{}", cfg.service_base_url(), cfg.container_name, encoded);

    let resp = client
        .get(url)
        .bearer_auth(token)
        .header("x-ms-version", "2023-11-03")
        .header("x-ms-date", httpdate::fmt_http_date(SystemTime::now()))
        .send()
        .await
        .context("download request failed")?;

    let status = resp.status();
    if !status.is_success() {
        let body = resp.text().await.unwrap_or_default();
        return Err(anyhow!("download failed: status={} body={}", status, body));
    }

    let bytes = resp.bytes().await.context("failed to read blob body")?;

    match serde_json::from_slice::<Value>(&bytes) {
        Ok(v) => Ok(Some(v)),
        Err(_) => Ok(None),
    }
}

fn encode_blob_name(name: &str) -> String {
    name.split('/')
        .map(|segment| utf8_percent_encode(segment, PATH_SEGMENT_ENCODE_SET).to_string())
        .collect::<Vec<_>>()
        .join("/")
}

fn required_var(name: &str) -> Result<String> {
