    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        // Expected: Authorization: Bearer <sub>:<role>
        let raw = parts
            .headers
            .get(AUTHORIZATION)
            .ok_or_else(|| APIError::unauthorized("missing Authorization header"))?
            .to_str()
            .map_err(|_| APIError::unauthorized("invalid Authorization header"))?;

        let token = raw
            .strip_prefix("Bearer ")
            .ok_or_else(|| APIError::unauthorized("expected Bearer token"))?;

        let (sub, role) = token
            .split_once(':')
            .ok_or_else(|| APIError::unauthorized("token format must be <sub>:<role>"))?;

        Ok(AccessClaims {
            sub: sub.to_string(),
            role: role.to_string(),
        })
    }
}

#[derive(Debug, Clone, Copy)]
enum APIVersion {
    V1,
    V2,
}

impl std::fmt::Display for APIVersion {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        match self {
            APIVersion::V1 => write!(f, "v1"),
            APIVersion::V2 => write!(f, "v2"),
        }
    }
}

impl FromStr for APIVersion {
    type Err = String;

    fn from_str(s: &str) -> Result<Self, Self::Err> {
        match s {
            "v1" | "1" => Ok(APIVersion::V1),
            "v2" | "2" => Ok(APIVersion::V2),
            other => Err(format!("unsupported api version: {other}")),
        }
    }
}

struct ApiVersionHeader(APIVersion);

impl<S> FromRequestParts<S> for ApiVersionHeader
where
    S: Send + Sync,
{
    type Rejection = APIError;

    async fn from_request_parts(parts: &mut Parts, _state: &S) -> Result<Self, Self::Rejection> {
        let name = HeaderName::from_static("x-api-version");
        let value = parts
            .headers
            .get(name)
            .ok_or_else(|| APIError::bad_request("missing X-Api-Version header"))?;

        let s = value
            .to_str()
            .map_err(|_| APIError::bad_request("invalid X-Api-Version header"))?;

        let version = s.parse::<APIVersion>().map_err(APIError::bad_request)?;
        Ok(ApiVersionHeader(version))
    }
}

async fn revoke_user_handler(
    ApiVersionHeader(api_version): ApiVersionHeader,
    State(_state): State<SharedState>,
    access_claims: AccessClaims,
    ValidatedJson(revoke_user): ValidatedJson<RevokeUser>,
) -> Result<impl IntoResponse, APIError> {
    if access_claims.sub != revoke_user.user_id {
        access_claims.validate_role_admin()?;
    }

    Ok(Json(json!({
        "ok": true,
        "api_version": api_version.to_string()
    })))
}

fn auth_routes() -> Router<SharedState> {
    Router::new().route("/revoke-user", post(revoke_user_handler))
}

#[tokio::main]
async fn main() {
    let state: SharedState = Arc::new(AppState::default());

    let app = Router::new()
        .nest("/{version}/auth", auth_routes())
        .with_state(state);

    let addr: SocketAddr = "127.0.0.1:3000".parse().unwrap();
    let listener = tokio::net::TcpListener::bind(addr).await.unwrap();
    println!("listening on http://{addr}");
