    let output = rewrite_file(input);
    println!("{}", output);
}

fn rewrite_file(src: &str) -> String {
    let mut file = syn::parse_file(src).expect("failed to parse Rust source");
    rewrite_items(&mut file.items);
    prettyplease::unparse(&file)
}

fn rewrite_items(items: &mut [Item]) {
    for item in items {
        match item {
            Item::Use(item_use) => rewrite_item_use(item_use),
            Item::Mod(item_mod) => rewrite_item_mod(item_mod),
            _ => {}
        }
    }
}

fn rewrite_item_mod(item_mod: &mut ItemMod) {
    if let Some((_, items)) = &mut item_mod.content {
        rewrite_items(items);
    }
}

fn rewrite_item_use(item_use: &mut ItemUse) {
    let mut imports = Vec::new();
    collect_use_tree(&item_use.tree, &mut Vec::new(), &mut imports);

    for spec in &mut imports {
        rewrite_spec(spec);
    }

    // Deduplicate while preserving first-seen order.
    let mut seen = HashSet::new();
    let mut deduped = Vec::new();
    for spec in imports {
        let key = spec_to_string(&spec);
        if seen.insert(key) {
            deduped.push(spec);
        }
    }

    if let Some(new_tree) = build_use_tree(&deduped) {
        item_use.tree = new_tree;
    }
}

fn collect_use_tree(tree: &UseTree, prefix: &mut Vec<String>, out: &mut Vec<ImportSpec>) {
    match tree {
        UseTree::Path(p) => {
            prefix.push(p.ident.to_string());
            collect_use_tree(&p.tree, prefix, out);
            prefix.pop();
        }
        UseTree::Name(n) => {
            let ident = n.ident.to_string();
            if ident == "self" {
                out.push(ImportSpec::Path(prefix.clone()));
            } else {
                let mut path = prefix.clone();
                path.push(ident);
                out.push(ImportSpec::Path(path));
            }
        }
        UseTree::Rename(r) => {
            let ident = r.ident.to_string();
            let mut path = prefix.clone();
            if ident != "self" {
                path.push(ident);
            }
            out.push(ImportSpec::Rename {
                path,
                alias: r.rename.to_string(),
            });
        }
        UseTree::Glob(_) => out.push(ImportSpec::Glob(prefix.clone())),
        UseTree::Group(g) => {
            for t in &g.items {
                collect_use_tree(t, prefix, out);
            }
        }
        _ => {}
    }
}

fn rewrite_spec(spec: &mut ImportSpec) {
    match spec {
        ImportSpec::Path(path) => rewrite_path(path),
        ImportSpec::Rename { path, .. } => rewrite_path(path),
        ImportSpec::Glob(path) => rewrite_path(path),
    }
}

