fn build_use_tree(specs: &[ImportSpec]) -> Option<UseTree> {
    let parts: Vec<String> = specs
        .iter()
        .filter_map(|s| {
            let txt = spec_to_string(s);
            if txt.is_empty() {
                None
            } else {
                Some(txt)
            }
        })
        .collect();

    if parts.is_empty() {
