    }

    let src = if parts.len() == 1 {
        parts[0].clone()
    } else {
        format!("{{{}}}", parts.join(", "))
    };

    syn::parse_str::<UseTree>(&src).ok()
}

fn spec_to_string(spec: &ImportSpec) -> String {
    match spec {
        ImportSpec::Path(path) => path.join("::"),
        ImportSpec::Rename { path, alias } => {
            if path.is_empty() {
                String::new()
            } else {
                format!("{} as {}", path.join("::"), alias)
            }
        }
        ImportSpec::Glob(path) => {
            if path.is_empty() {
                String::new()
            } else {
                format!("{}::*", path.join("::"))
            }
        }
    }
}
