fn main() -> Result<(), Box<dyn std::error::Error>> {
    // File writer for the file layer
    let file = OpenOptions::new()
        .append(true)
        .create(true)
        .open("logfile.log")?;
    let file = Mutex::new(file);

    // Create independently reloadable filters for each layer.
    // This lets us change only console or only file logging at runtime.
    let (console_filter, console_handle) = reload::Layer::new(filter::LevelFilter::INFO);
    let (file_filter, _file_handle) = reload::Layer::new(filter::LevelFilter::INFO);

    let subscriber = Registry::default()
        .with(
