  "main.rs": "use std::env;
use std::fs;
use std::path::{Path, PathBuf};
use std::process::{Command, ExitCode};
use std::time::{SystemTime, UNIX_EPOCH};

// In a real project, you can replace this with:
// const PY_SCRIPT: &str = include_str!("python/script.py");
// and keep script.py in your repo.
const PY_SCRIPT: &str = r#"
import sys

print('Hello from embedded Python script!')
print('argv from Rust -> Python:', sys.argv)
"#;

fn main() -> ExitCode {
    let script_path = match write_embedded_script() {
        Ok(p) => p,
        Err(e) => {
            eprintln!("failed to write temporary script.py: {e}");
            return ExitCode::from(1);
        }
    };

    let user_args: Vec<String> = env::args().skip(1).collect();

    let status = match run_python(&script_path, &user_args) {
        Ok(status) => status,
        Err(e) => {
            eprintln!("failed to execute Python interpreter: {e}");
            let _ = fs::remove_file(&script_path);
            return ExitCode::from(1);
        }
    };

    // Best-effort cleanup.
    let _ = fs::remove_file(&script_path);

    match status.code() {
        Some(code) => ExitCode::from(code as u8),
        None => ExitCode::from(1),
    }
}

fn write_embedded_script() -> std::io::Result<PathBuf> {
    let mut path = env::temp_dir();
    path.push(unique_script_name());
    fs::write(&path, PY_SCRIPT)?;
    Ok(path)
}

fn unique_script_name() -> String {
    let pid = std::process::id();
    let nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0);
    format!("rust_program_embedded_{pid}_{nanos}.py")
}

fn run_python(script_path: &Path, passthrough_args: &[String]) -> std::io::Result<std::process::ExitStatus> {
    // Try common interpreter commands in order.
    // Windows often has "py" launcher; Unix often has "python3".
    let candidates: &[(&str, &[&str])] = &[
        ("python3", &[]),
        ("python", &[]),
        ("py", &["-3"]),
        ("py", &[]),
    ];

    for (cmd, pre_args) in candidates {
        if is_command_usable(cmd, pre_args) {
            let mut child = Command::new(cmd);
            child.args(*pre_args);
            child.arg(script_path);
            child.args(passthrough_args);
            return child.status();
        }
    }

    Err(std::io::Error::new(
        std::io::ErrorKind::NotFound,
        "no Python interpreter found (tried: python3, python, py -3, py)",
    ))
}

fn is_command_usable(cmd: &str, pre_args: &[&str]) -> bool {
    let mut probe = Command::new(cmd);
    probe.args(pre_args).arg("--version");
    probe.status().map(|s| s.success()).unwrap_or(false)
}
"
}

