  "main.rs": "use axum::{
    body::Body,
    extract::{
        ws::{Message, WebSocket},
        Path, WebSocketUpgrade,
    },
    http::{
        header::{CONTENT_TYPE, ORIGIN, UPGRADE},
        Method, Request, StatusCode,
    },
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use tower_http::cors::CorsLayer;

const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    // Middleware that enforces Origin for websocket upgrade requests.
    let app = Router::new()
        .route("/", get(root))
        .route("/client/:session_id", get(client_handler))
        .route_layer(middleware::from_fn(check_ws_origin))
        // Regular CORS for normal HTTP endpoints.
        .layer(
            CorsLayer::new()
                .allow_origin([ALLOWED_ORIGIN.parse().expect("valid origin")])
                .allow_methods([Method::GET, Method::POST])
                .allow_headers([CONTENT_TYPE]),
        );

    let listener = tokio::net::TcpListener::bind("0.0.0.0:3000")
        .await
        .expect("bind failed");

    println!("listening on http://{}", listener.local_addr().unwrap());
    axum::serve(listener, app).await.expect("server failed");
}

async fn root() -> &'static str {
    "Try websocket endpoint at /client/<session_id>"
}

async fn check_ws_origin(req: Request<Body>, next: Next) -> Result<Response, StatusCode> {
    // Only enforce this on websocket upgrade requests.
    let is_ws_upgrade = req
        .headers()
        .get(UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);

    if is_ws_upgrade {
        let origin_ok = req
            .headers()
            .get(ORIGIN)
            .and_then(|v| v.to_str().ok())
            .map(|origin| origin == ALLOWED_ORIGIN)
            .unwrap_or(false);

        if !origin_ok {
            return Err(StatusCode::FORBIDDEN);
        }
    }

    Ok(next.run(req).await)
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    while let Some(Ok(msg)) = socket.recv().await {
        match msg {
            Message::Text(text) => {
                let reply = format!("[{session_id}] {text}");
                if socket.send(Message::Text(reply.into())).await.is_err() {
                    break;
                }
            }
            Message::Binary(bytes) => {
                if socket.send(Message::Binary(bytes)).await.is_err() {
                    break;
                }
            }
            Message::Close(_) => break,
            _ => {}
        }
    }
}
"
}

