",
  "main.rs": "use std::{
    env,
    error::Error,
    io::{self, BufRead, BufReader, Write},
    process::{Command, Stdio},
    sync::{
        atomic::{AtomicBool, Ordering},
        Arc,
    },
    thread,
    time::Duration,
};

use rustyline::{error::ReadlineError, DefaultEditor};

fn main() -> Result<(), Box<dyn Error>> {
    if env::args().any(|a| a == "--child") {
        run_child()?;
        return Ok(());
    }

    run_parent()
}

fn run_parent() -> Result<(), Box<dyn Error>> {
    let mut rl = DefaultEditor::new()?;

    let exe = env::current_exe()?;
    let mut child = Command::new(exe)
        .arg("--child")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .spawn()?;

    let mut child_stdin = child.stdin.take().expect("failed to take child stdin");
    let child_stdout = child.stdout.take().expect("failed to take child stdout");

    // Key point: this printer can print while readline() is blocked.
    let mut printer = rl.create_external_printer()?;
    thread::spawn(move || {
        let reader = BufReader::new(child_stdout);
        for line in reader.lines() {
            match line {
                Ok(line) => {
                    let _ = printer.print(format!("[child] {line}"));
                }
                Err(_) => break,
            }
        }
    });

    loop {
        match rl.readline("> ") {
            Ok(line) => {
                let trimmed = line.trim();
                if !trimmed.is_empty() {
                    let _ = rl.add_history_entry(trimmed);
                }

                writeln!(child_stdin, "{line}")?;
                child_stdin.flush()?;

                if trimmed == "exit" || trimmed == "quit" {
                    break;
                }
            }
            Err(ReadlineError::Interrupted) => {
                println!("^C (type 'exit' to quit)");
            }
            Err(ReadlineError::Eof) => {
                writeln!(child_stdin, "exit")?;
                child_stdin.flush()?;
                break;
            }
            Err(err) => {
                eprintln!("readline error: {err}");
                break;
            }
        }
    }

    let _ = child.wait();
    Ok(())
}

fn run_child() -> Result<(), Box<dyn Error>> {
    let running = Arc::new(AtomicBool::new(true));
    let running_bg = Arc::clone(&running);

    let bg = thread::spawn(move || {
        let mut i = 1u64;
        while running_bg.load(Ordering::SeqCst) {
            println!("async event #{i} (emitted even if parent is waiting in readline)");
            let _ = io::stdout().flush();
            i += 1;
            thread::sleep(Duration::from_secs(2));
        }
    });

    println!("child REPL started. Commands: ping, help, exit");
    io::stdout().flush()?;

    let stdin = io::stdin();
    for line in stdin.lock().lines() {
        let line = line?;
        let cmd = line.trim();

        match cmd {
            "ping" => println!("pong"),
            "help" => println!("available commands: ping, help, exit"),
            "exit" | "quit" => {
                println!("bye");
                io::stdout().flush()?;
                break;
            }
            "" => {}
            other => println!("echo: {other}"),
        }

        io::stdout().flush()?;
    }

    running.store(false, Ordering::SeqCst);
    let _ = bg.join();
    Ok(())
}
"
}

