    let mut session = spawn("env TERM=xterm-256color bash -i")?;

    // IMPORTANT PATTERN:
    // Duplicate PTY master FD and split read/write without a shared mutex.
    // Reader can block forever; writer remains independent.
    let master_fd = session.as_raw_fd();
    let read_fd = dup(master_fd)?;
    let write_fd = dup(master_fd)?;

    let (to_writer_tx, to_writer_rx) = mpsc::channel::<Vec<u8>>();
    let (reader_done_tx, reader_done_rx) = mpsc::channel::<()>();

    // Reader thread: blocking read from PTY, print to stdout.
    let reader_handle = thread::spawn(move || {
        let mut reader = File::from(read_fd);
        let mut stdout = std::io::stdout();
        let mut buf = [0u8; 4096];

