    // Writer thread: receives bytes from channel and writes to PTY.
    let writer_handle = thread::spawn(move || {
        let mut writer = File::from(write_fd);
        while let Ok(bytes) = to_writer_rx.recv() {
            if writer.write_all(&bytes).is_err() {
                break;
            }
            let _ = writer.flush();
        }
    });

    println!("\n--- PTY started ---");
    println!("Type to interact. Press Ctrl-] to quit this demo.\n");

    let _raw = RawModeGuard::new()?;

    // Main loop: poll keyboard and forward bytes to writer channel.
    // Also exits when child side closes (reader_done).
    loop {
        if reader_done_rx.try_recv().is_ok() {
            break;
        }

        if event::poll(Duration::from_millis(30))? {
            if let Event::Key(k) = event::read()? {
                if let Some(bytes) = key_to_bytes(k) {
                    if bytes == vec![0x1d] {
                        // Ctrl-] local escape (do not send to child)
                        break;
                    }
                    if to_writer_tx.send(bytes).is_err() {
                        break;
                    }
                }
            }
        }
    }

    // Stop writer thread.
    drop(to_writer_tx);

    // Dropping session typically ends child management on expectrl side.
    drop(session);

    let _ = writer_handle.join();
    let _ = reader_handle.join();

    println!("\n--- exited ---");
    Ok(())
}
