use std::time::Duration;
use thiserror::Error;

/// The asset type we want to load through Bevy.
#[derive(Asset, TypePath, Debug)]
struct PackText(pub String);

#[derive(Default)]
struct PackTextLoader;

#[derive(Debug, Error)]
enum PackLoadError {
    #[error("io error: {0}")]
    Io(#[from] std::io::Error),

    #[error("utf8 error: {0}")]
    Utf8(#[from] std::string::FromUtf8Error),

    #[error("invalid descriptor format. expected: `pack_relative_path|entry_name`")]
    InvalidDescriptor,

    #[error("invalid pack file magic")]
    InvalidMagic,

    #[error("entry `{0}` not found in pack")]
    MissingEntry(String),
}

impl AssetLoader for PackTextLoader {
    type Asset = PackText;
    type Settings = ();
    type Error = PackLoadError;

    async fn load(
        &self,
        reader: &mut Reader,
        _settings: &Self::Settings,
        load_context: &mut LoadContext<'_>,
    ) -> Result<Self::Asset, Self::Error> {
        // Read only a tiny descriptor file from Bevy (cheap):
        //   demo.pack|greeting.txt
        let mut descriptor_bytes = Vec::new();
        reader.read_to_end(&mut descriptor_bytes).await?;
        let descriptor = String::from_utf8(descriptor_bytes)?;
        let descriptor = descriptor.trim();

        let (pack_rel, entry_name) = descriptor
            .split_once('|')
            .ok_or(PackLoadError::InvalidDescriptor)?;

        // Resolve pack path relative to descriptor location inside assets/
        let descriptor_virtual_path = load_context.path().path();
        let descriptor_dir = descriptor_virtual_path.parent().unwrap_or(Path::new(""));
        let pack_virtual_path = descriptor_dir.join(pack_rel);

        // For default source, assets live under ./assets
        let pack_disk_path = Path::new("assets").join(pack_virtual_path);

        // Lazy part: open pack and read only the requested entry.
        let raw = read_entry_from_pack(&pack_disk_path, entry_name)?;
        let text = String::from_utf8(raw)?;

        Ok(PackText(text))
    }

    fn extensions(&self) -> &[&str] {
        &["packtxt"]
    }
}

#[derive(Resource)]
struct RequestedHandle(Handle<PackText>);

fn main() {
    create_demo_files().expect("failed to create demo files");

    App::new()
        .add_plugins((
            MinimalPlugins.set(ScheduleRunnerPlugin::run_loop(Duration::from_millis(50))),
