// ---------------- Demo pack format + helpers ----------------
// Format:
// [4 bytes magic "PACK"]
// [u32 entry_count]
// repeated entry_count times:
//   [u16 name_len][name bytes][u64 offset][u64 size]
// then raw data blob for each entry.

fn create_demo_files() -> std::io::Result<()> {
    let assets_dir = PathBuf::from("assets");
    fs::create_dir_all(&assets_dir)?;

    let pack_path = assets_dir.join("demo.pack");
    let entries: Vec<(&str, &[u8])> = vec![
        ("greeting.txt", b"Hello from a lazily-read entry inside demo.pack!"),
        ("other.txt", b"Another file in the same archive."),
        ("notes/dev.txt", b"Nested-like names work too (as plain strings)."),
    ];
    write_pack(&pack_path, &entries)?;

    // Descriptor files Bevy can load normally.
    // Each tells loader which archive+entry to fetch lazily.
    fs::write(
        assets_dir.join("demo_greeting.packtxt"),
        "demo.pack|greeting.txt\n",
    )?;

    Ok(())
}

fn write_pack(path: &Path, entries: &[(&str, &[u8])]) -> std::io::Result<()> {
    let mut file = File::create(path)?;

    let header_len: u64 = 4
        + 4
        + entries
            .iter()
            .map(|(name, _)| 2 + name.as_bytes().len() as u64 + 8 + 8)
            .sum::<u64>();

    file.write_all(b"PACK")?;
    write_u32(&mut file, entries.len() as u32)?;

    let mut running_offset = header_len;
    for (name, data) in entries {
        let name_bytes = name.as_bytes();
        write_u16(&mut file, name_bytes.len() as u16)?;
        file.write_all(name_bytes)?;
        write_u64(&mut file, running_offset)?;
        write_u64(&mut file, data.len() as u64)?;
        running_offset += data.len() as u64;
    }

    for (_, data) in entries {
        file.write_all(data)?;
    }

    Ok(())
}

fn read_entry_from_pack(path: &Path, wanted_name: &str) -> Result<Vec<u8>, PackLoadError> {
    let mut file = File::open(path)?;

    let mut magic = [0u8; 4];
    file.read_exact(&mut magic)?;
    if &magic != b"PACK" {
        return Err(PackLoadError::InvalidMagic);
    }

    let count = read_u32(&mut file)?;

    let mut found: Option<(u64, u64)> = None;

    for _ in 0..count {
        let name_len = read_u16(&mut file)? as usize;
        let mut name_bytes = vec![0u8; name_len];
        file.read_exact(&mut name_bytes)?;
        let name = String::from_utf8(name_bytes)?;

        let offset = read_u64(&mut file)?;
        let size = read_u64(&mut file)?;

        if name == wanted_name {
            found = Some((offset, size));
        }
    }

    let (offset, size) = found.ok_or_else(|| PackLoadError::MissingEntry(wanted_name.to_string()))?;

    file.seek(SeekFrom::Start(offset))?;
    let mut buf = vec![0u8; size as usize];
    file.read_exact(&mut buf)?;
    Ok(buf)
}

fn write_u16<W: Write>(w: &mut W, v: u16) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}
fn write_u32<W: Write>(w: &mut W, v: u32) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}
fn write_u64<W: Write>(w: &mut W, v: u64) -> std::io::Result<()> {
    w.write_all(&v.to_le_bytes())
}

fn read_u16<R: Read>(r: &mut R) -> std::io::Result<u16> {
    let mut b = [0u8; 2];
    r.read_exact(&mut b)?;
    Ok(u16::from_le_bytes(b))
}
fn read_u32<R: Read>(r: &mut R) -> std::io::Result<u32> {
    let mut b = [0u8; 4];
    r.read_exact(&mut b)?;
    Ok(u32::from_le_bytes(b))
}
fn read_u64<R: Read>(r: &mut R) -> std::io::Result<u64> {
    let mut b = [0u8; 8];
    r.read_exact(&mut b)?;
    Ok(u64::from_le_bytes(b))
}
"
