static CHANNEL_INDEX: AtomicUsize = AtomicUsize::new(0);

/// Replacement for `fetch_add(1, Ordering::Relaxed)` using a critical section.
///
/// Important notes for embedded targets:
/// - Keep `Ordering::Relaxed` for the load/store if your original operation was relaxed.
/// - Use `wrapping_add` to match `fetch_add` overflow behavior.
/// - On RP2040 (dual core), your critical-section implementation must protect across cores,
///   not just disable interrupts on one core.
fn cs_fetch_add_relaxed(atom: &AtomicUsize, val: usize) -> usize {
    critical_section::with(|_| {
        let old = atom.load(Ordering::Relaxed);
        atom.store(old.wrapping_add(val), Ordering::Relaxed);
        old
    })
}

