  "main.rs": "use serde::{Deserialize, Serialize};
use serde_json::{json, Value};
use std::collections::HashMap;

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
enum RichTextType {
    Text,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct TextObject {
    content: String,
    link: Option<String>,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct RichTextObject {
    annotations: Option<Value>,
    data_type: Option<RichTextType>,
    equation: Option<Value>,
    mention: Option<Value>,
    plain_text: Option<String>,
    href: Option<String>,
    text: TextObject,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
struct SelectObject {
    id: Option<String>,
    color: Option<String>,
    name: String,
}

#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "type", content = "value")]
enum PropertyValues {
    Title(Vec<RichTextObject>),
    Url(String),
    MultiSelect(Vec<SelectObject>),
}

fn value_to_name(v: &Value) -> String {
    v.as_str().map_or_else(|| v.to_string(), ToString::to_string)
}

macro_rules! notion_value {
    ("title", $value:expr) => {
        PropertyValues::Title(vec![RichTextObject {
            annotations: None,
            data_type: Some(RichTextType::Text),
            equation: None,
            mention: None,
            plain_text: None,
            href: None,
            text: TextObject {
                content: ($value).clone(),
                link: None,
            },
        }])
    };
    ("url", $value:expr) => {
        PropertyValues::Url(($value).clone())
    };
    ("MultiSelect", $value:expr) => {
        PropertyValues::MultiSelect(
            ($value)
                .iter()
                .map(|f| SelectObject {
                    id: None,
                    color: None,
                    name: value_to_name(f),
                })
                .collect(),
        )
    };
    ($other:literal, $value:expr) => {
        compile_error!(concat!("Unsupported notion_property type: ", $other));
    };
}

macro_rules! notion_struct_emit_fields {
    () => {};
    (
        #[notion_property(type = $ptype:literal, name = $pname:literal)]
        $vis:vis $fname:ident : $fty:ty,
        $($rest:tt)*
    ) => {
        $vis $fname : $fty,
        notion_struct_emit_fields! { $($rest)* }
    };
}

macro_rules! notion_struct_insert_fields {
    ($self_ref:expr, $map:ident,) => {};

    (
        $self_ref:expr,
        $map:ident,
        #[notion_property(type = $ptype:literal, name = $pname:literal)]
        $vis:vis $fname:ident : Option<$inner:ty>,
        $($rest:tt)*
    ) => {
        if let Some(value) = &$self_ref.$fname {
            $map.insert($pname.to_string(), notion_value!($ptype, value));
        }
        notion_struct_insert_fields!($self_ref, $map, $($rest)*);
    };

    (
        $self_ref:expr,
        $map:ident,
        #[notion_property(type = $ptype:literal, name = $pname:literal)]
        $vis:vis $fname:ident : $fty:ty,
        $($rest:tt)*
    ) => {
        let value = &$self_ref.$fname;
        $map.insert($pname.to_string(), notion_value!($ptype, value));
        notion_struct_insert_fields!($self_ref, $map, $($rest)*);
    };
}

macro_rules! notion_struct {
    (
        $(#[$meta:meta])*
        struct $name:ident {
            $($fields:tt)*
        }
    ) => {
        $(#[$meta])*
        #[derive(Debug, Clone, Serialize, Deserialize)]
        struct $name {
            notion_struct_emit_fields! { $($fields)* }
        }

        impl $name {
            fn to_notion_properties(&self) -> HashMap<String, PropertyValues> {
                let mut tmp = HashMap::new();
                notion_struct_insert_fields!(self, tmp, $($fields)*);
                tmp
            }
        }
    };
}

notion_struct! {
    struct MyUnit {
        #[notion_property(type = "title", name = "Name")]
        pub name: String,

        #[notion_property(type = "url", name = "Icon url")]
        pub icon_url: Option<String>,

        #[notion_property(type = "MultiSelect", name = "Roles")]
        pub categories: Option<Vec<Value>>,
    }
}

fn main() {
    let unit = MyUnit {
        name: "Payments Service".to_string(),
        icon_url: Some("https://example.com/icon.png".to_string()),
        categories: Some(vec![json!("Backend"), json!("Critical"), json!(42)]),
    };

    let properties = unit.to_notion_properties();

    println!("{:#?}", properties);
    println!("\nAs JSON:\n{}");
    println!(
        "{}",
        serde_json::to_string_pretty(&properties).expect("Failed to serialize properties")
    );
}
"
