fn face_gizmo_rotation(block_rot: Quat, normal_ws: Vec3) -> Quat {
    let z = normal_ws.normalize();

    // Start from cube's local up transformed to world, then project onto face plane.
    let mut y = block_rot * Vec3::Y;
    y -= z * y.dot(z);

    // Fallback if nearly parallel to normal.
    if y.length_squared() < 1e-6 {
        y = block_rot * Vec3::X;
        y -= z * y.dot(z);
    }

    y = y.normalize();
    let x = y.cross(z).normalize();
    let y = z.cross(x).normalize();

    Quat::from_mat3(&Mat3::from_cols(x, y, z))
}
