                None => break,
            }
        }
        r_busy_c.set(false);
    });

    // --- nq -> s_fb (non-reentrant sink) ---
    let s_queue = Rc::new(RefCell::new(VecDeque::<bool>::new()));
    let s_busy = Rc::new(Cell::new(false));
