use std::io;
use std::path::{Path, PathBuf};

#[derive(Debug)]
struct A {
    path_list: Vec<PathBuf>,
}

#[derive(Deserialize)]
struct ARaw {
    path_list: PathListField,
}

#[derive(Deserialize)]
#[serde(untagged)]
enum PathListField {
    Inline(Vec<PathBuf>),
    Ref {
        #[serde(rename = "$ref")]
        reference: String,
    },
}

fn err_invalid(msg: impl Into<String>) -> Box<dyn Error> {
    io::Error::new(io::ErrorKind::InvalidData, msg.into()).into()
}

fn resolve_ref_to_paths(reference: &str, base_dir: &Path) -> Result<Vec<PathBuf>, Box<dyn Error>> {
    let (file_part, pointer_part) = match reference.split_once('#') {
        Some((file, pointer)) => (file, pointer),
        None => (reference, ""),
    };

    if file_part.is_empty() {
        return Err(err_invalid("$ref must include a file path, e.g. ./a.json#/p_list"));
    }

    let target_file = base_dir.join(file_part);
    let target_json = fs::read_to_string(&target_file)?;
    let doc: Value = serde_json::from_str(&target_json)?;

    let target_value = if pointer_part.is_empty() {
        &doc
    } else {
        let pointer = if pointer_part.starts_with('/') {
            pointer_part.to_string()
        } else {
            format!("/{}", pointer_part)
        };

        doc.pointer(&pointer).ok_or_else(|| {
            err_invalid(format!(
                "JSON pointer '{}' not found in file '{}'",
                pointer,
                target_file.display()
            ))
        })?
    };

    let paths: Vec<PathBuf> = serde_json::from_value(target_value.clone())?;
    Ok(paths)
}

fn load_a(path: &Path) -> Result<A, Box<dyn Error>> {
    let json = fs::read_to_string(path)?;
    let raw: ARaw = serde_json::from_str(&json)?;

    let base_dir = path.parent().unwrap_or_else(|| Path::new("."));
    let path_list = match raw.path_list {
        PathListField::Inline(v) => v,
        PathListField::Ref { reference } => resolve_ref_to_paths(&reference, base_dir)?,
    };

    Ok(A { path_list })
}

