  "main.rs": "use std::io::{self, Read};

/// Split a command line into tokens, using shell-like rules for:
/// - whitespace separation (space/tab/newline)
/// - single quotes that preserve literal text
/// - concatenation across quoted/unquoted segments
///
/// Example:
/// input:  one  ' two  'three    four
/// output: ["one", " two  three", "four"]
fn tokenize_shell_like(input: &str) -> Result<Vec<String>, String> {
    fn is_shell_whitespace(c: char) -> bool {
        matches!(c, ' ' | '\t' | '\n')
    }

    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quote = false;
    let mut token_started = false;

    for ch in input.chars() {
        if in_single_quote {
            if ch == '\'' {
                in_single_quote = false;
            } else {
                current.push(ch);
            }
            token_started = true;
            continue;
        }

        match ch {
            '\'' => {
                in_single_quote = true;
                token_started = true;
            }
            c if is_shell_whitespace(c) => {
                if token_started {
                    tokens.push(std::mem::take(&mut current));
                    token_started = false;
                }
            }
            _ => {
                current.push(ch);
                token_started = true;
            }
        }
    }

    if in_single_quote {
        return Err("unclosed single quote".to_string());
    }

    if token_started {
        tokens.push(current);
    }

    Ok(tokens)
}

fn main() {
    // Read entire stdin if provided; otherwise use the sample.
    let mut buf = String::new();
    let _ = io::stdin().read_to_string(&mut buf);

    let input = if buf.trim().is_empty() {
        " one  ' two  'three    four"
    } else {
        buf.trim_end_matches(['\r', '\n'])
    };

    match tokenize_shell_like(input) {
        Ok(tokens) => {
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("tokenize error: {e}");
            std::process::exit(1);
        }
    }
}

#[cfg(test)]
mod tests {
    use super::tokenize_shell_like;

    #[test]
    fn sample_from_prompt() {
        let input = " one  ' two  'three    four";
        let got = tokenize_shell_like(input).unwrap();
        let expected = vec![
            "one".to_string(),
            " two  three".to_string(),
            "four".to_string(),
        ];
        assert_eq!(got, expected);
    }

    #[test]
    fn empty_quoted_token() {
        let input = "a '' b";
        let got = tokenize_shell_like(input).unwrap();
        assert_eq!(got, vec!["a", "", "b"]);
    }

    #[test]
    fn quoted_unquoted_concatenation() {
        let input = "x'y'z";
        let got = tokenize_shell_like(input).unwrap();
        assert_eq!(got, vec!["xyz"]);
    }

    #[test]
    fn error_on_unclosed_quote() {
        let input = "abc 'def";
        assert!(tokenize_shell_like(input).is_err());
    }
}
"
}

