struct NounDataFilter {
    gender: Option<Gender>,
    countable: Option<bool>,
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Deserialize)]
#[serde(default, deny_unknown_fields)]
struct VerbDataFilter {
    transitive: Option<bool>,
}

#[derive(Debug, Default, Clone, PartialEq, Eq, Deserialize)]
#[serde(default, deny_unknown_fields)]
struct DictWordMetadataFilter {
    noun: Option<NounDataFilter>,
    verb: Option<VerbDataFilter>,
    swear: Option<bool>,
    preposition: Option<bool>,
    common: Option<bool>,
    stress: Option<Stress>,
    gender: Option<Gender>,
}

// ---------------- MATCHING LOGIC ----------------

trait MatchesFilter<F> {
    fn matches_filter(&self, filter: &F) -> bool;
}

fn option_value_matches<T: PartialEq>(value: &Option<T>, cond: &Option<T>) -> bool {
    match cond {
        Some(expected) => value.as_ref() == Some(expected),
        None => true,
    }
}

impl MatchesFilter<NounDataFilter> for NounData {
    fn matches_filter(&self, f: &NounDataFilter) -> bool {
        option_value_matches(&self.gender, &f.gender)
            && option_value_matches(&self.countable, &f.countable)
    }
}

impl MatchesFilter<VerbDataFilter> for VerbData {
    fn matches_filter(&self, f: &VerbDataFilter) -> bool {
        option_value_matches(&self.transitive, &f.transitive)
    }
}

