    #[sqlx(rename = "team_name")]
    name: String,
}

#[derive(Debug, Clone, PartialEq, Eq, FromRow)]
struct Employee {
    id: i64,
    name: String,
    #[sqlx(flatten)]
    team: Team,
}

#[tokio::main]
async fn main() -> Result<(), Box<dyn std::error::Error>> {
    // In-memory SQLite database.
    // max_connections(1) keeps this simple and avoids separate-memory-connection gotchas.
    let pool = SqlitePoolOptions::new()
        .max_connections(1)
        .connect("sqlite::memory:")
        .await?;

    query("PRAGMA foreign_keys = ON;").execute(&pool).await?;

    query(
        r#"
        CREATE TABLE teams (
            id INTEGER PRIMARY KEY,
            name TEXT NOT NULL
        );
        "#,
    )
    .execute(&pool)
    .await?;

    query(
