        CREATE TABLE employees (
            id INTEGER PRIMARY KEY,
            name TEXT NOT NULL,
            team INTEGER NOT NULL,
            FOREIGN KEY (team) REFERENCES teams(id)
        );
        "#,
    )
    .execute(&pool)
    .await?;

    query("INSERT INTO teams (id, name) VALUES (1, 'East Coast Team'), (2, 'West Coast Team');")
        .execute(&pool)
        .await?;

    query("INSERT INTO employees (id, name, team) VALUES (1, 'Boston Alice', 1), (2, 'Seattle Bob', 2);")
        .execute(&pool)
        .await?;

    // IMPORTANT: To materialize Employee { team: Team }, you must JOIN and select team columns.
    // A plain "SELECT * FROM employees" only has team_id, not the full Team row.
    let employee: Employee = query_as(
        r#"
        SELECT
            e.id,
            e.name,
            t.id   AS team_id,
            t.name AS team_name
        FROM employees e
        JOIN teams t ON t.id = e.team
        WHERE e.id = ?
        "#,
    )
    .bind(1_i64)
    .fetch_one(&pool)
    .await?;

    let expected = Employee {
        id: 1,
        name: "Boston Alice".to_string(),
        team: Team {
            id: 1,
            name: "East Coast Team".to_string(),
        },
    };

    assert_eq!(employee, expected);

