const FILE_PATH: &str = "output.json";

fn load_or_create(path: &Path) -> io::Result<Vec<String>> {
    match fs::read_to_string(path) {
        Ok(data) => {
            if data.trim().is_empty() {
                return Ok(Vec::new());
            }

            let todos: Vec<String> = serde_json::from_str(&data).map_err(|e| {
                io::Error::new(
                    io::ErrorKind::InvalidData,
                    format!("Invalid JSON in {}: {}", path.display(), e),
                )
            })?;

            Ok(todos)
