        Err(e) if e.kind() == io::ErrorKind::NotFound => {
            fs::write(path, "[]")?;
            Ok(Vec::new())
        }
        Err(e) => Err(e),
    }
}

fn save(path: &Path, todos: &[String]) -> io::Result<()> {
    let json = serde_json::to_string_pretty(todos).map_err(|e| {
        io::Error::new(
            io::ErrorKind::Other,
            format!("Failed to serialize todo list: {}", e),
        )
