  "main.rs": "use serde::de::{self, Deserialize, Deserializer, MapAccess, Visitor};
use serde::Serialize;
use std::fmt;

#[derive(Debug, Default, Serialize)]
struct A {
    x: usize,
    b: Vec<B>,
}

#[derive(Debug, Serialize)]
enum B {
    Num(i64),
    Text(String),
}

// -------------------------
// Custom Deserialize for B
// Expected JSON shape for each B:
// {"kind":"num","n":123}
// or
// {"kind":"text","s":"hello"}
// -------------------------
impl<'de> Deserialize<'de> for B {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        enum Field {
            Kind,
            N,
            S,
        }

        impl<'de> Deserialize<'de> for Field {
            fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
            where
                D: Deserializer<'de>,
            {
                struct FieldVisitor;

                impl<'de> Visitor<'de> for FieldVisitor {
                    type Value = Field;

                    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                        formatter.write_str("`kind`, `n`, or `s`")
                    }

                    fn visit_str<E>(self, value: &str) -> Result<Field, E>
                    where
                        E: de::Error,
                    {
                        match value {
                            "kind" => Ok(Field::Kind),
                            "n" => Ok(Field::N),
                            "s" => Ok(Field::S),
                            _ => Err(de::Error::unknown_field(value, &["kind", "n", "s"])),
                        }
                    }
                }

                deserializer.deserialize_identifier(FieldVisitor)
            }
        }

        struct BVisitor;

        impl<'de> Visitor<'de> for BVisitor {
            type Value = B;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("a map describing enum B")
            }

            fn visit_map<V>(self, mut map: V) -> Result<B, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut kind: Option<String> = None;
                let mut n: Option<i64> = None;
                let mut s: Option<String> = None;

                while let Some(key) = map.next_key()? {
                    match key {
                        Field::Kind => {
                            if kind.is_some() {
                                return Err(de::Error::duplicate_field("kind"));
                            }
                            kind = Some(map.next_value()?);
                        }
                        Field::N => {
                            if n.is_some() {
                                return Err(de::Error::duplicate_field("n"));
                            }
                            n = Some(map.next_value()?);
                        }
                        Field::S => {
                            if s.is_some() {
                                return Err(de::Error::duplicate_field("s"));
                            }
                            s = Some(map.next_value()?);
                        }
                    }
                }

                match kind.as_deref() {
                    Some("num") => {
                        let value = n.ok_or_else(|| de::Error::missing_field("n"))?;
                        Ok(B::Num(value))
                    }
                    Some("text") => {
                        let value = s.ok_or_else(|| de::Error::missing_field("s"))?;
                        Ok(B::Text(value))
                    }
                    Some(other) => Err(de::Error::unknown_variant(other, &["num", "text"])),
                    None => Err(de::Error::missing_field("kind")),
                }
            }
        }

        deserializer.deserialize_map(BVisitor)
    }
}

// -------------------------
// Custom Deserialize for A
// This is where nested deserialization happens:
// "b" => map.next_value::<Vec<B>>()?
// -------------------------
impl<'de> Deserialize<'de> for A {
    fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
    where
        D: Deserializer<'de>,
    {
        enum Field {
            X,
            B,
        }

        impl<'de> Deserialize<'de> for Field {
            fn deserialize<D>(deserializer: D) -> Result<Self, D::Error>
            where
                D: Deserializer<'de>,
            {
                struct FieldVisitor;

                impl<'de> Visitor<'de> for FieldVisitor {
                    type Value = Field;

                    fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                        formatter.write_str("`x` or `b`")
                    }

                    fn visit_str<E>(self, value: &str) -> Result<Field, E>
                    where
                        E: de::Error,
                    {
                        match value {
                            "x" => Ok(Field::X),
                            "b" => Ok(Field::B),
                            _ => Err(de::Error::unknown_field(value, &["x", "b"])),
                        }
                    }
                }

                deserializer.deserialize_identifier(FieldVisitor)
            }
        }

        struct AVisitor;

        impl<'de> Visitor<'de> for AVisitor {
            type Value = A;

            fn expecting(&self, formatter: &mut fmt::Formatter) -> fmt::Result {
                formatter.write_str("struct A")
            }

            fn visit_map<V>(self, mut map: V) -> Result<A, V::Error>
            where
                V: MapAccess<'de>,
            {
                let mut x: Option<usize> = None;
                let mut b: Option<Vec<B>> = None;

                while let Some(key) = map.next_key()? {
                    match key {
                        Field::X => {
                            if x.is_some() {
                                return Err(de::Error::duplicate_field("x"));
                            }
                            x = Some(map.next_value()?);
                        }
                        Field::B => {
                            if b.is_some() {
                                return Err(de::Error::duplicate_field("b"));
                            }
                            // This is the nested handoff to B's custom deserializer.
                            b = Some(map.next_value::<Vec<B>>()?);
                        }
                    }
                }

                let x = x.ok_or_else(|| de::Error::missing_field("x"))?;
                let b = b.unwrap_or_default();

                Ok(A { x, b })
            }
        }

        deserializer.deserialize_struct("A", &["x", "b"], AVisitor)
    }
}

fn main() {
    let input = r#"
    {
