  "main.rs": "/// This example is self-contained and runnable with `cargo run`.
///
/// Why this matters for `radiate`:
/// - If `radiate::Op` is an enum with only predefined variants,
///   you cannot add new variants (like `sqrtplusone`) from outside the crate.
/// - In Rust, enums are closed types.
/// - So your options are:
///   1) Use a crate-provided "custom function" constructor (if it exists), or
///   2) Fork/modify `radiate` to add custom-op support.
///
/// The code below demonstrates the pattern a GP library would need:
/// a `Custom` operator variant storing function pointer + arity.

#[derive(Clone, Copy)]
enum BuiltinOp {
    Add,
    Sub,
    Mul,
    Pow,
    Var(usize),
    Const(f64),
}

#[derive(Clone, Copy)]
struct CustomOp {
    name: &'static str,
    arity: usize,
    f: fn(&[f64]) -> f64,
}

#[derive(Clone, Copy)]
enum Op {
    Builtin(BuiltinOp),
    Custom(CustomOp),
}

#[derive(Clone)]
struct Node {
    op: Op,
    children: Vec<Node>,
}

impl Node {
    fn eval(&self, vars: &[f64]) -> f64 {
        match self.op {
            Op::Builtin(BuiltinOp::Add) => self.children[0].eval(vars) + self.children[1].eval(vars),
            Op::Builtin(BuiltinOp::Sub) => self.children[0].eval(vars) - self.children[1].eval(vars),
            Op::Builtin(BuiltinOp::Mul) => self.children[0].eval(vars) * self.children[1].eval(vars),
            Op::Builtin(BuiltinOp::Pow) => self.children[0].eval(vars).powf(self.children[1].eval(vars)),
            Op::Builtin(BuiltinOp::Var(i)) => vars[i],
            Op::Builtin(BuiltinOp::Const(c)) => c,
            Op::Custom(custom) => {
                assert_eq!(self.children.len(), custom.arity, "arity mismatch for custom op: {}", custom.name);
                let args: Vec<f64> = self.children.iter().map(|c| c.eval(vars)).collect();
                (custom.f)(&args)
            }
        }
    }
}

fn sqrt_plus_one(args: &[f64]) -> f64 {
    (args[0].abs()).sqrt() + 1.0
}

fn custom_sqrt_plus_one() -> Op {
    Op::Custom(CustomOp {
        name: "sqrtplusone",
        arity: 1,
        f: sqrt_plus_one,
    })
}

fn main() {
    // Build tree: sqrtplusone( x0 + 1 )
    let tree = Node {
        op: custom_sqrt_plus_one(),
        children: vec![Node {
            op: Op::Builtin(BuiltinOp::Add),
            children: vec![
                Node { op: Op::Builtin(BuiltinOp::Var(0)), children: vec![] },
                Node { op: Op::Builtin(BuiltinOp::Const(1.0)), children: vec![] },
            ],
        }],
    };

    let x0 = 8.0;
    let y = tree.eval(&[x0]);

    println!("x0 = {x0}");
    println!("sqrtplusone(x0 + 1) = {y}");
    println!();
    println!("For radiate specifically:");
    println!("- If `Op` has no custom-function API, you cannot implement `impl operation for sqrtplusone`.");
    println!("- You must use a built-in extension point (if any) or modify/fork the crate.");
}
"
}

