        let mut matches: Vec<(&str, bool)> = Vec::new(); // (word, is_keyword)

        for kw in KEYWORDS {
            if kw.to_ascii_lowercase().starts_with(&prefix_lower) {
                matches.push((kw, true));
            }
        }

        for t in TABLES {
            if t.to_ascii_lowercase().starts_with(&prefix_lower) {
                matches.push((t, false));
            }
        }

        for c in COLUMNS {
            if c.to_ascii_lowercase().starts_with(&prefix_lower) {
                matches.push((c, false));
            }
        }

        let unique = matches.len() == 1;

        let pairs = matches
            .into_iter()
            .map(|(word, is_keyword)| {
                let replacement = if unique && is_keyword {
                    // Practical workaround: add a trailing space only for unique SQL keyword completion.
                    // For identifiers (table/column), do NOT add trailing space, so `book.<TAB>` flows naturally.
                    format!("{word} ")
                } else {
                    word.to_string()
                };

                Pair {
                    display: word.to_string(),
                    replacement,
                }
            })
            .collect();

        Ok((start, pairs))
    }
