// A small deterministic PRNG (SplitMix64) that works in const context.
// This is commonly used to initialize larger RNGs and is perfectly fine
// for generating fixed Zobrist keys.
const fn splitmix64_next(state: u64) -> (u64, u64) {
    let new_state = state.wrapping_add(0x9E37_79B9_7F4A_7C15);
    let mut z = new_state;
    z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
