    fn process(&mut self, input: Self::Input) -> Self::Output;
}

pub trait Sample: Copy + Clone + Add<Self, Output = Self> {
    type Float: Float;

    const CHANNELS: usize;

    fn mono(&self) -> Self::Float;
    fn gain(&self, db: Self::Float) -> Self;
}

#[derive(Copy, Clone)]
pub struct Node<P>(pub P);

impl<In: Copy, Out, P> Processor for Node<P>
where
    P: Processor<Input = In, Output = Out>,
{
    type Input = In;
    type Output = Out;

    fn prepare(&mut self, _rate: f64) {}

    fn process(&mut self, input: Self::Input) -> Self::Output {
        self.0.process(input)
    }
}

// Key change:
// Make Gain generic over the *actual stored type* (F), not over Sample (S).
// Then `Gain(32f32)` directly gives `Gain<f32>`, so inference works.
#[derive(Copy, Clone, Debug)]
pub struct Gain<F: Float + Copy>(pub F);

impl<F: Float + Copy> Processor for Gain<F> {
    type Input = F;
    type Output = F;

    fn prepare(&mut self, _rate: f64) {}

    fn process(&mut self, input: Self::Input) -> Self::Output {
        self.0 * input
    }
}

pub fn gain_node<F: Float + Copy>(db: F) -> Node<Gain<F>> {
    Node(Gain(db))
}

impl Sample for f32 {
    type Float = Self;

    const CHANNELS: usize = 1;

    fn mono(&self) -> Self::Float {
        *self
    }

    fn gain(&self, db: Self::Float) -> Self {
        *self * db
    }
}

fn main() {
