#[derive(Clone, Copy)]
struct DragBus {
    // Which point is currently being dragged, if any.
    active_id: Signal<Option<usize>>,
    // Registry: point id -> that point's local position signal.
    subscribers: Signal<HashMap<usize, Signal<Pos>>>,
}

impl DragBus {
    fn start_drag(&self, id: usize) {
        self.active_id.set(Some(id));
    }

    fn stop_drag(&self) {
        self.active_id.set(None);
    }

    fn drag_to_event(&self, evt: MouseEvent) {
