fn parse_lancedb_datetime(input: &str) -> Result<DateTime<Utc>, String> {
    // In case the DB string is returned with quotes, remove them.
    let s = input.trim().trim_matches('"');

    // LanceDB-like values shown:
    //   1970-01-01T00:00:00
    //   2025-08-02T17:35:41.409
    // (no timezone, optional fractional seconds)
    // So parse as NaiveDateTime first, then attach UTC.
    let formats = [
        "%Y-%m-%dT%H:%M:%S%.f", // with optional fraction in many chrono versions
        "%Y-%m-%dT%H:%M:%S",    // no fraction
    ];

    for fmt in formats {
        if let Ok(naive) = NaiveDateTime::parse_from_str(s, fmt) {
            return Ok(DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc));
        }
    }

    Err(format!("Could not parse datetime: {s}"))
}

