fn decode_signed_data(ci: &ContentInfo) -> Result<SignedData> {
    // First attempt: decode directly from Any (what you'd normally do)
    match ci.content.decode_as::<SignedData>() {
        Ok(sd) => Ok(sd),
        Err(first_err) => {
            // Second attempt: decode from raw inner bytes (helps with some encodings)
            SignedData::from_der(ci.content.value()).map_err(|second_err| {
                anyhow!(
                    "Could not decode SignedData.\n- decode_as::<SignedData>() error: {first_err}\n- SignedData::from_der(ci.content.value()) error: {second_err}\n\nThis usually means the payload is BER/non-canonical PKCS#7 in some section, while `cms`/`der` expects strict DER."
                )
            })
        }
    }
}

fn main() -> Result<()> {
    let input_path = env::args().nth(1).unwrap_or_else(|| "ci.der".to_string());
    let body = fs::read(&input_path)
        .with_context(|| format!("failed to read input file: {input_path}"))?;

    let ci = ContentInfo::from_der(&body).context("failed to decode outer ContentInfo")?;
    println!("Outer ContentInfo decoded successfully");
    println!("contentType OID: {}", ci.content_type);

