    let trades: Vec&lt;TradeData&gt; = trades_opt.into_iter().chain(trades_fut).map(|(_name, trade)| trade).collect();

    println!(&quot;[LOG] [Azure OPTIMIZED] Total: {} trades in {:.2} seconds&quot;, trades.len(), start.elapsed().as_secs_f32());
    Ok(trades)
}
