#[derive(Debug, Clone)]
struct Config {
    tenant_id: String,
    client_id: String,
    client_secret: String,
    account_name: String,
    container_name: String,
    prefixes: Vec<String>,
    max_concurrency: usize,
}

impl Config {
    fn from_env() -> Result<Self> {
        let tenant_id = read_required("AZURE_TENANT_ID")?;
        let client_id = read_required("AZURE_CLIENT_ID")?;
        let client_secret = read_required("AZURE_CLIENT_SECRET")?;
        let account_name = read_required("AZURE_ACCOUNT_NAME")?;
        let container_name = read_required("AZURE_CONTAINER_NAME")?;

        let prefixes = if let Ok(v) = env::var("AZURE_PREFIXES") {
            v.split(',')
                .map(|s| s.trim().to_string())
                .filter(|s| !s.is_empty())
                .collect::<Vec<_>>()
        } else {
            let mut p = Vec::new();
            if let Ok(v) = env::var("AZURE_PREFIX_OPT") {
                if !v.trim().is_empty() {
                    p.push(v);
                }
            }
            if let Ok(v) = env::var("AZURE_PREFIX_FUT") {
                if !v.trim().is_empty() {
                    p.push(v);
                }
            }
            p
        };

        let prefixes = if prefixes.is_empty() {
            vec!["".to_string()] // empty = list entire container
        } else {
            prefixes
        };

        let max_concurrency = env::var("AZURE_MAX_CONCURRENCY")
            .ok()
            .and_then(|s| s.parse::<usize>().ok())
            .filter(|n| *n > 0)
            .unwrap_or(64);

        Ok(Self {
            tenant_id,
            client_id,
            client_secret,
            account_name,
            container_name,
            prefixes,
            max_concurrency,
        })
    }
}

fn read_required(key: &str) -> Result<String> {
