async fn get_oauth_token(http: &Client, tenant_id: &str, client_id: &str, client_secret: &str) -> Result<String> {
    let token_url = format!(
        "https://login.microsoftonline.com/{}/oauth2/v2.0/token",
        tenant_id
    );

    let params = TokenRequest {
        grant_type: "client_credentials",
        client_id,
        client_secret,
        scope: "https://storage.azure.com/.default",
    };

    let response = http
        .post(token_url)
        .form(&params)
        .send()
        .await
        .context("Failed to call Azure AD token endpoint")?;

    let status = response.status();
    let body = response.text().await.unwrap_or_default();

    if !status.is_success() {
        return Err(anyhow!(
            "Token endpoint returned status {}: {}",
            status,
            body
        ));
    }

    let token: TokenResponse = serde_json::from_str(&body)
        .with_context(|| format!("Failed to parse token response body: {body}"))?;

    Ok(token.access_token)
}

async fn list_blob_names(container: Arc<ContainerClient>, prefix: String) -> Result<Vec<String>> {
    let mut names = Vec::new();

    let mut builder = container.list_blobs();
    if !prefix.is_empty() {
        builder = builder.prefix(prefix);
    }

    let mut stream = builder.into_stream();

    while let Some(page) = stream.next().await {
        let page = page.context("Failed while listing blobs")?;
        for blob in page.blobs.blobs() {
            if blob.name.ends_with(".json") {
                names.push(blob.name.clone());
            }
        }
    }

    Ok(names)
}

#[tokio::main]
async fn main() -> Result<()> {
    dotenvy::dotenv().ok();

