    let container = Arc::new(blob_service.container_client(cfg.container_name.clone()));

    let list_start = Instant::now();
    let list_results = stream::iter(cfg.prefixes.clone().into_iter().map(|prefix| {
        let container = Arc::clone(&container);
        async move {
            let p = if prefix.is_empty() { "<all>".to_string() } else { prefix.clone() };
            let started = Instant::now();
            let res = list_blob_names(container, prefix).await;
            (p, started.elapsed().as_secs_f64(), res)
        }
    }))
    .buffer_unordered(8)
    .collect::<Vec<_>>()
    .await;

    let mut blob_names = Vec::new();
    for (prefix, secs, res) in list_results {
        match res {
            Ok(mut names) => {
                println!("[TIMING] list prefix={} -> {} blobs in {:.3}s", prefix, names.len(), secs);
                blob_names.append(&mut names);
            }
            Err(e) => {
                eprintln!("[ERROR] list prefix={} failed in {:.3}s: {:#}", prefix, secs, e);
            }
        }
    }
    println!("[TIMING] listing total: {:.3}s", list_start.elapsed().as_secs_f64());
    println!("[INFO] total .json blobs queued: {}", blob_names.len());

    let download_start = Instant::now();
    let parse_fail = Arc::new(AtomicUsize::new(0));
    let download_fail = Arc::new(AtomicUsize::new(0));

    let parsed_json: Vec<Value> = stream::iter(blob_names.into_iter().map(|name| {
        let container = Arc::clone(&container);
        let parse_fail = Arc::clone(&parse_fail);
        let download_fail = Arc::clone(&download_fail);

