fn column_means(matrix: &DMatrix<f64>) -> RowDVector<f64> {
    let mut means = RowDVector::zeros(matrix.ncols());

    for j in 0..matrix.ncols() {
        let mut sum = 0.0;
        for i in 0..matrix.nrows() {
            sum += matrix[(i, j)];
        }
        means[j] = sum / matrix.nrows() as f64;
    }

    means
}

fn center_columns(matrix: &DMatrix<f64>) -> DMatrix<f64> {
    let means = column_means(matrix);
    let mut centered = matrix.clone();

    // "Broadcast" manually: subtract the j-th mean from every element in column j.
    for i in 0..centered.nrows() {
        for j in 0..centered.ncols() {
            centered[(i, j)] -= means[j];
        }
    }

    centered
}

