  "main.rs": "use anyhow::{Context, Result};
use expectrl::spawn;
use nix::fcntl::{fcntl, FcntlArg, OFlag};
use std::io::{self, Read, Write};
use std::os::fd::AsRawFd;
use std::sync::mpsc;
use std::thread;
use std::time::Duration;

fn set_nonblocking<T: AsRawFd>(io_obj: &T) -> Result<()> {
    let fd = io_obj.as_raw_fd();
    let flags = OFlag::from_bits_truncate(fcntl(fd, FcntlArg::F_GETFL)?);
    let new_flags = flags | OFlag::O_NONBLOCK;
    fcntl(fd, FcntlArg::F_SETFL(new_flags))?;
    Ok(())
}

fn main() -> Result<()> {
    // Change command as needed, e.g. "codex", "gemini", "bash -i", etc.
    let cmd = std::env::args().nth(1).unwrap_or_else(|| "bash -i".to_string());

    println!("Starting PTY command: {cmd}");
    println!("Type input and press Enter. Type /quit to exit.\n");

    let mut session = spawn(&cmd).with_context(|| format!("failed to spawn: {cmd}"))?;
    set_nonblocking(&session).context("failed to set PTY non-blocking")?;

    // Channel: UI/main thread -> PTY thread
    let (tx_in, rx_in) = mpsc::channel::<Vec<u8>>();
    // Channel: PTY thread -> UI/main thread
    let (tx_out, rx_out) = mpsc::channel::<Vec<u8>>();

    // Single owner thread for Session (no Arc<Mutex<Session>>).
    // This avoids deadlock between blocking read and write.
    let io_thread = thread::spawn(move || {
        let mut buf = [0u8; 4096];

        loop {
            // 1) Drain outgoing input and write to PTY
            while let Ok(data) = rx_in.try_recv() {
                if let Err(e) = session.write_all(&data) {
                    let _ = tx_out.send(format!("\r\n[write error: {e}]\r\n").into_bytes());
                    return;
                }
                let _ = session.flush();
            }

            // 2) Read available PTY output (non-blocking)
            match session.read(&mut buf) {
                Ok(0) => {
                    let _ = tx_out.send(b"\r\n[process terminated]\r\n".to_vec());
                    return;
                }
                Ok(n) => {
                    let _ = tx_out.send(buf[..n].to_vec());
                }
                Err(e) if e.kind() == io::ErrorKind::WouldBlock => {
                    // No output right now; continue.
                }
                Err(e) => {
                    let _ = tx_out.send(format!("\r\n[read error: {e}]\r\n").into_bytes());
                    return;
                }
            }

            thread::sleep(Duration::from_millis(10));
        }
    });

    // Printer thread (simulates Tauri event emission to frontend)
    let printer = thread::spawn(move || {
        let mut stdout = io::stdout().lock();
        while let Ok(chunk) = rx_out.recv() {
            let _ = stdout.write_all(&chunk);
            let _ = stdout.flush();
        }
    });

    // Main thread reads user input and forwards to PTY thread
    let stdin = io::stdin();
    loop {
        let mut line = String::new();
        let n = stdin.read_line(&mut line)?;
        if n == 0 {
            break;
        }

        if line.trim_end() == "/quit" {
            break;
        }

        // Typical terminal Enter should be CR (or CRLF depending on target).
        // Keep it simple: convert trailing '\n' to '\r'.
        if line.ends_with('\n') {
            line.pop();
            if line.ends_with('\r') {
                line.pop();
            }
            line.push('\r');
        }

        if tx_in.send(line.into_bytes()).is_err() {
            break;
        }
    }

    drop(tx_in);
    let _ = io_thread.join();
    let _ = printer.join();

    Ok(())
}
"
}

