#[derive(Debug)]
enum TryPollResult<X> {
    Ready(X),
    Pending,
}

// Non-async function that polls a future exactly once using the caller's Context.
fn try_poll<X, F>(future: Pin<&mut F>, cx: &mut Context<'_>) -> TryPollResult<X>
where
    F: Future<Output = X>,
{
    match future.poll(cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending,
    }
}

