    let mut immediate = Box::pin(async { 123 });

    let immediate_result = poll_fn(|cx| Poll::Ready(try_poll(immediate.as_mut(), cx))).await;
    match immediate_result {
        TryPollResult::Ready(v) => println!("immediate future was ready: {v}"),
        TryPollResult::Pending => println!("immediate future was pending"),
    }

    // Example 2: not ready on first poll, so we spawn it
    let mut delayed = Box::pin(async {
        tokio::time::sleep(Duration::from_millis(500)).await;
        "done after sleep"
    });

    let delayed_result = poll_fn(|cx| Poll::Ready(try_poll(delayed.as_mut(), cx))).await;
    match delayed_result {
        TryPollResult::Ready(v) => {
            println!("delayed future unexpectedly ready: {v}");
        }
        TryPollResult::Pending => {
            println!("delayed future is pending; spawning a task to await it...");
            let handle = tokio::spawn(async move {
                let v = delayed.await;
                println!("spawned task got result: {v}");
            });
            handle.await.unwrap();
        }
    }
}
