fn rewrite_tree(tree: UseTree, parent_is_vexide: bool) -> UseTree {
    match tree {
        UseTree::Path(mut p) => {
            let is_vexide = p.ident == "vexide";
            let child = rewrite_tree(*p.tree, is_vexide);

            // Drop the `devices` segment only when it appears directly under `vexide`.
            if parent_is_vexide && p.ident == "devices" {
                child
            } else {
                p.tree = Box::new(child);
                UseTree::Path(p)
            }
