                    UseTree::Group(inner) => {
                        for inner_item in inner.items.into_iter() {
                            out.push(inner_item);
                        }
                    }
                    other => out.push(other),
                }
            }
            g.items = out;
            UseTree::Group(g)
        }
        UseTree::Name(mut n) => {
            // `use vexide::{devices, fs};` -> `use vexide::{self, fs};`
            if parent_is_vexide && n.ident == "devices" {
                n.ident = Ident::new("self", Span::call_site());
            }
            UseTree::Name(n)
        }
        UseTree::Rename(mut r) => {
            // `use vexide::devices as d;` -> `use vexide::self as d;`
            if parent_is_vexide && r.ident == "devices" {
                r.ident = Ident::new("self", Span::call_site());
            }
            UseTree::Rename(r)
        }
        other => other,
    }
}

fn normalize_groups(tree: &mut UseTree) {
    match tree {
        UseTree::Path(p) => normalize_groups(&mut p.tree),
        UseTree::Group(g) => {
            for item in &mut g.items {
                normalize_groups(item);
            }

            // Flatten any direct nested groups that remain.
            let mut flat: Punctuated<UseTree, Comma> = Punctuated::new();
            for item in std::mem::take(&mut g.items).into_iter() {
                if let UseTree::Group(inner) = item {
                    for inner_item in inner.items.into_iter() {
                        flat.push(inner_item);
                    }
                } else {
                    flat.push(item);
                }
            }
            g.items = flat;
        }
        _ => {}
    }
}

fn parse_use_tree(src: &str) -> Option<UseTree> {
    syn::parse_str::<UseTree>(src).ok()
}
