",
  "main.rs": "use axum::{
    extract::{ws::{Message, WebSocket, WebSocketUpgrade}, Path, Request},
    http::{header::{ORIGIN, UPGRADE}, HeaderValue, Method, StatusCode},
    middleware::{self, Next},
    response::{IntoResponse, Response},
    routing::get,
    Router,
};
use tower_http::cors::CorsLayer;

const ALLOWED_ORIGIN: &str = "https://www.example.com";

#[tokio::main]
async fn main() {
    // CORS for normal HTTP requests (browser fetch/XHR).
    let cors = CorsLayer::new()
        .allow_origin(ALLOWED_ORIGIN.parse::<HeaderValue>().unwrap())
        .allow_methods([Method::GET, Method::POST])
        .allow_headers([axum::http::header::CONTENT_TYPE]);

    let app = Router::new()
        .route("/", get(|| async { "Server is running" }))
        .route(
            "/client/{session_id}",
            get(client_handler)
                // Route-specific middleware: checks Origin during WS handshake.
                .route_layer(middleware::from_fn(ws_origin_guard)),
        )
        .layer(cors);

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .expect("failed to bind listener");

    println!("listening on http://127.0.0.1:3000");
    axum::serve(listener, app)
        .await
        .expect("server error");
}

async fn ws_origin_guard(req: Request, next: Next) -> Response {
    let is_ws_upgrade = req
        .headers()
        .get(UPGRADE)
        .and_then(|v| v.to_str().ok())
        .map(|v| v.eq_ignore_ascii_case("websocket"))
        .unwrap_or(false);

    if is_ws_upgrade {
        let allowed = req
            .headers()
            .get(ORIGIN)
            .and_then(|v| v.to_str().ok())
            .map(|origin| origin == ALLOWED_ORIGIN)
            .unwrap_or(false);

        if !allowed {
            return (StatusCode::FORBIDDEN, "Forbidden: invalid Origin for websocket").into_response();
        }
    }

    next.run(req).await
}

async fn client_handler(
    ws: WebSocketUpgrade,
    Path(session_id): Path<String>,
) -> impl IntoResponse {
    ws.on_upgrade(move |socket| handle_socket(socket, session_id))
}

async fn handle_socket(mut socket: WebSocket, session_id: String) {
    // Send a greeting.
    let _ = socket
        .send(Message::Text(format!("Connected to session {session_id}").into()))
        .await;

    // Echo loop.
    while let Some(result) = socket.recv().await {
        match result {
            Ok(Message::Text(text)) => {
                let reply = format!("[{session_id}] {text}");
                if socket.send(Message::Text(reply.into())).await.is_err() {
                    break;
                }
            }
            Ok(Message::Binary(bin)) => {
                if socket.send(Message::Binary(bin)).await.is_err() {
                    break;
                }
            }
            Ok(Message::Close(_)) => break,
            Ok(_) => {}
            Err(_) => break,
        }
    }
}
"
}

