  "main.rs": "use async_trait::async_trait;
use std::sync::Arc;
use tokio::time::{sleep, Duration};
use tracing::{info, info_span, Instrument, Span};
use tracing_subscriber::{fmt::format::FmtSpan, prelude::*, EnvFilter};

#[derive(Clone)]
struct RequestCtx {
    request_id: u64,
    request_span: Span,
}

#[async_trait]
trait ProxyLifecycle: Send + Sync {
    async fn on_stage_1(self: Arc<Self>, ctx: RequestCtx);
    async fn on_stage_2(self: Arc<Self>, ctx: RequestCtx);
    async fn call_upstream(self: Arc<Self>, ctx: RequestCtx);
}

struct DemoProxy;

#[async_trait]
impl ProxyLifecycle for DemoProxy {
    async fn on_stage_1(self: Arc<Self>, ctx: RequestCtx) {
        let stage_span = info_span!(parent: &ctx.request_span, "stage_1", request_id = ctx.request_id);

        async move {
            info!("stage 1 begin");
            sleep(Duration::from_millis(80)).await;
            info!("stage 1 done");
        }
        .instrument(stage_span)
        .await;
    }

    async fn on_stage_2(self: Arc<Self>, ctx: RequestCtx) {
        let stage_span = info_span!(parent: &ctx.request_span, "stage_2", request_id = ctx.request_id);

        async move {
            info!("stage 2 begin");
            sleep(Duration::from_millis(40)).await;
            self.clone().call_upstream(ctx.clone()).await;
            info!("stage 2 done");
        }
        .instrument(stage_span)
        .await;
    }

    async fn call_upstream(self: Arc<Self>, _ctx: RequestCtx) {
        // Parent here is whatever span is currently entered (stage_2 in this demo)
        let upstream_span = info_span!("upstream");

        async move {
            info!("upstream request");
            sleep(Duration::from_millis(120)).await;
            info!("upstream response");
        }
        .instrument(upstream_span)
        .await;
    }
}

async fn handle_request(proxy: Arc<DemoProxy>, request_id: u64) {
    // Create one span for the full request lifecycle and keep it in request context.
    let request_span = info_span!("request", request_id);
    let ctx = RequestCtx {
        request_id,
        request_span: request_span.clone(),
    };

    async move {
        info!("request accepted");

        // Simulate Pingora/Tokio invoking callbacks on worker tasks/threads.
        let p1 = proxy.clone();
        let c1 = ctx.clone();
        let h1 = tokio::spawn(async move {
            p1.on_stage_1(c1).await;
        });
        h1.await.expect("stage_1 task panicked");

        let p2 = proxy.clone();
        let c2 = ctx.clone();
        let h2 = tokio::spawn(async move {
            p2.on_stage_2(c2).await;
        });
        h2.await.expect("stage_2 task panicked");

        info!("request complete");
    }
    .instrument(request_span)
    .await;
}

#[tokio::main(flavor = "multi_thread", worker_threads = 4)]
async fn main() {
    let fmt_layer = tracing_subscriber::fmt::layer()
        .with_target(false)
        .with_thread_ids(true)
        .with_span_events(FmtSpan::NEW | FmtSpan::CLOSE);

    tracing_subscriber::registry()
        .with(EnvFilter::new("info"))
        .with(fmt_layer)
        .init();

    let proxy = Arc::new(DemoProxy);
    handle_request(proxy, 42).await;
}
