use std::process::{Command, Stdio};
use std::thread;
use std::time::Duration;

fn main() -> Result<(), Box<dyn Error>> {
    if env::args().any(|a| a == "--child") {
        return run_child();
    }
    run_parent()
}

fn run_parent() -> Result<(), Box<dyn Error>> {
    let exe = env::current_exe()?;

    let mut child = Command::new(exe)
        .arg("--child")
        .stdin(Stdio::piped())
        .stdout(Stdio::piped())
        .stderr(Stdio::inherit())
        .spawn()?;

    let mut child_stdin = child.stdin.take().ok_or("failed to open child stdin")?;
    let child_stdout = child.stdout.take().ok_or("failed to open child stdout")?;

    let mut rl = DefaultEditor::new()?;
    let mut printer = rl.create_external_printer()?;

    thread::spawn(move || {
        let reader = BufReader::new(child_stdout);
        for line in reader.lines() {
            match line {
                Ok(l) => {
                    let _ = printer.print(format!("[child] {l}"));
                }
                Err(_) => break,
            }
        }
        let _ = printer.print("[child] <stdout closed>".to_string());
    });

    println!("Type anything to send it to child. Type 'exit' to quit.");

    loop {
        match rl.readline("> ") {
            Ok(line) => {
                let input = line.trim_end().to_string();
                let _ = rl.add_history_entry(input.as_str());

                writeln!(child_stdin, "{input}")?;
                child_stdin.flush()?;

                if input == "exit" {
                    break;
                }
            }
            Err(ReadlineError::Interrupted) => {
                println!("^C");
                continue;
            }
            Err(ReadlineError::Eof) => {
                println!("^D");
                break;
            }
            Err(err) => {
                eprintln!("readline error: {err}");
                break;
            }
        }
    }

    let _ = child.kill();
    let _ = child.wait();
    Ok(())
}

fn run_child() -> Result<(), Box<dyn Error>> {
    // Background periodic output to simulate asynchronous child-process logs/events.
    thread::spawn(|| {
        let mut n = 1u64;
        loop {
            thread::sleep(Duration::from_secs(2));
            println!("async event #{n}");
            let _ = io::stdout().flush();
            n += 1;
        }
    });

    let stdin = io::stdin();
    let mut reader = BufReader::new(stdin.lock());
    let mut line = String::new();

    loop {
        line.clear();
        let bytes = reader.read_line(&mut line)?;
        if bytes == 0 {
            break;
        }

        let cmd = line.trim_end();
        if cmd == "exit" {
            println!("bye from child");
            io::stdout().flush()?;
            break;
        }

        println!("echo: {cmd}");
        io::stdout().flush()?;
    }

    Ok(())
}
"
}

