    Title { title: Vec<RichTextObject> },
    Url { url: String },
    MultiSelect { multi_select: Vec<SelectObject> },
}

macro_rules! notion_prop_insert {
    ($map:ident, $self:ident, $field:ident, "title", $pname:literal) => {{
        $map.insert(
            $pname.to_string(),
            PropertyValue::Title {
                title: vec![RichTextObject {
                    annotations: None,
                    data_type: Some("text".to_string()),
                    equation: None,
                    mention: None,
                    plain_text: None,
                    href: None,
                    text: TextObject {
