        if let Some(value) = $self.$field.clone() {
            $map.insert($pname.to_string(), PropertyValue::Url { url: value });
        }
    }};

    ($map:ident, $self:ident, $field:ident, "MultiSelect", $pname:literal) => {{
        if let Some(values) = &$self.$field {
            let multi = values
                .iter()
                .map(|v| SelectObject {
                    id: None,
                    color: None,
                    name: match v {
                        Value::String(s) => s.clone(),
                        _ => v.to_string(),
                    },
                })
                .collect::<Vec<_>>();

            $map.insert(
                $pname.to_string(),
                PropertyValue::MultiSelect { multi_select: multi },
