        }
    }};

    ($map:ident, $self:ident, $field:ident, $unknown:literal, $pname:literal) => {
        compile_error!("Unsupported notion_property type. Add a new notion_prop_insert! arm.");
    };
}

macro_rules! notion_struct {
    (
        $(#[$meta:meta])*
        $svis:vis struct $name:ident {
