fn find_python_interpreter() -> Option<String> {
    // Allow override via env var.
    if let Ok(py) = env::var("PYTHON") {
        if command_works(&py) {
            return Some(py);
        }
    }

    // Common interpreter names across platforms.
    let candidates = ["python3", "python", "py"];
    for c in candidates {
        if command_works(c) {
            return Some(c.to_string());
        }
    }
    None
}

fn command_works(cmd: &str) -> bool {
    Command::new(cmd)
        .arg("--version")
        .stdout(Stdio::null())
        .stderr(Stdio::null())
        .status()
        .map(|s| s.success())
        .unwrap_or(false)
}

