    let mut path = env::temp_dir();
    let pid = std::process::id();
    let ts = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_millis();

    path.push(format!("rust_program_script_{}_{}.py", pid, ts));
    fs::write(&path, PYTHON_SCRIPT)?;
    Ok(path)
}

