  "main.rs": "use core::sync::atomic::{AtomicUsize, Ordering};
use std::sync::Arc;
use std::thread;

/// Replacement for `fetch_add(1, Ordering::Relaxed)` using a critical section.
///
/// Important points:
/// - `load/store` use `Relaxed` because the original operation was Relaxed.
/// - Atomicity is provided by `critical_section::with(...)` (mutual exclusion).
/// - `wrapping_add` matches atomic fetch_add overflow behavior.
fn fetch_add_via_critical_section(counter: &AtomicUsize) -> usize {
    critical_section::with(|_| {
        let old = counter.load(Ordering::Relaxed);
        counter.store(old.wrapping_add(1), Ordering::Relaxed);
        old
    })
}

fn main() {
    let counter = Arc::new(AtomicUsize::new(0));

    let threads = 8;
    let per_thread = 10_000;

    let mut handles = Vec::new();
    for _ in 0..threads {
        let c = Arc::clone(&counter);
        handles.push(thread::spawn(move || {
            for _ in 0..per_thread {
                let _ = fetch_add_via_critical_section(&c);
            }
        }));
    }

    for h in handles {
        h.join().unwrap();
    }

    let final_value = counter.load(Ordering::Relaxed);
    let expected = threads * per_thread;

    println!("final counter = {final_value}, expected = {expected}");
    assert_eq!(final_value, expected);
    println!("OK");
}
"
}

