                        let _ = msg_tx.send(Message::QuitRequested("keyboard"));
                    }
                    KeyCode::Esc => {
                        let _ = msg_tx.send(Message::QuitRequested("keyboard(esc)"));
                    }
                    KeyCode::Char(c) => {
                        let _ = msg_tx.send(Message::Key(c));
