const BYTES_PER_PIXEL: usize = 4;

/// Flips one line of RGBA (4-byte) pixels in place.
///
/// This uses 32-bit unaligned loads/stores so each pixel swap is done as one
/// 4-byte value instead of 4 separate byte swaps.
fn flip_line(line_bytes: &mut [u8]) {
    assert_eq!(line_bytes.len() % BYTES_PER_PIXEL, 0, "line length must be multiple of 4");

    let pixels = line_bytes.len() / BYTES_PER_PIXEL;
    if pixels <= 1 {
        return;
    }

    let mut i = 0usize;
    let mut j = pixels - 1;

    while i < j {
        let li = i * BYTES_PER_PIXEL;
        let rj = j * BYTES_PER_PIXEL;

        unsafe {
            let lptr = line_bytes.as_mut_ptr().add(li) as *mut u32;
            let rptr = line_bytes.as_mut_ptr().add(rj) as *mut u32;

            let lv = std::ptr::read_unaligned(lptr);
            let rv = std::ptr::read_unaligned(rptr);
