fn resolve_path_list(source: PathListSource, current_file: &Path) -> Result<Vec<PathBuf>, Box<dyn Error>> {
    match source {
        PathListSource::Direct(v) => Ok(v),
        PathListSource::Ref(r) => resolve_ref(&r.reference, current_file),
    }
