fn resolve_ref(reference: &str, current_file: &Path) -> Result<Vec<PathBuf>, Box<dyn Error>> {
    let (file_part, pointer_part) = reference
        .split_once('#')
        .ok_or("$ref must look like './file.json#/json/pointer'")?;

    let base_dir = current_file.parent().unwrap_or(Path::new("."));
