    let root: Value = serde_json::from_str(&text)?;

    let pointer = if pointer_part.is_empty() { "" } else { pointer_part };

    let target = root
        .pointer(pointer)
        .ok_or_else(|| format!("JSON pointer '{pointer}' not found in {}", target_file.display()))?;

    let paths: Vec<PathBuf> = serde_json::from_value(target.clone())?;
    Ok(paths)
