edition = "2021"

[dependencies]
bevy = "0.14"
thiserror = "1"
",
  "main.rs": "use bevy::asset::{io::Reader, AssetLoader, AsyncReadExt, LoadContext};
use bevy::prelude::*;
use bevy::render::render_asset::RenderAssetUsages;
use bevy::render::render_resource::{Extent3d, TextureDimension, TextureFormat};
use std::collections::HashMap;
use std::fs::{self, File};
use std::io::{Read, Seek, SeekFrom, Write};
use std::path::{Path, PathBuf};
use thiserror::Error;

#[derive(Debug, Clone)]
struct PackEntry {
    width: u16,
    height: u16,
    offset: u64,
    len: u32,
}

#[derive(Asset, TypePath, Debug)]
struct PackIndex {
    relative_path: String,
    entries: HashMap<String, PackEntry>,
}

#[derive(Default)]
struct PackIndexLoader;

#[derive(Debug, Error)]
enum PackLoaderError {
    #[error("io error: {0}")]
    Io(#[from] std::io::Error),
    #[error("invalid pack magic, expected LPK1")]
    InvalidMagic,
    #[error("invalid utf-8 in entry name: {0}")]
    Utf8(#[from] std::string::FromUtf8Error),
}

impl AssetLoader for PackIndexLoader {
    type Asset = PackIndex;
    type Settings = ();
    type Error = PackLoaderError;

    async fn load(
        &self,
        reader: &mut dyn Reader,
        _settings: &Self::Settings,
        load_context: &mut LoadContext<'_>,
    ) -> Result<Self::Asset, Self::Error> {
        let mut magic = [0_u8; 4];
        reader.read_exact(&mut magic).await?;
        if &magic != b"LPK1" {
            return Err(PackLoaderError::InvalidMagic);
        }

        let count = read_u32(reader).await?;
        let mut entries = HashMap::with_capacity(count as usize);

        for _ in 0..count {
            let name_len = read_u16(reader).await? as usize;
            let mut name_bytes = vec![0_u8; name_len];
            reader.read_exact(&mut name_bytes).await?;
            let name = String::from_utf8(name_bytes)?;

            let width = read_u16(reader).await?;
            let height = read_u16(reader).await?;
            let offset = read_u64(reader).await?;
            let len = read_u32(reader).await?;

            entries.insert(
                name,
                PackEntry {
                    width,
                    height,
                    offset,
                    len,
                },
            );
        }

        let relative_path = load_context
            .path()
            .path()
            .to_string_lossy()
            .replace('\\', "/");

        Ok(PackIndex {
            relative_path,
            entries,
        })
    }

    fn extensions(&self) -> &[&str] {
        &["lpk"]
    }
}

#[derive(Resource)]
struct AssetsRoot(PathBuf);

#[derive(Resource)]
struct DemoState {
    pack: Handle<PackIndex>,
    names: Vec<String>,
    next: usize,
    cache: HashMap<String, Handle<Image>>,
}

#[derive(Component)]
struct DemoSprite;

#[derive(Debug, Error)]
enum PackReadError {
    #[error("entry '{0}' was not found in pack")]
    MissingEntry(String),
    #[error("io error: {0}")]
    Io(#[from] std::io::Error),
}

fn main() {
    let assets_folder = "assets";
    let assets_root = std::env::current_dir().unwrap().join(assets_folder);

    App::new()
        .insert_resource(AssetsRoot(assets_root))
        .add_plugins(DefaultPlugins.set(AssetPlugin {
            file_path: assets_folder.into(),
            ..default()
        }))
        .init_asset::<PackIndex>()
        .init_asset_loader::<PackIndexLoader>()
        .add_systems(Startup, setup)
        .add_systems(Update, (announce_ready, cycle_textures))
        .run();
}

fn setup(mut commands: Commands, asset_server: Res<AssetServer>, root: Res<AssetsRoot>) {
    let pack_path = root.0.join("demo.lpk");
    if let Err(e) = create_demo_pack(&pack_path, 64) {
        error!("Failed to create demo pack: {e}");
    }

    let pack: Handle<PackIndex> = asset_server.load("demo.lpk");

    commands.insert_resource(DemoState {
        pack,
        names: Vec::new(),
        next: 0,
        cache: HashMap::new(),
    });

    commands.spawn(Camera2dBundle::default());
}

fn announce_ready(mut once: Local<bool>, state: Res<DemoState>, packs: Res<Assets<PackIndex>>) {
    if *once {
        return;
    }

    if let Some(pack) = packs.get(&state.pack) {
        *once = true;
        info!(
            "Pack index loaded ({} entries). Press SPACE to lazy-load next texture.",
            pack.entries.len()
        );
    }
}

fn cycle_textures(
    keyboard: Res<ButtonInput<KeyCode>>,
    mut commands: Commands,
    mut state: ResMut<DemoState>,
    packs: Res<Assets<PackIndex>>,
    root: Res<AssetsRoot>,
    mut images: ResMut<Assets<Image>>,
    mut sprite_query: Query<&mut Handle<Image>, With<DemoSprite>>,
) {
    if !keyboard.just_pressed(KeyCode::Space) {
        return;
    }

    let Some(pack) = packs.get(&state.pack) else {
        info!("Pack not loaded yet...");
        return;
    };

    if state.names.is_empty() {
        state.names = pack.entries.keys().cloned().collect();
        state.names.sort();
    }

    if state.names.is_empty() {
        return;
    }

    let name = state.names[state.next % state.names.len()].clone();
    state.next += 1;

    let handle = if let Some(existing) = state.cache.get(&name) {
        existing.clone()
    } else {
        match lazy_load_image(pack, &name, &root.0, &mut images) {
            Ok(h) => {
                state.cache.insert(name.clone(), h.clone());
                h
            }
            Err(e) => {
                error!("Could not load '{name}' lazily: {e}");
                return;
            }
        }
    };

    if let Ok(mut tex) = sprite_query.get_single_mut() {
        *tex = handle;
    } else {
        commands.spawn((
            SpriteBundle {
                texture: handle,
                transform: Transform::from_scale(Vec3::splat(8.0)),
                ..default()
            },
            DemoSprite,
        ));
    }

    info!("Showing {name}");
}

fn lazy_load_image(
    pack: &PackIndex,
    entry_name: &str,
    assets_root: &Path,
    images: &mut Assets<Image>,
) -> Result<Handle<Image>, PackReadError> {
    let entry = pack
        .entries
        .get(entry_name)
        .ok_or_else(|| PackReadError::MissingEntry(entry_name.to_string()))?;

    let full_path = assets_root.join(&pack.relative_path);
    let mut file = File::open(full_path)?;
    file.seek(SeekFrom::Start(entry.offset))?;

    let mut data = vec![0_u8; entry.len as usize];
    file.read_exact(&mut data)?;

    let image = Image::new(
        Extent3d {
            width: entry.width as u32,
            height: entry.height as u32,
            depth_or_array_layers: 1,
        },
        TextureDimension::D2,
        data,
        TextureFormat::Rgba8UnormSrgb,
        RenderAssetUsages::default(),
    );

    Ok(images.add(image))
}

fn create_demo_pack(path: &Path, texture_count: usize) -> std::io::Result<()> {
    if path.exists() {
        return Ok(());
    }

    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent)?;
    }

    let mut textures: Vec<(String, u16, u16, Vec<u8>)> = Vec::with_capacity(texture_count);

    for i in 0..texture_count {
        let name = format!("texture_{i:04}");
        let w = 32_u16;
        let h = 32_u16;
        let mut data = vec![0_u8; w as usize * h as usize * 4];

        for y in 0..h {
            for x in 0..w {
                let idx = ((y as usize * w as usize + x as usize) * 4) as usize;
                let checker = ((x / 4 + y / 4) % 2) as u8;
                let r = ((i * 53) % 255) as u8;
                let g = ((i * 97) % 255) as u8;
                let b = if checker == 0 { 40 } else { 220 };

                data[idx] = r;
                data[idx + 1] = g;
                data[idx + 2] = b;
                data[idx + 3] = 255;
            }
        }

        textures.push((name, w, h, data));
    }

    let mut directory_size = 0_usize;
    for (name, _, _, _) in &textures {
        directory_size += 2 + name.len() + 2 + 2 + 8 + 4;
    }

    let mut payload_offset = (4 + 4 + directory_size) as u64;

    let mut out = File::create(path)?;
    out.write_all(b"LPK1")?;
    write_u32(&mut out, textures.len() as u32)?;

    for (name, w, h, data) in &textures {
        write_u16(&mut out, name.len() as u16)?;
        out.write_all(name.as_bytes())?;
        write_u16(&mut out, *w)?;
        write_u16(&mut out, *h)?;
        write_u64(&mut out, payload_offset)?;
        write_u32(&mut out, data.len() as u32)?;
        payload_offset += data.len() as u64;
    }

    for (_, _, _, data) in &textures {
        out.write_all(data)?;
    }

    Ok(())
}

async fn read_u16(reader: &mut dyn Reader) -> Result<u16, std::io::Error> {
    let mut bytes = [0_u8; 2];
    reader.read_exact(&mut bytes).await?;
    Ok(u16::from_le_bytes(bytes))
}

async fn read_u32(reader: &mut dyn Reader) -> Result<u32, std::io::Error> {
    let mut bytes = [0_u8; 4];
    reader.read_exact(&mut bytes).await?;
    Ok(u32::from_le_bytes(bytes))
}

async fn read_u64(reader: &mut dyn Reader) -> Result<u64, std::io::Error> {
    let mut bytes = [0_u8; 8];
    reader.read_exact(&mut bytes).await?;
    Ok(u64::from_le_bytes(bytes))
}

fn write_u16(writer: &mut dyn Write, v: u16) -> std::io::Result<()> {
    writer.write_all(&v.to_le_bytes())
}

fn write_u32(writer: &mut dyn Write, v: u32) -> std::io::Result<()> {
    writer.write_all(&v.to_le_bytes())
}

fn write_u64(writer: &mut dyn Write, v: u64) -> std::io::Result<()> {
    writer.write_all(&v.to_le_bytes())
}
"
