const FILE_PATH: &str = "output.json";

type DynResult<T> = Result<T, Box<dyn Error>>;

fn load_or_create(path: &str) -> DynResult<Vec<String>> {
    match fs::read_to_string(path) {
        Ok(content) => {
            let trimmed = content.trim();
            if trimmed.is_empty() {
                Ok(Vec::new())
            } else {
                let todos: Vec<String> = serde_json::from_str(trimmed)?;
                Ok(todos)
            }
