        Err(err) if err.kind() == ErrorKind::NotFound => {
            fs::write(path, "[]")?;
            Ok(Vec::new())
        }
        Err(err) => Err(Box::new(err)),
    }
}

fn save(path: &str, todos: &[String]) -> DynResult<()> {
    let json = serde_json::to_string_pretty(todos)?;
    fs::write(path, json)?;
    Ok(())
