name = "quote_aware_tokenizer"
version = "0.1.0"
edition = "2021"

[dependencies]
",
  "main.rs": "use std::io::{self, Read};

fn is_shell_whitespace(c: char) -> bool {
    matches!(c, ' ' | '\t' | '\n')
}

/// Split a command line into tokens, honoring single quotes.
///
/// This intentionally implements a small, focused subset of shell parsing:
/// - single quotes preserve all characters literally until the next single quote
/// - whitespace outside quotes separates tokens
/// - quoted and unquoted segments next to each other are concatenated into one token
///
/// Example:
///   one  ' two  'three    four
/// -> ["one", " two  three", "four"]
fn split_shell_words(input: &str) -> Result<Vec<String>, String> {
    let mut tokens = Vec::new();
    let mut current = String::new();
    let mut in_single_quotes = false;

    for (idx, ch) in input.char_indices() {
        if in_single_quotes {
            if ch == '\'' {
                in_single_quotes = false;
            } else {
                current.push(ch);
            }
        } else {
            match ch {
                '\'' => in_single_quotes = true,
                c if is_shell_whitespace(c) => {
                    if !current.is_empty() {
                        tokens.push(std::mem::take(&mut current));
                    }
                }
                _ => current.push(ch),
            }
        }

        // idx is currently only used for helpful errors at end
        let _ = idx;
    }

    if in_single_quotes {
        return Err("Unterminated single quote in input".to_string());
    }

    if !current.is_empty() {
        tokens.push(current);
    }

    Ok(tokens)
}

fn main() {
    // Read from stdin. If nothing is piped/typed, use the example.
    let mut buf = String::new();
    io::stdin().read_to_string(&mut buf).unwrap();

    let input = if buf.is_empty() {
        " one  ' two  'three    four".to_string()
    } else {
        // Remove one trailing line ending (common when pressing Enter),
        // while preserving leading/internal spaces.
        let s = buf.strip_suffix("\r\n").unwrap_or(&buf);
        let s = s.strip_suffix('\n').unwrap_or(s);
        s.to_string()
    };

    match split_shell_words(&input) {
        Ok(tokens) => {
            println!("{} args:", tokens.len());
            for t in tokens {
                println!("<{}>", t);
            }
        }
        Err(e) => {
            eprintln!("error: {e}");
            std::process::exit(1);
        }
    }
}
"
}

