  "main.rs": "use serde::Deserialize;
use self_cell::self_cell;
use tokio::sync::mpsc;

#[derive(Debug, Deserialize)]
struct MyData<'a> {
    data: &'a str,
    more_data: &'a str,
}

// Self-referential container:
// - owner: owns the JSON String
// - dependent: deserialized struct borrowing from owner
self_cell!(
    struct ParsedPayload {
        owner: String,

        #[covariant]
        dependent: MyData,
    }
);

fn parse_once(raw_json: String) -> Result<ParsedPayload, serde_json::Error> {
    ParsedPayload::try_new(raw_json, |s| serde_json::from_str::<MyData>(s))
}

#[tokio::main(flavor = "multi_thread")]
async fn main() {
    let (raw_tx, mut raw_rx) = mpsc::channel::<String>(16);
    let (parsed_tx, mut parsed_rx) = mpsc::channel::<ParsedPayload>(16);

    // Producer task: simulates incoming JSON payloads.
    let producer = tokio::spawn(async move {
        for i in 0..5 {
            let msg = format!(
                "{{\"data\":\"hello-{i}\",\"more_data\":\"world-{i}\"}}"
            );
            if raw_tx.send(msg).await.is_err() {
                break;
            }
        }
    });

    // Parser task: deserialize once into borrowed struct tied to owned String.
    let parser = tokio::spawn(async move {
        while let Some(raw) = raw_rx.recv().await {
            match parse_once(raw) {
                Ok(parsed) => {
                    if parsed_tx.send(parsed).await.is_err() {
                        break;
                    }
                }
                Err(e) => {
                    eprintln!("parse error: {e}");
                }
            }
        }
    });

    // Worker task: each ParsedPayload is moved into a spawned task (no cloning of payload).
    let worker = tokio::spawn(async move {
        let mut handles = Vec::new();

        while let Some(parsed) = parsed_rx.recv().await {
            let h = tokio::spawn(async move {
                // Borrow from the self-referential container.
                let d = parsed.borrow_dependent();
                println!("processed -> data='{}', more_data='{}'", d.data, d.more_data);
            });
            handles.push(h);
        }

        for h in handles {
            let _ = h.await;
        }
    });

    let _ = producer.await;
    let _ = parser.await;
    let _ = worker.await;
}
