struct EventSender {
    shared: Arc<Shared>,
}

impl EventSender {
    fn send(&self, event: Event) -> Result<(), SendError> {
        let guard = self.shared.tx.lock().unwrap();
        let tx = guard.as_ref().ok_or(SendError::Closed)?;

