type Type = LocalBoxedObservableClone<'static, bool, Infallible>;

#[derive(Clone)]
struct Dispatcher {
    inner: Rc<RefCell<DispatcherInner>>,
}

struct DispatcherInner {
    running: bool,
    queue: VecDeque<Box<dyn FnOnce()>>,
}

impl Dispatcher {
    fn new() -> Self {
        Self {
            inner: Rc::new(RefCell::new(DispatcherInner {
                running: false,
                queue: VecDeque::new(),
            })),
        }
    }

    fn schedule<F>(&self, f: F)
    where
        F: FnOnce() + 'static,
    {
        {
            let mut inner = self.inner.borrow_mut();
            inner.queue.push_back(Box::new(f));
            if inner.running {
                return;
            }
            inner.running = true;
        }

        loop {
            let next_job = {
                let mut inner = self.inner.borrow_mut();
                inner.queue.pop_front()
            };

            match next_job {
                Some(job) => job(),
                None => {
                    self.inner.borrow_mut().running = false;
                    break;
                }
            }
        }
    }
