impl<T> Array<T> {
    fn new(dims: Vec<usize>, store: Vec<T>) -> Self {
        let expected_len = dims.iter().product::<usize>();
        assert!(
            expected_len == store.len(),
            "store length {} does not match dims product {}",
            store.len(),
            expected_len
        );
        Self { store, dims }
