    fn dims(&self) -> &[usize] {
        &self.dims
    }

    fn cartesian_to_linear(&self, idx: &[usize]) -> usize {
        assert!(idx.len() == self.dims.len(), "rank mismatch");
        let mut linear = 0usize;
        for (&i, &dim) in idx.iter().zip(self.dims.iter()) {
            assert!(i < dim, "index out of bounds: {i} >= {dim}");
            linear = linear * dim + i;
        }
        linear
    }

    fn linear_to_cartesian_with_dims(mut linear: usize, dims: &[usize]) -> Vec<usize> {
        let mut out = vec![0; dims.len()];
        for d in (0..dims.len()).rev() {
            let dim = dims[d];
            out[d] = linear % dim;
            linear /= dim;
        }
        out
    }

    fn selection_to_linear_indices(&self, selection: &[Vec<usize>]) -> Vec<usize> {
        assert!(
            selection.len() == self.dims.len(),
            "selection rank mismatch"
        );
        for (axis, (sel, &dim)) in selection.iter().zip(self.dims.iter()).enumerate() {
            assert!(!sel.is_empty(), "selection axis {axis} is empty");
            for &v in sel {
                assert!(v < dim, "selection index {v} out of bounds on axis {axis}");
            }
        }

        // Cartesian product over per-axis selections.
        let mut result = Vec::new();
        let mut current = vec![0usize; selection.len()];
        fn rec<T>(
            arr: &Array<T>,
            selection: &[Vec<usize>],
            axis: usize,
            current: &mut [usize],
            out: &mut Vec<usize>,
        ) {
            if axis == selection.len() {
                out.push(arr.cartesian_to_linear(current));
                return;
            }
            for &v in &selection[axis] {
                current[axis] = v;
                rec(arr, selection, axis + 1, current, out);
            }
        }
        rec(self, selection, 0, &mut current, &mut result);
        result
    }

    fn iter_view<'a>(&'a self, selection: Vec<Vec<usize>>) -> ArrayIter<'a, T> {
        let linear_indices = self.selection_to_linear_indices(&selection);
        ArrayIter {
            array: self,
            dims: self.dims.clone(),
            linear_indices,
            pos: 0,
        }
    }

    fn iter_view_mut<'a>(&'a mut self, selection: Vec<Vec<usize>>) -> ArrayIterMut<'a, T> {
        let linear_indices = self.selection_to_linear_indices(&selection);

        // Safety invariant for mutable iterator: no repeated indices.
        let mut seen = HashSet::new();
        for &lin in &linear_indices {
            assert!(
                seen.insert(lin),
                "mutable view has duplicate index (linear={lin}); cannot safely yield &mut references"
            );
        }

        ArrayIterMut {
            ptr: self.store.as_mut_ptr(),
            dims: self.dims.clone(),
            linear_indices,
            pos: 0,
            _marker: PhantomData,
        }
    }
