        let &lin = self.linear_indices.get(self.pos)?;
        self.pos += 1;
        let cart = Array::<T>::linear_to_cartesian_with_dims(lin, &self.dims);
        Some((cart, &self.array.store[lin]))
    }
}

struct ArrayIterMut<'a, T> {
    ptr: *mut T,
    dims: Vec<usize>,
