use std::ffi::CString;
use std::io::{self, Write};
use std::os::fd::RawFd;
use std::ptr;
use std::sync::{
    atomic::{AtomicBool, Ordering},
    Arc,
};
use std::thread::sleep;
use std::time::{Duration, Instant, SystemTime, UNIX_EPOCH};

struct ShmBuffer {
    name: CString,
    fd: RawFd,
    ptr: *mut u8,
    len: usize,
}

impl ShmBuffer {
    fn new(len: usize) -> io::Result<Self> {
        let pid = std::process::id();

        let mut fd = -1;
        let mut name = None;

        for attempt in 0..32u32 {
            let nanos = SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .unwrap_or_default()
                .as_nanos();
            let candidate = format!("/kitty-rs-shm-{}-{}-{}", pid, nanos, attempt);
            let cname = CString::new(candidate).expect("valid shm name");

            let created_fd = unsafe {
                libc::shm_open(
                    cname.as_ptr(),
                    libc::O_CREAT | libc::O_EXCL | libc::O_RDWR,
                    0o600,
                )
            };

            if created_fd >= 0 {
                fd = created_fd;
                name = Some(cname);
                break;
            }

            let err = io::Error::last_os_error();
            if err.raw_os_error() != Some(libc::EEXIST) {
                return Err(err);
            }
        }

        if fd < 0 {
            return Err(io::Error::new(
                io::ErrorKind::AlreadyExists,
                "failed to create unique shm object",
            ));
        }

        if unsafe { libc::ftruncate(fd, len as libc::off_t) } != 0 {
            let e = io::Error::last_os_error();
            unsafe { libc::close(fd) };
            if let Some(n) = name.as_ref() {
                unsafe { libc::shm_unlink(n.as_ptr()) };
            }
            return Err(e);
        }

        let mapped = unsafe {
            libc::mmap(
                ptr::null_mut(),
                len,
                libc::PROT_READ | libc::PROT_WRITE,
                libc::MAP_SHARED,
                fd,
                0,
            )
        };

        if mapped == libc::MAP_FAILED {
            let e = io::Error::last_os_error();
            unsafe { libc::close(fd) };
            if let Some(n) = name.as_ref() {
                unsafe { libc::shm_unlink(n.as_ptr()) };
            }
            return Err(e);
        }

        Ok(Self {
            name: name.expect("name set"),
            fd,
            ptr: mapped as *mut u8,
            len,
        })
    }

    fn as_mut_slice(&mut self) -> &mut [u8] {
        unsafe { std::slice::from_raw_parts_mut(self.ptr, self.len) }
    }

    fn name_str(&self) -> &str {
        self.name.to_str().expect("utf8 shm name")
    }
}

impl Drop for ShmBuffer {
    fn drop(&mut self) {
        unsafe {
            libc::munmap(self.ptr as *mut libc::c_void, self.len);
            libc::close(self.fd);
            libc::shm_unlink(self.name.as_ptr());
        }
    }
}

fn fill_gradient_rgb24(buf: &mut [u8], width: usize, height: usize, t: f32) {
    let mut i = 0usize;
    for y in 0..height {
        let fy = y as f32 / height as f32;
        for x in 0..width {
            let fx = x as f32 / width as f32;

            let r = ((fx * std::f32::consts::PI + t).sin() * 0.5 + 0.5) * 255.0;
            let g = ((fy * std::f32::consts::PI + t * 1.3).sin() * 0.5 + 0.5) * 255.0;
            let b = (((fx + fy) * std::f32::consts::PI + t * 0.7).sin() * 0.5 + 0.5) * 255.0;

            buf[i] = r as u8;
            buf[i + 1] = g as u8;
            buf[i + 2] = b as u8;
            i += 3;
        }
    }
}

fn send_kitty_frame_from_shm<W: Write>(
    out: &mut W,
    shm_name: &str,
    width: usize,
    height: usize,
    image_id: u32,
) -> io::Result<()> {
    // Payload is still base64, but now it's only the shm object name, not raw pixels.
    let payload = STANDARD.encode(shm_name.as_bytes());

    // a=T : transmit and display
    // t=s : shared memory transmission medium
    // f=24: RGB24
    // s,v  : image width/height in pixels
    // i    : image id (reuse same id each frame)
    // q=2  : do not send responses unless errors
    write!(
        out,
        "\x1b_Ga=T,t=s,f=24,s={},v={},i={},q=2;{}\x1b\\",
        width, height, image_id, payload
    )?;
    Ok(())
}

fn main() -> io::Result<()> {
    let (w, h) = termion::terminal_size_pixels().unwrap_or((1280, 720));
    let (width, height) = (w as usize, h as usize);

    let mut shm = ShmBuffer::new(width * height * 3)?;
    let shm_name = shm.name_str().to_string();

    let running = Arc::new(AtomicBool::new(true));
    {
        let r = running.clone();
        ctrlc::set_handler(move || {
            r.store(false, Ordering::SeqCst);
        })
        .expect("failed to set Ctrl-C handler");
    }

    let stdout = io::stdout();
    let mut out = stdout.lock();

    // Hide cursor, clear screen, move home.
    write!(out, "\x1b[?25l\x1b[2J\x1b[H")?;
    out.flush()?;

    let frame_budget = Duration::from_nanos(1_000_000_000 / 60);
    let mut t = 0.0f32;
    let image_id = 1u32;

    while running.load(Ordering::SeqCst) {
        let start = Instant::now();

        fill_gradient_rgb24(shm.as_mut_slice(), width, height, t);

        // Keep drawing at top-left.
        write!(out, "\x1b[H")?;
        send_kitty_frame_from_shm(&mut out, &shm_name, width, height, image_id)?;
        out.flush()?;

        t += 0.08;

        let elapsed = start.elapsed();
        if elapsed < frame_budget {
            sleep(frame_budget - elapsed);
        }
    }

    // Show cursor again when exiting.
    write!(out, "\x1b[?25h\n")?;
    out.flush()?;

    Ok(())
}
