    fn pow() -> Self {
        Self::Pow
    }
    fn var(i: usize) -> Self {
        Self::Var(i)
    }
    fn constant(c: f64) -> Self {
        Self::Const(c)
    }
    fn custom(name: &'static str, arity: usize, f: fn(&[f64]) -> f64) -> Self {
        Self::Custom { name, arity, f }
    }

