    fn handle(
        &self,
        _event: &Event,
        _count: RepeatCount,
        _positive: bool,
        context: &EventContext,
    ) -> Option<Cmd> {
        let pos = context.pos();
        let line = context.line();
        let left = &line[..pos];

        if let Some(last_non_ws) = left.rfind(|c: char| !c.is_whitespace()) {
            let ws_count = pos.saturating_sub(last_non_ws + 1);
            if ws_count > 0 {
