type FlusterResult<T> = Result<T, FlusterError>;

/// Parse LanceDB-style datetime strings such as:
/// - 1970-01-01T00:00:00
/// - 2025-08-02T17:35:41.409
/// Also accepts RFC3339 if timezone is present.
fn parse_lancedb_datetime(input: &str) -> FlusterResult<DateTime<Utc>> {
    // If the string has timezone info (e.g. Z or +00:00), this works directly.
    if let Ok(dt) = DateTime::parse_from_rfc3339(input) {
        return Ok(dt.with_timezone(&Utc));
    }

    // LanceDB values in your example are "naive" (no timezone),
    // so parse as NaiveDateTime and treat as UTC.
    let formats = [
        "%Y-%m-%dT%H:%M:%S%.f", // with optional fractional seconds
        "%Y-%m-%dT%H:%M:%S",    // without fractional seconds
    ];

    for fmt in formats {
        if let Ok(naive) = NaiveDateTime::parse_from_str(input, fmt) {
            let utc_dt = DateTime::<Utc>::from_naive_utc_and_offset(naive, Utc);
            return Ok(utc_dt);
        }
    }

    Err(FlusterError::FailToParseDate(input.to_string()))
}

/// Convert to unix timestamp in milliseconds.
