  "main.rs": "use futures::task::noop_waker;
use std::future::Future;
use std::pin::Pin;
use std::task::{Context, Poll};
use tokio::time::{sleep, Duration};

enum TryPollResult<T, F: Future> {
    Ready(T),
    Pending(Pin<Box<F>>),
}

fn try_poll_once<F>(mut fut: Pin<Box<F>>) -> TryPollResult<F::Output, F>
where
    F: Future,
{
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);

    match fut.as_mut().poll(&mut cx) {
        Poll::Ready(value) => TryPollResult::Ready(value),
        Poll::Pending => TryPollResult::Pending(fut),
    }
}

// Non-async function, called from async context.
fn use_or_spawn<F>(future: F)
where
    F: Future<Output = String> + Send + 'static,
{
    match try_poll_once(Box::pin(future)) {
        TryPollResult::Ready(value) => {
            println!("ready immediately: {value}");
        }
        TryPollResult::Pending(fut) => {
            println!("not ready; spawning task to await it...");
            tokio::spawn(async move {
                let value = fut.await;
                println!("completed in spawned task: {value}");
            });
        }
    }
}

#[tokio::main]
async fn main() {
    // Completes on first poll.
    use_or_spawn(async { "instant result".to_string() });

    // Returns Pending on first poll, then completes later.
    use_or_spawn(async {
        sleep(Duration::from_millis(150)).await;
        "delayed result".to_string()
    });

    // Give spawned task time to finish for demo output.
    sleep(Duration::from_millis(300)).await;
}
"
