use std::sync::Arc;
use std::time::Duration;
use tokio::time::sleep;
use tracing::{info, info_span, Instrument, Span};
use tracing_opentelemetry::OpenTelemetrySpanExt;
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

#[derive(Clone)]
struct RequestCtx {
    request_id: u64,
    // Keep a handle to the request/root tracing span.
    request_span: Span,
    // Keep the OTel context so callbacks can re-attach it.
    otel_parent: Context,
}

#[derive(Clone, Default)]
struct ProxyHandler;

#[async_trait]
trait Lifecycle {
    async fn stage_1(&self, ctx: Arc<RequestCtx>);
    async fn stage_2(&self, ctx: Arc<RequestCtx>);
    async fn upstream(&self, ctx: Arc<RequestCtx>);
}

impl ProxyHandler {
    async fn handle_request(&self, request_id: u64) {
        // Root/request span
        let request_span = info_span!("request", request_id);

        request_span.in_scope(|| {
            info!(thread = ?std::thread::current().id(), "request accepted");
        });

        // Capture OTel context from this request span.
        let ctx = Arc::new(RequestCtx {
            request_id,
            otel_parent: request_span.context(),
            request_span: request_span.clone(),
        });

        // Simulate Pingora-style callbacks invoked later / potentially other threads.
        tokio::spawn({
            let this = self.clone();
            let ctx = Arc::clone(&ctx);
            async move { this.stage_1(ctx).await }
        })
        .await
        .unwrap();

        tokio::spawn({
            let this = self.clone();
            let ctx = Arc::clone(&ctx);
            async move { this.stage_2(ctx).await }
        })
        .await
        .unwrap();

        tokio::spawn({
            let this = self.clone();
            let ctx = Arc::clone(&ctx);
            async move { this.upstream(ctx).await }
        })
        .await
        .unwrap();

        request_span.in_scope(|| {
            info!("request complete");
        });
    }

    async fn run_stage(&self, ctx: Arc<RequestCtx>, stage_name: &'static str, delay_ms: u64) {
        // Rehydrate OTel context for code using pure OpenTelemetry API.
        let _otel_guard = ctx.otel_parent.clone().attach();

        // Explicitly set parent so hierarchy is stable regardless scheduler/thread.
        let stage_span = info_span!(
            parent: &ctx.request_span,
            "stage",
            stage = stage_name,
            request_id = ctx.request_id
        );

        async move {
            info!(thread = ?std::thread::current().id(), "callback started");
            sleep(Duration::from_millis(delay_ms)).await;

            // Optional: create a manual OpenTelemetry span to prove context is attached.
            self.manual_otel_child(stage_name);

            info!(thread = ?std::thread::current().id(), "callback finished");
        }
        .instrument(stage_span)
        .await;
    }

    fn manual_otel_child(&self, stage_name: &str) {
        let tracer = global::tracer("manual-otel-api");
        let mut span = tracer.start_with_context(
            format!("{stage_name}_manual_otel_child"),
            &Context::current(),
        );
        span.add_event("manual otel work".to_string(), vec![]);
        span.end();
    }
}

#[async_trait]
impl Lifecycle for ProxyHandler {
    async fn stage_1(&self, ctx: Arc<RequestCtx>) {
        self.run_stage(ctx, "stage_1", 80).await;
    }

    async fn stage_2(&self, ctx: Arc<RequestCtx>) {
        self.run_stage(ctx, "stage_2", 60).await;
    }

    async fn upstream(&self, ctx: Arc<RequestCtx>) {
        self.run_stage(ctx, "upstream", 120).await;
    }
}

fn init_tracing() -> SdkTracerProvider {
