use bytes::Bytes;
use futures_util::TryStreamExt;
use http_body_util::{
    combinators::BoxBody,
    BodyExt,
    Full,
    StreamBody,
};
use hyper::{
    body::{Frame, Incoming},
    server::conn::http1,
    service::service_fn,
    Method, Request, Response, StatusCode,
};
use hyper_util::rt::TokioIo;
use tokio::net::TcpListener;
use tokio_util::io::ReaderStream;

const ROOT: &str = "public";

type ResBody = BoxBody<Bytes, io::Error>;

#[tokio::main]
async fn main() -> io::Result<()> {
    // Create a tiny demo file so `cargo run` works out of the box.
    tokio::fs::create_dir_all(ROOT).await?;
    let index = Path::new(ROOT).join("index.html");
    if tokio::fs::metadata(&index).await.is_err() {
        tokio::fs::write(
            &index,
            "<h1>It works</h1><p>Try placing large files in ./public and downloading them.</p>",
        )
        .await?;
    }

    let addr: SocketAddr = ([127, 0, 0, 1], 3000).into();
    let listener = TcpListener::bind(addr).await?;
    println!("Listening on http://{}", addr);

    loop {
        let (stream, peer) = listener.accept().await?;
        let io = TokioIo::new(stream);

        tokio::spawn(async move {
            let svc = service_fn(handle);
            if let Err(err) = http1::Builder::new().serve_connection(io, svc).await {
                eprintln!("connection error ({}): {}", peer, err);
            }
        });
    }
}

async fn handle(req: Request<Incoming>) -> Result<Response<ResBody>, Infallible> {
    if req.method() != Method::GET && req.method() != Method::HEAD {
        return Ok(text_response(
            StatusCode::METHOD_NOT_ALLOWED,
            "Only GET and HEAD are supported\n",
        ));
    }

    let Some(path) = map_uri_to_path(req.uri().path()) else {
        return Ok(text_response(StatusCode::BAD_REQUEST, "Invalid path\n"));
    };

    match serve_path(&path, req.method() == Method::HEAD).await {
        Ok(resp) => Ok(resp),
        Err(err) if err.kind() == io::ErrorKind::NotFound => {
            Ok(text_response(StatusCode::NOT_FOUND, "Not found\n"))
        }
        Err(err) => {
            eprintln!("I/O error serving {}: {}", path.display(), err);
            Ok(text_response(
                StatusCode::INTERNAL_SERVER_ERROR,
                "Internal server error\n",
            ))
        }
    }
}

fn map_uri_to_path(uri_path: &str) -> Option<std::path::PathBuf> {
    let rel = uri_path.trim_start_matches('/');
    let rel = if rel.is_empty() { "index.html" } else { rel };

    // Very basic traversal protection.
    if rel.contains("..") || rel.contains('\\') {
        return None;
    }

    Some(Path::new(ROOT).join(rel))
}

async fn serve_path(path: &Path, head_only: bool) -> io::Result<Response<ResBody>> {
    let file = tokio::fs::File::open(path).await?;
    let len = file.metadata().await?.len();

    let mut builder = Response::builder().status(StatusCode::OK);
    builder = builder.header(hyper::header::CONTENT_LENGTH, len.to_string());

    if head_only {
        let empty = Full::new(Bytes::new())
            .map_err(|never| match never {})
            .boxed();
        return Ok(builder.body(empty).unwrap());
    }

    // Convert AsyncRead(File) -> Stream<Result<Bytes, io::Error>>
    // Then wrap each chunk into a hyper Frame and turn it into a Body.
    let stream = ReaderStream::new(file).map_ok(Frame::data);
    let body = StreamBody::new(stream).boxed();

    Ok(builder.body(body).unwrap())
}

fn text_response(status: StatusCode, msg: &str) -> Response<ResBody> {
    let body = Full::new(Bytes::from(msg.to_owned()))
        .map_err(|never| match never {})
        .boxed();

    Response::builder()
        .status(status)
        .header(hyper::header::CONTENT_TYPE, "text/plain; charset=utf-8")
        .header(hyper::header::CONTENT_LENGTH, msg.len().to_string())
        .body(body)
        .unwrap()
}
"
}

