/// Build a rotation for a face gizmo that:
/// - uses `normal` as forward (+Z)
/// - keeps in-plane "up" consistent with the cube's current rotation
fn face_aligned_rotation(cube_rotation: Quat, normal: Vec3) -> Quat {
    let n = normal.normalize();

    // Preferred up direction derived from cube orientation.
    // This preserves the face's roll/twist with the cube.
    let mut up = cube_rotation * Vec3::Y;

    // Project up onto the face plane.
    up = (up - n * up.dot(n)).normalize_or_zero();

    // Fallback if face is parallel to preferred up.
    if up.length_squared() < 1e-6 {
        up = (cube_rotation * Vec3::X - n * (cube_rotation * Vec3::X).dot(n)).normalize();
    }

    // Build an orthonormal basis: X, Y, Z(=normal).
    let x = up.cross(n).normalize();
    let y = n.cross(x).normalize();
    Quat::from_mat3(&Mat3::from_cols(x, y, n))
}
