fn yield_signals(msg_tx: mpsc::Sender<Message>, stop_rx: mpsc::Receiver<()>) {
    let mut signals = Signals::new([SIGINT, SIGTERM]).expect("failed to register signals");
    let handle = signals.handle();

    // Wait for stop message and then close the signal iterator.
    let closer = thread::spawn(move || {
        let _ = stop_rx.recv();
        handle.close();
    });

    for sig in signals.forever() {
        if msg_tx.send(Message::Signal(sig)).is_err() {
