use tokio_stream::{Stream, StreamExt};

#[derive(Debug, Clone)]
struct Event(String);

#[derive(Debug)]
struct SharedState {
    tx: Option<Sender<Event>>,
}

type Shared = Arc<Mutex<SharedState>>;

pub fn events_channel() -> (EventSender, EventStreamFactory, EventShutdown) {
    let (tx, _) = channel(20);
    let shared = Arc::new(Mutex::new(SharedState { tx: Some(tx) }));

    (
        EventSender {
            shared: shared.clone(),
        },
        EventStreamFactory {
            shared: shared.clone(),
        },
        EventShutdown { shared },
    )
