#[derive(Debug, Clone)]
pub struct EventSender {
    shared: Shared,
}

impl EventSender {
    pub fn send(&self, event: Event) -> Result<usize, SendError<Event>> {
        let guard = self.shared.lock().expect("mutex poisoned");
        match guard.tx.as_ref() {
            Some(tx) => tx.send(event),
            None => Err(SendError(event)),
        }
    }
}

#[derive(Clone)]
pub struct EventStreamFactory {
    shared: Shared,
}

impl EventStreamFactory {
    pub fn all_events(
        &self,
    ) -> Pin<Box<dyn Stream<Item = Result<Event, BroadcastStreamRecvError>> + Send>> {
        let maybe_tx = self.shared.lock().expect("mutex poisoned").tx.clone();

        match maybe_tx {
            Some(tx) => Box::pin(BroadcastStream::new(tx.subscribe())),
            None => Box::pin(tokio_stream::empty::<Result<Event, BroadcastStreamRecvError>>()),
        }
    }
}

#[derive(Clone)]
pub struct EventShutdown {
    shared: Shared,
}

impl EventShutdown {
    pub fn shutdown(&self) {
        let mut guard = self.shared.lock().expect("mutex poisoned");
        // Dropping the single stored Sender closes the broadcast channel globally.
        guard.tx = None;
    }
}

#[tokio::main]
async fn main() {
    let (sender, factory, shutdown) = events_channel();

    // Producer task (holds a clone of EventSender, but not a direct Sender clone).
    let producer = {
        let sender = sender.clone();
        tokio::spawn(async move {
            let mut i = 0u64;
            loop {
                i += 1;
                let event = Event(format!("event-{i}"));
                match sender.send(event) {
                    Ok(subscribers) => {
                        println!("sent event-{i} to {subscribers} subscriber(s)");
                    }
                    Err(_) => {
                        println!("producer: channel is shut down; exiting");
