                let name = String::from_utf8(name_bytes).map_err(|e| {
                    std::io::Error::new(std::io::ErrorKind::InvalidData, format!("utf8 error: {e}"))
                })?;

                let mut off_bytes = [0u8; 8];
                reader.read_exact(&mut off_bytes).await?;
                let offset = u64::from_le_bytes(off_bytes);

                let mut len_bytes = [0u8; 8];
                reader.read_exact(&mut len_bytes).await?;
                let len = u64::from_le_bytes(len_bytes);

                entries.insert(name, EntryInfo { offset, len });
            }

            Ok(PackIndex { entries })
        })
    }

    fn extensions(&self) -> &[&str] {
        &["pack"]
    }
}

#[derive(Resource, Clone)]
