        .add_systems(Startup, create_demo_pack)
        .add_systems(Startup, begin_load.after(create_demo_pack))
        .add_systems(Update, drive_demo)
        .run();
}

fn create_demo_pack(root: Res<AssetsRoot>) {
    create_dir_all(&root.0).expect("create assets dir");
    let pack_path = root.0.join("demo.pack");

    let entries: Vec<(String, Vec<u8>)> = (0..3200)
        .map(|i| {
            let name = format!("tex_{i:04}");
            let payload = format!("payload for {name}\n").into_bytes();
            (name, payload)
        })
        .collect();

    let index_size: usize = entries
        .iter()
        .map(|(name, _)| 2 + name.len() + 8 + 8)
        .sum();
    let header_size = 4 + 4 + index_size;

    let mut cursor = header_size as u64;
    let mut metas: Vec<(u64, u64)> = Vec::with_capacity(entries.len());
    for (_, data) in &entries {
        metas.push((cursor, data.len() as u64));
        cursor += data.len() as u64;
    }

    let file = File::create(&pack_path).expect("create pack file");
    let mut writer = BufWriter::new(file);

    writer.write_all(b"LPK1").unwrap();
    writer
        .write_all(&(entries.len() as u32).to_le_bytes())
        .unwrap();

    for ((name, _), (offset, len)) in entries.iter().zip(metas.iter()) {
        writer
            .write_all(&(name.len() as u16).to_le_bytes())
            .unwrap();
        writer.write_all(name.as_bytes()).unwrap();
        writer.write_all(&offset.to_le_bytes()).unwrap();
        writer.write_all(&len.to_le_bytes()).unwrap();
    }

    for (_, data) in &entries {
        writer.write_all(data).unwrap();
    }

    writer.flush().unwrap();
    println!("Wrote demo pack: {}", pack_path.display());
}

fn begin_load(asset_server: Res<AssetServer>, mut commands: Commands) {
    let pack_rel_path = "demo.pack".to_string();
    let handle: Handle<PackIndex> = asset_server.load(pack_rel_path.clone());

    commands.insert_resource(DemoState {
        pack_handle: handle,
        pack_rel_path,
        requested: false,
        printed: false,
        loaded: vec![],
    });
}

fn drive_demo(
    root: Res<AssetsRoot>,
    mut state: ResMut<DemoState>,
    indices: Res<Assets<PackIndex>>,
    mut texts: ResMut<Assets<PackedText>>,
) {
    let Some(index) = indices.get(&state.pack_handle) else {
        return;
    };

    if !state.requested {
        println!("Pack index loaded. Total entries: {}", index.entries.len());

        let wanted = ["tex_0000", "tex_1599", "tex_3199"];
        for name in wanted {
            if let Some(info) = index.entries.get(name) {
                match load_entry_lazy(&root.0, &state.pack_rel_path, info) {
                    Ok(asset) => {
                        let handle = texts.add(asset);
                        state.loaded.push((name.to_string(), handle));
                    }
                    Err(e) => {
                        eprintln!("Failed to load {name}: {e}");
                    }
                }
            }
        }

        state.requested = true;
    }

    if state.requested && !state.printed {
        for (name, handle) in &state.loaded {
            if let Some(txt) = texts.get(handle) {
                print!("{name} => {}", txt.value);
            }
        }
        state.printed = true;

        println!("\nDone. This demonstrates lazy per-entry reads from one pack file.");
        std::process::exit(0);
    }
}

fn load_entry_lazy(root: &Path, pack_rel_path: &str, entry: &EntryInfo) -> std::io::Result<PackedText> {
    let pack_path = root.join(pack_rel_path);
    let mut file = File::open(pack_path)?;
    file.seek(SeekFrom::Start(entry.offset))?;

    let mut bytes = vec![0u8; entry.len as usize];
    file.read_exact(&mut bytes)?;

    let value = String::from_utf8(bytes)
        .map_err(|e| std::io::Error::new(std::io::ErrorKind::InvalidData, e.to_string()))?;

    Ok(PackedText { value })
}
"
}

