  "main.rs": "use anyhow::{Context, Result};
use cms::{content_info::ContentInfo, signed_data::SignedData};
use der::{Decode, Encode};
use std::{env, fs};

fn main() -> Result<()> {
    let path = env::args().nth(1).unwrap_or_else(|| "ci.der".to_string());
    let raw = fs::read(&path).with_context(|| format!("failed to read input file: {path}"))?;

    // Accept either raw DER or base64-encoded data for convenience.
    let body = if looks_like_base64(&raw) {
        let s = String::from_utf8_lossy(&raw);
        base64::engine::general_purpose::STANDARD
            .decode(s.trim().as_bytes())
            .context("input looked like base64 but decode failed")?
    } else {
        raw
    };

    let ci = ContentInfo::from_der(&body).context("failed to decode ContentInfo")?;
    println!("ContentInfo decoded");
    println!("contentType OID: {}", ci.content_type);

    // First try the straightforward way.
    let sd = match ci.content.decode_as::<SignedData>() {
        Ok(sd) => {
            println!("SignedData decoded via ci.content.decode_as::<SignedData>()");
            sd
        }
        Err(e1) => {
            eprintln!("decode_as failed: {e1}");
            eprintln!("Trying fallback: decode SignedData from Any.value() bytes...");

            // Fallback that often helps when the Any wrapper/content encoding is odd.
            match SignedData::from_der(ci.content.value()) {
                Ok(sd) => {
                    println!("SignedData decoded via SignedData::from_der(ci.content.value())");
                    sd
                }
                Err(e2) => {
                    eprintln!("second attempt failed: {e2}");
                    eprintln!("Trying final fallback: decode SignedData from re-encoded Any DER...");

                    let reencoded_any = ci.content.to_der().context("failed to DER-encode ci.content")?;
                    SignedData::from_der(&reencoded_any).context(
                        "all SignedData decode attempts failed (likely non-DER/legacy PKCS#7 encoding detail)",
                    )?
                }
            }
        }
    };

    println!("\nDecoded SignedData:\n{sd:#?}");
    Ok(())
}

fn looks_like_base64(bytes: &[u8]) -> bool {
    if bytes.is_empty() {
        return false;
    }
    // Heuristic: mostly printable ASCII and no obvious DER SEQUENCE prefix (0x30 ...)
    let printable = bytes
        .iter()
        .filter(|b| matches!(b, b'\r' | b'\n' | b'\t' | b' ' | b'+' | b'/' | b'=' | b'A'..=b'Z' | b'a'..=b'z' | b'0'..=b'9'))
        .count();
    let ratio = printable as f32 / bytes.len() as f32;
    ratio > 0.95 && bytes.first().copied() != Some(0x30)
}
